import{H as o,g as l}from"./hints-BATT2iql.js";const e=[{id:"p1",firstName:"Jeremiah",lastName:"Goodwill",strangername:"un inconnu",photo:"portraits/portrait_jeremiah_goodwill.png",unlockedByDefault:!0,map:["resort"]},{id:"p2",firstName:"Lune",lastName:"Goodwill",strangername:"une inconnue",photo:"portraits/portrait_lune_goodwill.png",unlockedByDefault:!0,map:["resort","journey"]},{id:"p3",firstName:"Lucas",lastName:"Sterling",strangername:"un inconnu",photo:"portraits/portrait_lucas_sterling.png",unlockedByDefault:!1,map:["resort","journey"]},{id:"p4",firstName:"Theresa",lastName:"McIntyre",strangername:"une femme plus âgée",photo:"portraits/portrait_theresa_mintyre.png",unlockedByDefault:!1,map:["resort"]},{id:"p5",firstName:"Dieter",lastName:"von Guntram",strangername:"un inconnu bien habillé",photo:"portraits/portrait_dieter_von_guntram.png",unlockedByDefault:!1,map:["resort"]},{id:"p6",firstName:"Edward",lastName:"Bonfire",strangername:"un homme débraillé",photo:"portraits/portrait_edward_bonfire.png",unlockedByDefault:!1,map:["resort"]},{id:"p7",firstName:"Vitalina",lastName:"Petrosky",strangername:"une belle femme",photo:"portraits/portrait_vitalina_petrosky.png",unlockedByDefault:!1,map:["resort"]},{id:"p8",firstName:"Cynthia",lastName:"Seville",strangername:"une avocate",photo:"portraits/portrait_cynthia_seville.png",unlockedByDefault:!1,map:["resort","journey","cynthia_journey"]},{id:"p9",firstName:"Kanan",lastName:null,strangername:"un grand homme",photo:"portraits/portrait_kanan.png",unlockedByDefault:!1,map:["resort"]},{id:"p10",firstName:"Jiro",lastName:"Tanaka",strangername:"un travailleur japonais",photo:"portraits/portrait_tanaka_jiro.png",unlockedByDefault:!1,map:["resort"]},{id:"p11",firstName:"Aisyah",lastName:null,strangername:"une servante locale",photo:"portraits/portrait_aisyah.png",unlockedByDefault:!1,map:["resort"]},{id:"p12",firstName:"Rose",lastName:"Goodwill",strangername:"une jeune femme",photo:"portraits/portrait_rose_goodwill.png",unlockedByDefault:!1,hidden:!0,map:["resort","journey"]},{id:"p13",firstName:"Ludwig",lastName:"Harrow",strangername:"le mystérieux inconnu",photo:"portraits/portrait_ludwig_harrow.png",unlockedByDefault:!1,hidden:!0,map:["resort","cynthia_journey"]},{id:"p14",firstName:"Babalian",lastName:"Antau",strangername:"le chamane",photo:"portraits/portrait_babalian_antau.png",unlockedByDefault:!1,hidden:!0,ignoreInMindsEye:!0,map:["resort"]},{id:"p15",firstName:"Delphine",lastName:null,strangername:"l'enquêtrice",photo:"portraits/investigator.png",unlockedByDefault:!1,hidden:!0,ignoreInMindsEye:!0,map:["journey"]},{id:"p16",firstName:"Reginald",lastName:"Fairfax",title:"Commandant",strangername:"un officier supérieur",photo:"portraits/portrait_reginald_fairfax.png",unlockedByDefault:!1,hidden:!0,ignoreInMindsEye:!0,map:["resort","cynthia_journey"]},{id:"p17",firstName:"Thomas",lastName:"Miller",title:"Sergent",strangername:"un grand officier",photo:"portraits/portrait_thomas_miller.png",unlockedByDefault:!1,hidden:!0,ignoreInMindsEye:!0,map:["resort","cynthia_journey"]},{id:"p18",firstName:"Stanley",lastName:"Hudson",title:"Caporal",strangername:"un officier plus âgé",photo:"portraits/portrait_stanley_hudson.png",unlockedByDefault:!1,hidden:!0,ignoreInMindsEye:!0,map:["resort","cynthia_journey"]},{id:"p19",firstName:"Arthur",lastName:"Birdwhistle",title:"Soldat",strangername:"un jeune soldat",photo:"portraits/portrait_arthur_birdwhistle.png",unlockedByDefault:!1,hidden:!0,ignoreInMindsEye:!0,map:["resort","cynthia_journey"]},{id:"p20",firstName:"John",lastName:"Fairfax",strangername:"un homme",photo:"portraits/portrait_john_fairfax.png",unlockedByDefault:!1,hidden:!0,ignoreInMindsEye:!0,map:["cynthia_journey"]},{id:"p21",firstName:"Charles",lastName:"Brooke",strangername:"un homme",photo:"portraits/portrait_charles_brooke.png",unlockedByDefault:!1,hidden:!0,ignoreInMindsEye:!0,map:["resort"]}],s=[{id:"study",name:"Bureau",x:44,y:56.5,map:"resort",unlockedByDefault:!0,description:"Lourds meubles en teck et odeur de fumée stagnante."},{id:"kitchen",name:"Cuisine",x:32,y:58,map:"resort",unlockedByDefault:!1,description:"Située à l'arrière du bâtiment pour éloigner la chaleur du fourneau des pièces principales."},{id:"dining",name:"Salle à Manger",x:37,y:63,map:"resort",unlockedByDefault:!1,description:"Une grande salle à manger avec une table et des chaises anciennes."},{id:"clubhouse",name:"Club House",x:50.5,y:44,map:"resort",unlockedByDefault:!1,description:"Une version rustique d'un club de gentlemen londonien."},{id:"workerquarters",name:"Quartiers des Travailleurs",x:70,y:8,map:"resort",unlockedByDefault:!1,description:"Où dorment les travailleurs et les serviteurs."},{id:"balcony",name:"Plateforme d'Observation",x:28,y:80,map:"resort",unlockedByDefault:!1,description:"Un point de vue en hauteur pour observer la tempête qui approche."},{id:"beach",name:"Plage Isolée",x:88,y:19,map:"resort",unlockedByDefault:!1,description:"Une crique cachée, loin des regards indiscrets."},{id:"boathouse",name:"Hangar à Bateaux",x:77,y:84,map:"resort",unlockedByDefault:!1,description:"Bois pourri et filets de pêche. Le domaine de Bone."},{id:"garden",name:"Terrain de Croquet",x:30.5,y:35,map:"resort",unlockedByDefault:!1,description:"Une pelouse impeccablement entretenue avec un jeu de croquet."},{id:"library",name:"Bibliothèque",x:34.5,y:49.5,map:"resort",unlockedByDefault:!1,description:"Un fauteuil confortable entouré de livres et de vieux magazines."},{id:"veranda",name:"Véranda",x:48,y:63.2,map:"resort",unlockedByDefault:!1,description:"L'endroit où la famille se rassemble pour boire son verre du soir et regarder le coucher du soleil."},{id:"masterbedroom",name:"Chambre Principale",x:64,y:55,map:"resort",unlockedByDefault:!1,description:"La chambre du maître et de sa femme."},{id:"luneroom",name:"Chambre de Lune",x:45,y:20,map:"resort",unlockedByDefault:!1,description:"La chambre de la jeune maîtresse."},{id:"guesthouse",name:"Maison d'amis",x:54.3,y:28.4,map:"resort",unlockedByDefault:!1,description:"Fonctionnelle avec de nombreux lits pour accueillir des invités inattendus."},{id:"jungle",name:"Entrée de la Jungle",x:20,y:19,map:"resort",unlockedByDefault:!1,description:"L'entrée de la jungle. Le chemin est envahi par la végétation."},{id:"chapel",name:"Chapelle",x:67,y:40,map:"resort",unlockedByDefault:!1,description:"Une petite chapelle avec une croix sur le mur."},{id:"railway",name:"Chemin de Fer",x:45,y:7,map:"resort",unlockedByDefault:!1,description:"Là où passe la locomotive à vapeur britannique de Bornéo."},{id:"theresaroom",name:"Chambre de Theresa",x:39.5,y:23,map:"resort",unlockedByDefault:!1,description:"La chambre de la mère de Lune."},{id:"bonfireroom",name:"Chambre de Bone",x:50,y:22,map:"resort",unlockedByDefault:!1,description:"La chambre où dorment Bone et Vita."},{id:"boat",name:"Bateau de Lucas",x:56,y:97,map:"resort",unlockedByDefault:!1,description:"Le navire de fuite de Lucas."},{id:"companionway",name:"Passage Secret",x:59,y:43,map:"resort",unlockedByDefault:!1,description:"Un passage secret allant du clubhouse à un bunker sous la chapelle. Une clé est nécessaire pour déverrouiller la grille métallique."},{id:"roof",name:"Toit",x:41,y:49.5,map:"resort",unlockedByDefault:!1,description:"Le toit de la maison principale. Vous pouvez voir tout le domaine depuis ici."},{id:"commandpost",name:"Poste de Commandement",x:53,y:60.7,map:"resort",unlockedByDefault:!1,description:"Le poste de commandement a été installé à la hâte dans ce qu'il reste de la véranda."},{id:"cemetery",name:"Cimetière",x:75,y:40,map:"resort",unlockedByDefault:!1,description:"Le cimetière est envahi par la végétation et abrite les tombes des membres de la famille Goodwill, dont beaucoup de jeunes hommes."},{id:"messhall",name:"Réfectoire",x:48,y:80,map:"resort",unlockedByDefault:!1,description:"La nourriture sent étonnamment bon compte tenu des circonstances."},{id:"shore",name:"Rivage",x:57,y:81,map:"resort",unlockedByDefault:!1,description:"Le bruit apaisant des vagues dissimule de façon trompeuse le carnage qui règne autour du domaine."},{id:"sule",name:"Mer de Sulu",x:79,y:77,map:"journey",unlockedByDefault:!0,description:"L'étendue d'eau libre entre Bornéo et le continent."},{id:"singapore",name:"Singapour",x:75,y:82,map:"journey",unlockedByDefault:!1,description:"Le Gibraltar de l'Orient est maintenant dans le chaos."},{id:"colombo",name:"Colombo",x:61,y:75,map:"journey",unlockedByDefault:!1,description:"Chaleur, poussière de charbon et une semaine de retards."},{id:"aden",name:"Aden",x:37,y:62,map:"journey",unlockedByDefault:!1,description:"Roches brûlées et chaleur oppressante."},{id:"suez",name:"Canal de Suez",x:31,y:44,map:"journey",unlockedByDefault:!1,description:"Traversée du désert."},{id:"mediterranean",name:"Mer Méditerranée",x:24,y:38,map:"journey",unlockedByDefault:!1,description:"Le choc glacial de l'Europe."},{id:"gibraltar",name:"Gibraltar",x:10,y:41,map:"journey",unlockedByDefault:!1,description:"Le rocher. Le premier sanctuaire en Europe."},{id:"arrival",name:"Docks de Tilbury",x:13,y:19,map:"journey",unlockedByDefault:!1,description:"La maison. Mais tout a changé."},{id:"london",name:"Londres",x:10.5,y:17,map:"journey",unlockedByDefault:!1,description:"La maison familiale des Sterling."},{id:"arabiansea",name:"Mer d'Arabie",x:49,y:71,map:"journey",unlockedByDefault:!1,description:"Le Grand Vide Bleu."},{id:"malacca",name:"Détroit de Malacca",x:71,y:76,map:"journey",unlockedByDefault:!1,description:"L'eau est peu profonde et encombrée des épaves de navires qui n'ont pas réussi à passer."},{id:"bengal",name:"Golfe du Bengale",x:66,y:75,map:"journey",unlockedByDefault:!1,description:"Une zone de guerre disputée, dangereuse et isolée."},{id:"plantation",name:"Plantation Goodwill",x:70,y:48,map:"cynthia_journey",unlockedByDefault:!0,description:"Tomber de Charybde en Scylla."},{id:"ulu",name:"Jungle d'Ulu",x:65,y:57,map:"cynthia_journey",unlockedByDefault:!1,description:"Un chemin étroit dissimulé par un feuillage dense."},{id:"nipa",name:"Marais de Nipa",x:53,y:58,map:"cynthia_journey",unlockedByDefault:!1,description:"Un labyrinthe de palmiers Nipa et de racines de mangroves enchevêtrées qui ressemblent à des araignées géantes."},{id:"gomantong",name:"Périphérie de Gomantong",x:35,y:53,map:"cynthia_journey",unlockedByDefault:!1,description:"De massives falaises de calcaire jaillissant de la canopée verte."},{id:"sepilok",name:"Traversée de Sepilok",x:23,y:38,map:"cynthia_journey",unlockedByDefault:!1,description:"Des arbres diptérocarpacées géants masquent le soleil, faisant du sol de la forêt un crépuscule permanent."},{id:"batusapi",name:"Batu Sapi",x:25,y:20,map:"cynthia_journey",unlockedByDefault:!1,description:"Formation rocheuse de grès à trois pattes qui ressemble à une vache debout dans la mer."},{id:"sandakan",name:"Sandakan",x:34,y:22,map:"cynthia_journey",unlockedByDefault:!1,description:"Dans le feu de l'action."}],a=[{id:"doc_intro",title:"Dossier de l'Enquêteur",preview:'"12 avril 1948, Chère Mademoiselle Delphine..."',type:"rich",fullText:`12 avril 1948<br>Londres<br><br>Chère Mademoiselle Delphine,<br><br>J'espère que cette correspondance vous trouvera en bonne santé et que l'air printanier vous apportera un soulagement bienvenu après le froid de l'hiver. Je dois m'excuser pour la nature soudaine de cette lettre, car nous n'avons jamais été officiellement présentés ; cependant, votre nom m'a été donné par une connaissance commune d'Oxford qui m'a parlé avec une grande conviction de vos dons uniques. Il m'a assuré que là où les autorités conventionnelles atteignent leurs limites, votre enquête commence. C'est cet espoir, peut-être désespéré, qui me pousse à vous écrire aujourd'hui.<br><br>Ils m'ont dit que c'était la guerre. Que mon père, ma sœur Lune... qu'ils n'étaient que des victimes de l'occupation. Mais je sais aujourd'hui qu'il n'en est rien. Ils avaient disparu bien avant le débarquement des Japonais.<br><br>Je suis resté coincé ici à Londres pendant le blitz, incapable de les rejoindre. Mon père, Jeremiah, dirigeait la <strong>Plantation de Tabac Goodwill</strong> au nord de Bornéo depuis des années. C'était notre paradis. Maintenant, on me dit que c'est un cimetière.<br><br>J'ai dépensé tout mon héritage à chasser des fantômes. Des lettres au bureau des colonies, des pots-de-vin à des marins... et c'est tout ce que j'ai. Une boîte de restes. Une carte. Quelques photos.<br><br>Vous êtes une Sensitive, m'a-t-on dit. C'est comme ça qu'on vous appelle ? S'il vous plaît. J'ai besoin de savoir ce qui leur est arrivé. Accédez aux souvenirs attachés à ces objets. Decouvrez la vérité.<br><br>Ci-jointes les rares photos que j'ai réussi à récupérer.<br><div class="intro-mugshots"><img src="portraits/portrait_jeremiah_goodwill.png" alt="Jeremiah"><img src="portraits/portrait_lucas_sterling.png" alt="Lucas"><img src="portraits/portrait_lune_goodwill.png" alt="Lune"><div class="more-files">+7 Autres</div></div><br>La seule chose dont je sois sûr est ce que le bureau des colonies m'a dit :<br><span class="clue-highlight">"Jeremiah Goodwill était seul dans le bureau à 16h00 le mardi 16 décembre 1941, lorsqu'il a passé un appel téléphonique aux autorités locales concernant l'arrivée d'un invité non annoncé et inattendu."</span><br><br>S'il vous plaît, aidez-moi à les reposer en paix.<br><br>- J. Goodwill Jr.`,discovered:!0},{id:"doc_mist",title:"Mist Project Report",preview:'"Top Secret. Marine Impériale Japonaise..."',fullText:`RAPPORT TOP SECRET
SUJET : 'La Brume verte'
ORIGINE : Non confirmée (On soupçonne un essai chimique par une unité de la MIJ au large de la côte).
EFFETS : nécrose rapide de la vie marine, hallucinations chez les humains à faible dose et deces en cas d'exposition prolongée.
CONCLUSION : La brume est un essai d'armement. Un échantillon a été acquis.`,discovered:!1},{id:"doc_ledgers",title:"Dépenses de la Plantation 1941",preview:'"Registre de Décembre..."',fullText:`<h3>Dépenses de la Plantation Goodwill - Décembre 1941</h3><p><b>Opérations Tabac</b></p><ul><li>Salaires des Coolies (150 têtes): £450.00</li><li>Réparations du Hangar de Fermentation: £35.00</li><li>Séchoirs: £12.00</li><li>Engrais: £40.00</li><li>Toile de Jute & Ficelle: £8.50</li></ul><p><b>Ferme Ostréicole</b></p><ul><li>Entretien du Matériel de Plongée: £25.00</li><li>Acide de Nettoyage des Coquilles: £15.00</li><li>Carburant pour Bateau: £45.00</li><li>Réparations des Filets: £6.00</li></ul><p><b>Complexe & Écuries</b></p><ul><li>Carburant pour Générateur: £30.00</li><li>Nourriture pour Chevaux: £18.00</li><li>Fournitures Vétérinaires: £7.50</li><li>Entretien du <span class='discover-link' onclick="window.discoverItem('room', 'garden');">Terrain de Croquet</span> & Pesticides: £5.00</li></ul><p><b>Provisions</b></p><ul><li>Riz & Denrées de Base: £85.00</li><li>Viandes en Conserve & Produits de Luxe: £60.00</li><li>Livraison de Blocs de Glace: £10.00</li><li>Divertissements (Gin/Whisky/Xérès): £150.00</li><li>Achat d'Opium: £120.00</li></ul><p><b>Taxes & Prélèvements</b></p><ul><li>Taxe Foncière de la BNB Chartered Co.: £200.00</li><li>Prélèvement de Protection du Rajah: £100.00</li><li>Droits de Port: £25.00</li></ul><hr><p><b>Dépenses Totales: £1,447.00</b></p><p><b>Revenus Totaux (est): £320.00</b></p><p><i>Note : Insolvabilité imminente. Liquidation des actifs recommandée immédiatement.</i></p>`,discovered:!1},{id:"doc_suicidenote",title:"Note Manuscrite",preview:'"À mon mari..."',type:"rich",fullText:"<i>Jeremiah,<br><br>Je trouve que je ne peux plus supporter cette misérable existence. L'isolement étouffant, le silence pesant de la jungle, et cette terreur constante et rongeante sont devenus tout à fait insupportables. Il m'est clair maintenant que tu es marié à ce domaine et à ses ressources, tandis que je suis devenue un peu plus qu'un fantôme dans ta maison. Je tiens à toi ; en effet, j'ai tenu à toi de tout ce qu'il reste de mon cœur mais je crains de n'être plus qu'une étrangère pour toi.<br><br>Je ne désire plus qu'une chose, que cette douleur dans ma poitrine cesse. Je t'en supplie, ne pars pas à ma recherche ; au moment où tu liras ceci, j'aurai été doucement réclamée par la mer. Je vais à la crique sur notre &beach, je l'ai toujours aimée, car elle renferme les fantômes des jours où tu me regardais encore avec gentillesse. Je me remémorerai ces heures perdues tout en laissant la marée m'emporter.<br><br>- Rose</i>",discovered:!1},{id:"doc_investigation",title:"Rapport Final",preview:'"À M. Goodwill Jr..."',type:"rich",fullText:"15 avril 1948<br>Londres<br><br>M. Goodwill,<br><br>Je n'ai pas encore terminé mon enquête, il reste encore trop de points à éclaircir. Je vais devoir poursuivre mon travail.<br><br>Bien que j'aie découvert des fragments du passé, l'image globale reste obscure. Cependant, j'ai des nouvelles qui vont changer votre vie. Votre sœur, Lune, n'a pas péri dans les incendies comme l'indiquent les archives coloniales. Mes visions la montrent s'échappant de l'île avec un certain Lucas Sterling et la seconde femme de votre père, Rose.<br><br>Je ne sais pas encore ce qui leur est arrivé et s'ils ont jamais réussi à quitter la zone de guerre. Je vais poursuivre mon enquête et vous tenir informé.<br><br>- Delphine<br><br><br><div style='text-align:center;'></div>",conditionalContent:{condition:{type:"unlocks",ids:["p6","p7","p8","p10","p12","p13"]},fullText:`15 avril 1948<br>Londres<br><br>M. Goodwill,<br><br>J'ai conclu mon enquête sur les événements de la Plantation Goodwill. La vérité est plus étrange que ne le laissaient entendre les rapports officiels.<br><br>Votre père, Jeremiah, est bien décédé cette nuit-là. Ce ne sont pas les Japonais qui l'ont tué, ni la malédiction des perles ou la brume verte. C'est une tragédie née du désespoir et de croyances occultes malavisées.<br><br>Cependant, j'ai des nouvelles qui vont changer votre vie. Votre sœur, Lune, n'a pas péri dans les incendies comme l'indiquent les archives coloniales. Mes visions la montrent s'échappant de l'île sur une chaloupe privée avec la seconde femme de votre père, Rose, et un homme nommé Lucas Sterling.<br><br>Ils ont réussi à se mettre en sécurité. Elle pourrait être en vie, M. Goodwill. Ils tentaient de fuir pour retourner en Angleterre sous une nouvelle identité. Elle a choisi de laisser cette vie derrière elle, mais je veux croire qu'elle a survécu.<br><br>J'espère que vous la retrouverez.<br><br>- Delphine<br><br><br><div style='text-align:center;'><button onclick='window.triggerDialogue("EPILOGUE"); window.closeDocument();' style='padding: 10px 20px; font-family: "Playfair Display"; background: #3c2f2f; color: #d4c5a9; border: 1px solid #d4c5a9; cursor: pointer; font-size: 1.1rem;'>TERMINER L'ENQUÊTE</button></div>`},discovered:!1},{id:"doc_journey_log",title:"Carte du Retour",preview:'"Itinéraire du SS..."',type:"rich",fullText:" oups. rien ici.",discovered:!1},{id:"doc_cynthia_ending",title:"Rapport sur le sort de Cynthia",preview:'"À M. Goodwill Jr..."',type:"rich",fullText:`15 avril 1948<br>Londres<br><br>M. Goodwill,<br><br>Je sais maintenant ce qui est arrivé à Cynthia. Elle s'est échappée de Sandakan avec le Rapport Brume et a atteint Ceylan. Je devrais essayer de la contacter pour obtenir sa version des faits un de ces jours, mais ce n'est pas pour aujourd'hui.<br><br>Pour l'instant, je peux clore ce chapitre.<br><br>- Delphine<br><br><br><div style='text-align:center;'><button onclick='window.triggerDialogue("CYNTHIA_ENDING"); window.closeDocument();' style='padding: 10px 20px; font-family: "Playfair Display"; background: #3c2f2f; color: #d4c5a9; border: 1px solid #d4c5a9; cursor: pointer; font-size: 1.1rem;'>TERMINER L'ENQUÊTE</button></div>`,discovered:!1}],n=[{id:"opium",name:"Pipe à Opium",ownerId:"p10",image:"items/pipe.png",description:"Ornée et sentant la fumée douce. Trouvée près du corps."},{id:"vial",name:"Fiole Bleue Vide",ownerId:"p7",image:"items/vial.png",description:"Sent légèrement le poisson."},{id:"pearl",name:"Perles",ownerId:"p6",image:"items/pearls.png",description:"Le rouge ressemble à du sang tourbillonnant à l'intérieur."},{id:"pouch",name:"Poche",ownerId:"p3",image:"items/pouch.png",description:"Une petite poche. Elle est plus lourde qu'elle n'en a l'air."},{id:"photo",name:"Vieille Photo",ownerId:"p1",unlocks:"p12",image:"items/faded_photo.png",description:"Au dos, il est écrit 'Ma chère femme et son tempérament adorable'"},{id:"photo2",name:"Petite Photo",ownerId:"p8",unlocks:"p20",image:"items/photo2.png",description:"une photo du futur mari de Cynthia."},{id:"radio",name:"Récepteur Radio",ownerId:"p2",image:"items/radio.png",dialogue_trigger:"RADIO_0",description:"Une radio lourde et portable. Elle est actuellement réglée sur une fréquence d'urgence."},{id:"telephone",name:"Téléphone à Cadran",ownerId:"p1",image:"items/telephone.png",dialogue_trigger:"TELEPHONE_0",description:"relié par un seul fil de cuivre physique à travers la jungle"},{id:"lighter",name:"Briquet",ownerId:"p1",image:"items/lighter.png",description:"Un briquet Unique en laiton plaqué or de chez Dunhill.",dialogue_trigger:"LIGHTER_0"},{id:"letter",name:"Lettre Manuscrite",image:"items/letter.png",ownerId:"p12",description:"Une lettre écrite à la hâte.",triggers:"doc_suicidenote"},{id:"sample",name:"Échantillon Biologique",ownerId:"p3",image:"items/sample.png",description:"Une bouteille en verre avec une étiquette d'avertissement. Elle contient un liquide visqueux et foncé."},{id:"key",name:"Clé du passage",ownerId:"p1",image:"items/key.png",description:"Une clé pour déverrouiller un passage secret."},{id:"binoculars",name:"Jumelles",ownerId:"p10",image:"items/binoculars.png",description:"Une paire de jumelles."},{id:"croquetbat",name:"Maillet de Croquet",ownerId:"p6",image:"items/croquetbat.png",description:"Un solide maillet de croquet."},{id:"pearl2",name:"Perle",ownerId:"p8",image:"items/pearl.png",description:"Une seule perle rouge.",map:"cynthia_journey",dialogue_trigger:"PEARL_2"},{id:"report",name:"Rapport sur la Brume",ownerId:"p3",image:"items/report.png",description:"Détails du programme sur la brume.",map:"cynthia_journey"},{id:"knife",name:"Couteau",ownerId:"p18",image:"items/knife.png",description:"Couteau réglementaire.",map:"cynthia_journey"}],t={beach_1:{personIds:["p5","p11"],links:["garden_2"],clue:`@note: La plage isolée est vide, à l'exception de &p5 et &p11 se tenant dans l'ombre des grandes falaises.
@p5: Tout est prêt, &p11_firstname?
@p11: Le sentier de la jungle jusqu'au bungalow n'est pas gardé, Tuan.
@p5: Excellent. Et notre... invité ?
@p11: Le capitaine &p13_lastname fera un signal au coucher du soleil. J'ai préparé la lampe et l'ai placée sur la crête comme balise.
@p5: Je serai content quand tout cela sera terminé. Cette attente me tue.
@p11: Vous avez intérêt d'avoir raison, M. &p5_lastname. Si cette entreprise échoue, ce n'est pas seulement ma position qui est en jeu. C'est nos cous.
@p5: Ayez foi, ma chère. Le chaos sera notre couverture. Personne ne nous soupçonnera.
@p11: Je veillerai à ce que &p9 soit occupé. Vous devez vous assurer que la compagnie reste à table dans la &dining.
@note: &p11 retourne vers la plantation. &p5 reste un instant, observant la marée ; lorsqu'il est certain de ne pas être observé, il retourne vers le &garden.`},veranda_0:{personIds:["p1","p2","p4"],objects:[{id:"lighter",heldBy:"p1"}],links:["veranda_1","balcony_0","balcony_1"],clue:`@note: &p1 entre dans la &veranda. &p2 et &p4 s'y trouvent déjà, assises face à la mer.
@p4: Il était temps que tu arrives. Je meurs de soif.
@p1: Ma chère, qu'as-tu fait pendant mon absence ? Je ne suis de retour que depuis quelques heures. As-tu manqué de quoi boire ces derniers jours ?
@p4: Contente-toi de verser.
@note: &p1 va au bar et commence à préparer des [Sundowners](SUNDOWNER).
@note: &p4 prend une pilule dans son sac à main et l'avale. Ce doit être sa [Tuan's dose](TUAN_DOSE) du jour.
@p1: As-tu déjà vu Bone ? Je dois lui parler. L'orient nous échappe.
@p4: De quoi tu parles ?
@p1: C'est pas vrai &p4_firstname, tu n'écoutes jamais. Il n'y a pas d'orient. Elles n'ont pas d'éclat. C'est cette foutue spirale rouge à l’intérieur qui ressemble à du sang, je te le dis. Je ne comprends tout simplement pas.
@p4: Qui dit ça ?
@p1: Tous ! Les [Towkays](TOWKAY), les [Bajaus](BAJAU), les <c>Japs</c>. Tous le disent. Sans orient, elles ne valent rien. Toutes les 10 tonnes dans l'entrepôt. Un pur gâchis.
@p1: Le [commerce du tabac s'assèche](TOBACCO_TRADE_IS_DRYING_UP) mais on commençait vraiment à trouver de bons bancs d’huîtres. et maintenant il y a ça. Je suis vraiment maudit.
@p4: Arrête de m'ennuyer avec tes problèmes. Je t'ecoutais pendant que tu servais les verres, mais tu commences vraiment à m'ennuyer maintenant.
@p4: Tout ça m'est complètement égal ces jours-ci. Où est &p12_firstname ? Ne devrais-tu pas te plaindre à ta charmante nouvelle épouse plutôt ?
@note: &p1 boit son verre d'un trait. Il s'en verse un autre.
@p1: Au diable tout ça. Tu sais très bien où elle est et avec qui. Je ne sais pas ce qu'elle trouve à &p7_firstname, mais elles sont toujours fourrées ensemble en ce moment.
@p2: T'as pas raison, ta nouvelle amie a dit qu'elle allait sur le balcon pour saluer &p12_firstname. Je n'ai pas encore vu &p7_firstname aujourd'hui.
@p1: Ce n'est pas mon amie. C'est mon avocate. Bref. C'est le mari de &p7_firstname dont j'ai besoin. Où est Bone ?
@p4: Chéri, il est au &clubhouse bien sûr. C'est le seul endroit où lui et le Boche peuvent se cacher pour faire tu-sais-quoi.
@p2: J'ai vu M. &p10_lastname y aller à l'instant, vous pensez qu'il soit aussi un Fumeur inscrit ?
@note: &p4 mime de prendre une longue bouffée avec une pipe en utilisant la paille de sa boisson. Puis elle éclate de rire.
@p2: <i>(excitée)</i> Père ! Regarde ! Il y a un radeau qui approche ! Il vient de ce grand navire ancré un peu plus loin sur la côte !
@note: &p2 pointe du doigt vers la mer. &p1 plisse les yeux vers l'horizon.
@note: &p1 pose son verre et passe la tête dans le couloir.
@p1: &p9 ! Descends au &boathouse et vois qui c'est ! Ne les laisse pas débarquer sans les avoir inspectés d'abord.
@note: Ils regardent depuis la rambarde pendant que &p3 amarre son radeau et &p9 s'approche de lui.
@p2: Mère, regarde, il est jeune ! Comme moi !
@p4: Chérie, ce n'est pas un enfant, il a probablement le double de ton âge.
@p2: Je ne suis pas un enfant, mère. Et il a l'air très gentil. Pourquoi &p9 est-il si brutal avec lui ?
@note: &p4 prend son verre et en boit une gorgée avec nonchalance, l'air blasée. Elle ne semble pas du tout se soucier de ce qui se passe.
@p1: Je n'aime pas l'allure de tout ça. Je vais au &study pour contacter la [gendarmerie](CONSTABULARY).
@note: &p1 pose son verre et rentre à l'intérieur.
@note: &p2 attend que son père quitte la pièce, puis retrousse sa jupe et dévale les marches en courant vers le &boathouse pour saluer l'inconnu.`},chapel_0:{personIds:["p7","p14"],objects:[{id:"vial",heldBy:"p14"},{id:"key",heldBy:"p14"}],links:["masterbedroom_1","companionway_1"],clue:`@note: Une petite chapelle délabrée se dresse à la lisière de la plantation. &p7 se tient devant l'autel, tordant son mouchoir.
@note: &p14, un vieil homme frêle vêtu de l'habit traditionnel Bajau, émerge d'en dessous de l'autel.
@p7: As-tu trouvé la réponse, Babalian ? Mon mari croit profondément en toi. Dis-moi que tu peux aider.
@p14: Ce n'est pas la terre qui est malade, Mem &p7_lastname. C'est le maître.
@p7: &p1_firstname ? Mais... comment ?
@p14: Une ombre sombre s'accroche à lui. Un esprit de cupidité et de désespoir. Il saigne dans tout ce qu'il touche. Les perles... ce ne sont que les larmes de la mer infectée.
@p7: Est-ce que cela peut être arrêté ? Peux-tu la lever ?
@p14: Je ne peux pas. Mais les esprits des profondeurs proposent un marché.
@note: &p14 sort une petite fiole bleue de sa robe. Elle brille faiblement dans la pénombre.
@p14: Cette eau est bénie par les esprits de la mer. Elle nettoiera l'ombre de son âme.
@p14: Il doit en boire. Une gorgée, et la malédiction sera levée. Les perles retrouveront leur clarté.
@trigger:switch_owner:vial:p17
@p7: <i>(Prenant la [fiole](&vial|item))</i> En es-tu certain ? Cela a l'air... dangereux.
@p14: Le remède pour l'âme est souvent amer sur la langue. Aie foi dans les anciennes méthodes, Mem &p7_lastname.
@p14: Donne-lui. Ce soir. Avant que la lune ne se lève.
@note: &p14 s'incline et se retire dans l'ombre. &p7 serre la [fiole](&vial|item) contre sa poitrine.`},jungle_0:{personIds:["p5"],links:["beach_1"],clue:`@note: &p5 émerge du sentier de la jungle, serrant une bouteille de [Kornbrand](KORNBRAND) contre sa poitrine.
@note: Il s'arrête à la lisière de la clairière, scrutant nerveusement le domaine.
@p5: <i>(Marmonnant)</i> La voie est libre... bien.
@note: Au lieu de se diriger vers la maison principale, il s'approche de la clôture périphérique.
@note: Il utilise un outil pour desserrer le fil d'attache d'un poteau de clôture, laissant le grillage lâche mais visuellement intact.
@note: Il teste sa dissimulation, hochant la tête avec satisfaction. Cela a l'air intact, mais une simple pression ferme créerait une brèche de la taille d'un homme.
@note: Il glisse la bouteille sous son bras et s'éloigne précipitamment en disparaissant vers une crique lointaine.`},kitchen_0:{personIds:["p11"],objects:[],links:["beach_1"],clue:`@note: &p11 est occupée à préparer des en-cas pour la tombée de la nuit. Elle décortique des cacahuètes pour du [Kachang](KACHANG).
@note: Une voix résonne de la fenêtre.
@unknown: Je viens de voir l'Allemand au chapeau près de la &jungle. Tu m'avais demandé de te prévenir.
@p11: Merci. J'irai le retrouver à l'endroit habituel.
@p11: Peux-tu prendre le relais ? Celles-ci doivent aller à Mme &p4_lastname dans la &veranda.`},study_0:{personIds:["p8"],objects:[{id:"telephone",heldBy:"p8"}],clue:`@note: &p8 se tient près du &telephone, attendant que l'opérateur établisse la communication.
@p8: Oui, bonjour ? Le Bureau du District ? C'est Mademoiselle &p8_lastname, représentant le cabinet Sterling & Cooper.
@p8: J'appelle pour confirmer mon arrivée à la plantation Goodwill. Veuillez transmettre un télégramme à mes associés à [Sandakan](SANDAKAN).
@p8: "BIEN ARRIVEE STOP AUDIT COMMENCE STOP SITUATION PRECAIRE STOP FERA RAPPORT LUNDI STOP"
@p8: Oui, c'est tout. Merci.
@note: Elle raccroche le récepteur et soupire, lissant sa jupe. Elle jette un regard critique autour du bureau poussiéreux, notant les piles de papiers désorganisés.
@p8: Qu'est-ce que je fais ici si loin de la civilisation. Je dois être folle.`},study_1:{personIds:["p1"],objects:[{id:"telephone",heldBy:"p1"},{id:"lighter",heldBy:"p1"}],links:["library_2","boathouse_0"],clue:`@note: &p1 est dans le bureau, parlant à quelqu'un dans le couloir.
@p1: Et vous l'avez laissé avec Lune ? À quoi pensiez-vous. Oui, allez. Je m'en occupe.
@note: &p1 décroche le &telephone et commence à parler dans le récepteur.
@p1: Agent du district ? C'est &p1 de la plantation Goodwill. Je veux signaler un visiteur inattendu, un certain M. &p3_firstname &p3_lastname qui a amarré son radeau à mon quai. Il prétend être le seul survivant d'une attaque de pirates sur la côte. Seriez-vous assez aimable pour avertir la [gendarmerie](CONSTABULARY) ?
@p1: De plus, je voudrais savoir si des navires de la Royal Navy portés disparus ont été signalés dans ces eaux. L'histoire de ce type est louche. Très louche même.
@p1: Le survivant me fait l'effet d'un jeune blanc-bec, beaucoup trop effronté à mon goût. Mon chef [jaga](JAGA) &p9_firstname l'a interrogé au &boathouse. Son comportement ne me plaît pas du tout.
@p1: Il se pourrait qu'il soit la victime qu'il prétend, mais pour autant que je sache, il est peut-être un simple scélérat ou une sentinelle pour les <c>Nips</c>. Je rappellerai aux premières lueurs de l'aube. J'attends que vous ayez les détails d'ici là. Bien obligé.
@note: &p1 raccroche le téléphone.
@note: Quelqu'un frappe à la porte.
@unknown: Tuan Bone vous attend dans la &library.
@note: Si quelqu'un se trouve aux abords de la pièce pendant l'événement, je n'ai pas besoin de savoir qui ils sont, ils resteront simplement comme des fantômes dans l'ombre.
`},boathouse_0:{personIds:["p3","p9"],objects:[{id:"pouch",heldBy:"p3"}],links:["boathouse_1","balcony_0"],clue:`@note: Je vois quelqu'un tirer un petit radeau sur le quai. Il semble être un jeune homme propre et soigné mais son uniforme est en lambeaux et imbibé de sang et de boue. C'est &p3. Il a l'air épuisé.
@note: La carrure imposante de &p9 bloque son chemin, la main posée sur l'épée dans son fourreau.
@p9: Halte. Pas un pas de plus. Qui êtes-vous ? Que faites-vous ici ?
@p3: Mon brave, une minute. Laissez-moi vous expliquer. Puis-je parler à votre maître ? Nous sommes sur une plantation britannique, n'est-ce pas ? J'ai pu le deviner de loin quand j'ai vu le train à vapeur et cet inimitable terrain de croquet.
@p3: Il faut respecter une nation qui s'acharne ainsi à recréer une pelouse anglaise dans la jungle. Et ils ont fait un sacré bon travail, devrais-je ajouter. On se sent comme à la maison.
@note: &p3 a réussi à atteindre le rivage et se tient maintenant près de &p9, essayant de l'embobiner pour entrer dans la maison, mais je ne suis pas sûr que &p9 va se laisser faire.
@p3: Je ne suis pas ici pour causer des ennuis, je cherche seulement l'asile pour la nuit. Mon navire a été attaqué par des pirates au large de la côte. J'ai réussi à me cacher derrière la [grille anti-pirates](PIRACY_GRILLE) dans la cabine des officiers, mais le reste de mon équipage... ils ont tous été massacrés.
@p3: Je suis avec le gouvernement britannique. Nous transportions une cargaison de [Chandu](CHANDU), mais les pirates ont tout pris.
@p9: Vous êtes bien trop jeune pour être officier sur un navire de la Royal Navy. Pourquoi vous auraient-ils mis en charge à votre âge ? Et si vous ne l'étiez pas, comment avez-vous réussi à vous cacher derrière la grille contrairement aux véritables officiers ?
@note: &p9 se rapproche tout près de &p3, la main serrée sur la garde de son épée.
@p9: Et c'est vraiment suspect que vous soyez le seul en vie. Vous allez faire demi-tour, remonter sur le radeau et m'emmener avec vous au bateau. Je vais vérifier la véracité de votre histoire.
@p3: Ce n'est pas nécessaire. Il n'y a rien là-bas mis à part le spectacle macabre de mes camarades d'équipage morts, je vous le dis.
@note: &p3 se montre remarquablement évasif, il y a plus que cela dans son histoire. Il vaudrait mieux que je note cela, j'y reviendrai plus tard.
@note: le cri d'une femme s'entend derrière eux, ça vient d'une &balcony perchée au bord de la falaise, surplombant la Mer de Chine.
@note: Le son distrait &p9 pour une seconde, assez pour interrompre brusquement son interrogatoire.
@note: Une jeune femme intervient, se plaçant entre les deux hommes. Pas besoin de deviner pour savoir que c'est &p2 avec un grand sourire.
`},boathouse_1:{personIds:["p3","p2","p9"],objects:[{id:"pouch",heldBy:"p3"}],links:["veranda_0","guesthouse_2","balcony_0","kitchen_2"],clue:`@p2: Oh, arrêtez, &p9 ! Père voudra le voir. Laissez-le passer.
@note: &p2 se précipite à la rencontre de &p3, tendant la main pour une poignée de main.
@p2: Ne faites pas attention à lui. Je m'appelle &p2_firstname &p2_lastname, quel est votre nom ?
@p3: Je m'appelle &p3_firstname &p3_lastname. Ravi de faire votre connaissance, mademoiselle.
@p2: Venez avec moi à la &veranda pour rencontrer tout le monde. Ma mère &p4_firstname y est déjà et prend son premier [Sundowner](SUNDOWNER). Mon père y était aussi, mais il a filé dans le &study. Pour vous dénoncer, j'en suis sûre. Il peut être tellement paranoïaque. Il sera de retour pour 18 heures pour son Sundowner.
@p3: Mademoiselle &p2_lastname, je ne veux pas être impoli, mais je viens de vivre le moment le plus traumatisant de ma vie. Pourriez-vous m'indiquer un endroit où je pourrais me rafraîchir et enfiler des vêtements propres d'abord ? Si ce n'est pas trop vous demander.
@p2: Oh mon Dieu ! Où sont mes bonnes manières ! Bien sûr, M. &p3_lastname, venez avec moi. Je vais vous montrer la &guesthouse.
@p2: &p9, pouvez-vous dire à &p11_firstname de venir à la maison d'amis avec des serviettes propres pour M. &p3_firstname ? Elle était dans la &kitchen tout à l'heure. Merci.
@note: &p9 s'incline. Il n'approuve peut-être pas, mais il respecte la jeune femme.
@p9: Bien sûr, [petite Mem](MEM). J'irai d'abord avertir le [Tuan Besar](TUAN_BESAR) de l'arrivée de notre invité, puis j'irai la chercher.
@note: &p2 sourit et concentre de nouveau son attention sur &p3.
@p2: Venez, venez. Allons-y.`},balcony_0:{personIds:["p12"],links:["balcony_1"],clue:`@note: &p12 se tient seule au bord du précipice, le regard perdu dans la brume verte tourbillonnante qui s'élève de la mer de Sulu.
@p12: Ce serait si facile. À peine un pas.
@p12: Est-ce que ça ferait mal ? S'écraser contre les rochers ? Ou la brume me rattraperait-elle ?
@note: &p12 se penche davantage dans le vide. Le vent fouette ses cheveux.
@note: Elle hurle dans le vide, puis se recompose et s'éloigne du bord.
@p12: Ou peut-être... peut-être que ce jeune homme en bas, qui arrive sur son radeau... peut-être qu'il est mon Saint-Georges venu m'arracher de ce maudit rocher.
@note: &p8 monte les marches vers le pont.
@note: &p12 essuie violemment les larmes sur ses joues. Elle redresse ses cheveux et affiche un sourire feint.
@p12: Reprends-toi, &p12_firstname. C'est l'heure du spectacle.
@p12: La maîtresse de maison se doit d'accueillir la toute dernière petite acquisition du maître avec la dignité qui sied à son rang.`},balcony_1:{personIds:["p12","p8"],links:["balcony_2"],clue:`@note: &p12 se tourne de nouveau vers la mer alors que &p8 monte les marches.
@p8: Bonsoir, &p12_firstname. Je suis &p8_firstname, c'est un plaisir de faire votre connaissance.
@p12: J'en suis certaine.
@note: &p12 garde le dos tourné un instant de plus que ce que la politesse exigerait.
@p12: <i>(se tournant, souriante)</i> C'est une belle fin d'après-midi, n'est-ce pas ?
@note: &p8 rejoint &p12 au bord du balcon.
@p8: Cette brume est très mystérieuse. Savez-vous ce qu'elle signifie ?
@p12: La fin des temps, Mademoiselle &p8_lastname. Tout comme [la fumée noire](BLACK_SMOKE) venant du sud. La guerre approche d'ici. Nous ne pouvions pas continuer à vivre ainsi éternellement.
@p12: La Terre sous le Vent s'apprête à affronter sa plus grande tempête.
@note: &p8 et &p12 fixent la mer en silence pendant un moment.
@p8: Alors, qu'en est-il de Mademoiselle &p7_lastname ? Elle semble bien trop belle pour un homme comme M. Bone. Il est si... négligé. Sa barbe semble n'avoir pas été lavée depuis longtemps et franchement, d'après ce que j'ai pu voir de ses comptes, il est dans une situation financière décidément très délicate. On se demande bien ce qu'elle peut lui trouver.
@p12: <i>(riant)</i> Il est fauché comme les blés, ça, c'est certain. L'amour est mystérieux, n'est-ce pas ? Ou peut-être est-ce simplement une question de goûts communs.
@p8: Goûts communs ?
@p12: Ils ont tous deux un sacré appétit pour la pipe. L'opium les lie plus intimement que n'importe quelle attraction physique.
@p8: C'est très sombre.
@p12: Changeons de sujet. Elle arrive.`},kitchen_2:{personIds:["p9","p11"],links:["workerquarters_3"],clue:`@note: La cuisine est une véritable fournaise. &p11 s'affaire avec un mortier et un pilon en pierre, le visage luisant de sueur.
@note: &p9 entre en trombe.
@p9: La [petite Mem](MEM) te veut à la maison des invités. Des serviettes propres pour le nouvel arrivant.
@p11: <i>(sans lever les yeux)</i> Je suis occupée. Pourquoi ne demandes-tu pas à l'une des autres filles ?
@p9: Parce qu'elle a expressément demandé après toi par ton nom.
@p11: Mem &p4_lastname a commandé un plateau de [Small Chops](SMALL_CHOPS) pour la &veranda, je n'ai pas le temps pour tes exigences.
@p9: <i>(En colère)</i> Elle ne peut pas te dire quoi faire. Elle n'a pas été la véritable maîtresse de ce domaine depuis des années, qu'elle se l'imagine ou non.
@p9: De toute façon, le gin s'emparera de son emprise habituelle bien assez vite. Comme chaque soir.
@p11: Nous verrons bien.
@p9: Fais juste ce qu'on te dit pour une fois.
@note: &p11 claque son couteau sur la table et se retourne vers &p9.
@p11: Arrête d'agir ainsi. Je ne peux pas partir avec toi. Ton plan est insensé et je ne t'aime pas. Peux-tu s'il te plaît comprendre ? Je forgerai ma propre chance.
@p9: Retrouve-moi simplement aux &workerquarters quand tu auras terminé.
@note: &p9 fait demi-tour et sort en marchant au pas de charge, claquant la porte.
@note: &p11 attend un instant, puis s'essuie les mains. Elle ouvre un placard et en sort une pile de serviettes propres ainsi qu'un ensemble de vêtements blancs.
@note: Elle se dirige vers la &guesthouse.`},companionway_1:{personIds:["p14"],objects:[{id:"key",heldBy:"p14"}],links:["boathouse_2"],clue:`@note: &p14 fouille dans quelques caisses, dans l'obscurité de la &companionway.
@p14: Où est-il ? Ils avaient dit que les rations étaient stockées ici.
@note: &p14 craque une allumette pour allumer une bougie.
@note: L'éclat soudain illumine le visage de &p14 et se reflète dans un vieux miroir posé sur le mur.
@note: Pendant une fraction de seconde, une [image fantôme](GHOST_IMAGE) de l'expression surprise de &p14 flotte dans les airs.
@note: &p14 est assis sur une caisse, mangeant des rations tirées d'une boîte de conserve.
@note: Le bruit provenant du &boathouse semble s'être calmé.
@p14: Enfin. Le repos.
@note: Il s'essuie la bouche et se lève.
@p14: Voyons maintenant ce que les esprits ont remué avec cette visite.
@note: &p14 sort de sa cachette discrètement.`},boathouse_2:{personIds:["p14"],objects:[{id:"key",heldBy:"p14"}],links:["boat_3"],clue:`@note: &p14 se tient sur la jetée du &boathouse, se protégeant les yeux du soleil.
@note: Il examine les attaches d'un petit radeau en bois qui ballotte dans l'eau.
@p14: Curieux. D'où venez-vous ?
@note: Il scrute la mer et repère une silhouette à l'horizon : un &boat.
@p14: Une chaloupe ? Ancrée si loin ? C'est très étrange.
@note: Il prend une décision. &p14 détache le radeau et commence à pagayer en direction de la chaloupe.`},boat_3:{personIds:["p14"],objects:[{id:"key",heldBy:"p14"}],links:["boathouse_4"],clue:`@note: &p14 monte sur le pont du &boat depuis le radeau.
@note: La scène est macabre. Plusieurs soldats japonais et officiers de la Royal Navy gisent morts sur le pont.
@p14: Que diable s'est-il passé ici ?
@note: Il enjambe un marin tombé et trouve un [rapport](doc_mist) serré dans sa main.
@note: &p14 y jette un coup d'œil, les yeux écarquillés.
@note: Il empoche le [rapport](doc_mist).
@p14: Je dois retourner. Je ne pense pas trouver grand-chose d'autre ici.
@note: Il redescend dans le radeau et pagaie de nouveau vers le &boathouse.`},boathouse_4:{personIds:["p14"],objects:[{id:"key",heldBy:"p14"}],links:["companionway_5","clubhouse_4"],clue:`@note: &p14 amarre le radeau à la jetée.
@note: Une explosion retentit en provenance de la direction du &clubhouse.
@note: Il observe la fumée s'élever dans le ciel tandis que de minuscules silhouettes s'éparpillent dans la panique, courant vers le bâtiment.
@p14: Le chaos total.
@p14: Ils courent comme des poulets sans tête. Même cet idiot de &p9_firstname, notre soi-disant chef [Jaga](JAGA).
@p14: Le bunker mène directement au &clubhouse par le passage. Ils seront trop occupés à courir pour scruter les ombres.
@p14: Je peux m'y rendre, jeter un œil aux alentours et rester indétecté.
@note: &p14 se dirige vers l'entrée du tunnel.`},companionway_5:{personIds:["p14"],objects:[{id:"key",heldBy:"p14"}],links:["clubhouse_6"],clue:`@note: &p14 navigue dans le bunker en béton et pénètre dans le couloir de la &companionway.
@note: L'air est vicié et le tunnel est d'une étroitesse étouffante.
@p14: Si serré...
@note: Il avance à tâtons, les murs se resserrant à chaque pas.
@note: Finalement, il atteint la fin. Il repère le loquet dissimulé.
@note: D'un léger clic, il fait glisser le panneau qui mène dans le &clubhouse.`},clubhouse_6:{personIds:["p14"],objects:[{id:"key",heldBy:"p14"}],links:["clubhouse_7"],clue:`@note: &p14 sort du panneau et pénètre dans le &clubhouse en ruines.
@note: Il inspecte les débris fumants, mais son attention est captivée par un mouvement sur la pelouse à l'extérieur. Des hommes armés.
@p14: Que diable ?
@note: Il remarque une silhouette familière qui aboie des ordres.
@p14: &p13_lastname. Que fait-il ici ? Les Rajahs ne peuvent pas être au courant de ça.
@p14: Pourquoi se donner la peine de faire empoisonner &p1_firstname discrètement pour éviter tout soupçon, pour ensuite envoyer cette brute ?
@p14: Cela n'a aucun sens... à moins que...
@p14: &p13_lastname est en train de doubler les Rajahs. J'en suis sûr.
@note: &p14 recule dans les ombres profondes pour observer.`},clubhouse_7:{personIds:["p14"],objects:[{id:"key",heldBy:"p14"}],links:["railway_8"],clue:`@note: &p14 continue d'observer depuis son poste d'observation.
@note: Il voit &p13 et ses hommes se diriger vers la &railway.
@note: Quelques instants plus tard, des flammes s'élèvent le long des voies.
@p14: Folie ! Les champs de tabac sont juste là !
@p14: La saison a été sèche... tout va brûler. La plantation entière sera consumée !
@p14: Ce n'est pas ce que les Rajahs auraient voulu. Que se passe-t-il ici.
@note: Réalisant le danger, &p14 sort de sa cachette.
@note: Il se précipite vers le feu qui se propage.`},railway_8:{personIds:["p14"],objects:[{id:"key",heldBy:"p14"}],links:["jungle_9"],clue:`@note: La chaleur est intense lorsque &p14 arrive à la &railway. Le feu se propage déjà rapidement, consumant l'herbe sèche tout autour.
@note: Il aperçoit &p13 se dirigeant vers la jungle, une torche toujours à la main.
@p14: <i>(Murmurant)</i> Espèce d'idiot. Espèce d'idiot sanguinaire.
@p14: Pourquoi détruire tout ça ?
@note: La colère remplace la peur. &p14 sort de la fumée et se dirige dans la direction de &p13.`},balcony_2:{personIds:["p7","p8","p12"],links:["chapel_0","library_3","balcony_3"],clue:`@note: &p7 rejoint les dames sur le balcon.
@p7: Est-ce que je vous interromps ?
@p12: Pas du tout, ma chère. Nous étions juste en train de refaire le monde. Ou du moins la plantation.
@note: &p12 verse un verre pour &p7.
@p12: Le Seigneur a-t-il répondu à vos prières ?
@p7: Je ne sais pas. Je ne suis plus sûre de croire en lui. Ce n'est plus qu'un rituel à ce stade.
@p8: Alors, pouvez-vous m'en dire plus sur ce &p5_lastname ? Ça ne me semble pas très rassurant d'avoir un <c>Hun</c> qui se promène autour du &clubhouse, surtout avec la façon dont les choses tournent en Europe.
@p12: N'avez-vous pas remarqué ce pauvre bougre ? Il suit &p4_firstname comme un animal blessé depuis des semaines.
@p7: C'est diablement pathétique. Il a un faible pour elle depuis longtemps, n'est-ce pas ?
@p12: Toujours. Mais maintenant qu'elle est divorcée, il pense avoir sa chance. Il n'en a aucune. C'est une chiffe molle. Il n'a aucune colonne vertébrale pour ainsi dire. Et c'est un <c>Jerry</c>. Se marier avec ces gens-là, ça ne se fait tout simplement pas de nos jours. On ne voudrait tout simplement pas être vue avec lui.
@p8: Et qu'en est-il de vous et &p1_firstname, &p12_firstname ?
@note: &p12 prend une longue gorgée de son [Gin Pahit](GIN_PAHITS) avant de répondre.
@p12: Jerry... il m'a fait tourner la tête autrefois. J'étais une jeune fille naïve, pleine d'illusions. Je pensais avoir atterri en plein milieu d'un roman à l'eau de rose.
@p12: Mais une fois l'effet de nouveauté dissipé et qu'il a eu ce qu'il voulait... eh bien, je suis devenue un énième trophée. Quelque chose à garder sur la plantation pour que les voisins l'admirent. Je m'ennuie à mourir, mesdames. S'il n'y avait pas le gin et les ragots, je crois que je perdrais complètement la tête.
@p8: Vous me pardonnerez d'être effroyablement directe, &p7_firstname, mais vous et M. &p6_lastname ? Cela semble... un assortiment plutôt singulier, si je puis me permettre.
@p7: Vous êtes une femme très curieuse, Mademoiselle &p8_firstname.
@p8: Je vous implore de me pardonner. Je passe toutes mes heures plongée dans les registres comptables, à ne manipuler que des chiffres et des statistiques. J'ai bien peur d'avoir complètement oublié mes bonnes manières.
@p7: Ça peut paraître étrange pour quelqu'un de l'extérieur, je le sais bien. Mais je tiens beaucoup à lui. C'est une âme transparente qui a le cœur sur la main, vous savez. Il remuerait ciel et terre pour moi.
@p8: Même malgré... son vice ? La pipe est un maître impitoyable, &p7_firstname.
@p7: La pipe ? C'est la seule chose qui atténue la douleur. Ces blessures de la Grande Guerre... elles ne guérissent jamais vraiment. Elles hantent un homme.
@p7: Mais j'ai des relations à Shanghai. Je peux me procurer des produits pharmaceutiques adéquats, de qualité médicale. Je prends des dispositions pour les faire expédier sur les îles. Je dois d'abord accomplir une certaine... obligation pour un monsieur ici.
@p8: Des relations à Shanghai ? Êtes-vous un agent bolchevique, &p7_firstname ?
@p7: <i>(Rit doucement)</i> Tout le monde a ses propres théories de nos jours, mais la vérité est bien plus prosaïque, ma chère. Je suis simplement une Russe Blanche, l'une des milliers qui ont fui les Rouges quand notre monde a sombré dans le chaos.
@p7: Croyez-le ou non, ma mère était une Grande-Duchesse de l'ancien Empire. Mais la Guerre Civile remet tout le monde au même niveau. Je me suis retrouvée à Shanghai, à gagner ma croûte comme taxi-girl dans un cabaret de jazz.
@p7: J'y fus séduite par un simple soldat de ligne... et bien, vous connaissez la suite.
@note: &p8 termine son verre et le repose.
@p8: Eh bien, ce fut éclairant. Mais je dois m'excuser. J'ai quelques registres à mettre en ordre dans la &library avant ma réunion avec &p1_firstname plus tard.
@note: &p8 quitte le pont.`},garden_2:{personIds:["p5","p4"],links:["clubhouse_3"],clue:`@note: &p5 traverse le jardin, une bouteille de [Kornbrand](KORNBRAND) à la main.
@p4: <i>(Depuis la &veranda)</i> &p5_firstname ! Attends ! Veux-tu un [Sundowner](SUNDOWNER) ?
@p5: Non merci, &p4_firstname. Bone et &p10_firstname m'attendent au &clubhouse.
@note: &p4 dévale les escaliers pour le rattraper.
@p4: S'il te plaît, &p5_firstname. J'ai juste besoin d'un ami à qui parler. Puis-je simplement t'accompagner sur le chemin ?
@p5: Bien sûr, ma chère. Tu sais que j'ai toujours du temps pour toi.
@p4: &p1_firstname est hors de lui au sujet des perles. Personne ne veut y toucher dans leur état actuel.
@p4: Je sais que je fais semblant de m'en moquer, mais... si nous perdons la plantation...
@note: &p5 rit.
@p5: Jerry et Bone sont des idiots. Tous les deux.
@p5: Ce "Tourbillon Rouge" ne se serait jamais produit dans nos fermes perlières au pays avant la guerre.
@p4: Qu'est-ce que tu veux dire ? Tu sais quelque chose ?
@p5: Je ne les aide pas. Et tu ne devrais pas non plus. Pas après ce qu'il t'a fait. Pourquoi l'aiderais-tu ?
@p4: Mais ce sont tes amis.
@p5: Des amis. Quels genre d'amis sont-ils vraiment pour moi ? Ils me tolèrent, mais je sais ce qu'ils disent dans mon dos. Ce n'est pas le grand amour entre eux et les Allemands.
@p5: Je ne serais pas surpris s'ils pensaient que je suis un nazi malgré tout ce que nous avons traversé, juste à cause de mes origines. Au diable, tous autant qu'ils sont.
@p4: Dis-le moi. Au nom du bon vieux temps. S'il te plaît.
@p5: Ce n'est pas une malédiction, &p4_firstname, c'est tout ce que je dirai.
@p4: Tu dois leur dire comment arranger ça. Tu es un homme bien. Ne sois pas si mesquin.
@note: &p4 retourne vers la &veranda. &p5 reprend sa marche vers le &clubhouse.`},guesthouse_2:{personIds:["p2","p3"],objects:[{id:"pouch",heldBy:"p3"}],links:["veranda_3"],clue:`@note: &p2 escorte &p3 jusqu'à la maison des invités.
@p2: La maison d'amis est sur la droite ici, juste après la salle d'eau.
@note: &p3 s'arrête.
@p3: Puis-je... Puis-je utiliser la salle d'eau maintenant, rapidement ? Y a-t-il de l'eau ?
@p2: Oh oui. Nous avons toujours de l'eau. Suivez-moi.
@p2: Ne voulez-vous pas attendre que &p11 arrive d'abord avec des serviettes propres ?
@p3: J'ai juste vraiment besoin de me nettoyer. Avec cette chaleur, je sécherai très vite.
@p2: Oh, mais vous devez attendre les serviettes.
@p3: Je m'en sortirai très bien. C'est ici ?
@note: &p2 hoche la tête. &p3 ouvre la porte et entre.
@note: Il retire son uniforme en lambeaux et ne conserve qu'une &pouch qu'il cachait sous sa veste.
@note: &p3 attrape un [Gayung](GAYUNG) pour puiser de l'eau froide dans la [Shanghai Jar](SHANGAI_JAR) et se la verse sur les cheveux, le visage et le corps, un regard de pure satisfaction sur le visage.
@note: Il frotte la boue et le sang pendant un long moment.
@note: Quand il s'arrête enfin, il reste planté là une minute, puis baisse les yeux vers sa main droite. Elle tremble de façon incontrôlable.
@note: &p3 se met à sangloter doucement.
@p3: &p3_firstname, reprends-toi, mon vieux. C'est fini. Tu as réussi. Tu es en sécurité.
@note: Il regarde autour de lui dans la petite pièce. Le sol est fait de pierres pour empêcher le bois de pourrir. Le sol est incliné vers une évacuation qui donne sur le jardin.
@note: Il sursaute en entendant &p11 arriver. Il reste immobile une minute, écoutant la conversation de &p2_firstname et &p11, et attend que &p11 parte avant de reprendre ses recherches.
@note: &p3 remarque une pierre descellée sur le sol. Il la soulève et cache la petite blague en dessous avant de la remettre en place.
@p2: <i>(Depuis l'extérieur de la porte)</i> J'ai les serviettes et des vêtements propres. Ce sont des [blancs empesés](STARCHED_WHITES), j'espère que cela ira. C'est tout ce que les hommes portent ici. Ce n'est pas aussi chic que ce dont vous avez l'habitude, j'en suis sûre. Puis-je entrouvrir la porte et vous les donner ?
@note: &p3 passe les mains par la porte et &p2 y dépose les serviettes et les vêtements.
@p2: J'espère qu'ils vous iront. Ils appartenaient à un jeune cousin de mon père qui est mort de la [fièvre](FEVER). Il faisait à peu près votre taille, je dirais.
@p2: Ne vous inquiétez pas, les vêtements sont propres.
@note: &p2 attend patiemment que &p3 finisse de se sécher.
@p2: Mes parents ont divorcé il y a un an. Ma mère a été... Eh bien, vous verrez par vous-même bientôt. C'est une femme adorable. Elle était la plus belle femme de tout [Sabah](SABAH) quand elle était plus jeune, mais le soleil a fait des ravages au fil des années.
@p2: Mes parents ont divorcé et mon père s'est remarié dans les semaines qui ont suivi. Ma mère boit beaucoup maintenant.
@p2: Mais elle est adorable, vous verrez.
@p2: Et j'ai un frère à Londres. Il est parti en pension quand j'étais bébé. Mais je crois que vous le savez déjà, n'est-ce pas ?
@note: &p3 sort de la salle d'eau, regardant &p2 avec curiosité.
@p3: Je ne sais pas de quoi vous parlez.
@p2: Balivernes ! Vous savez exactement de quoi je parle.
@note: &p2 lui lance un regard entendu, comme si elle s'attendait à ce qu'il confirme ce fait.
@p3: <i>(changeant de sujet)</i> Merci pour les vêtements. Ils me vont très bien. Je ne sais comment vous remercier.
@p2: De rien. Je suis heureuse qu'ils vous plaisent.
@p2: Venez, venez maintenant. Allons retrouver les autres. Le dîner sera prêt sous peu. Vous devez être affamé.
@note: Ils se dirigent vers la &veranda.`},veranda_1:{personIds:["p4"],objects:[{id:"photo",heldBy:"p4"}],links:["garden_2"],clue:`@note: &p4 est seule sur la &veranda, sirotant un verre.
@note: Elle prend une &photo sur le manteau de la cheminée.
@p4: <i>(Se moque)</i> Regarde-toi.
@note: &p4 vide son verre. Elle fixe la photo avec un mélange de haine et de pitié.
@p4: Il se lassera de toi aussi, ma chère. Tout comme il s'est lassé de moi.
@p4: Et ensuite ce sera le tour de la petite mademoiselle &p8_lastname. Tu verras.
@note: Elle claque la &photo face contre table.
@note: &p4 aperçoit quelqu'un dehors et court l'accueillir.`},masterbedroom_1:{personIds:["p7"],objects:[{id:"vial",heldBy:"p7"}],clue:`@note: La pièce est vide. &p7 se glisse à l'intérieur, refermant doucement la porte.
@note: Elle s'approche de la table de chevet où se trouve un flacon de médicaments.
@note: Elle sort une fiole de sa poche.
@note: Elle débouche le flacon de médicaments et verse son contenu dans un pot de fleurs.
@note: Ensuite, elle verse le liquide de la fiole dans le flacon de médicaments.
@note: Elle rebouche le flacon, cache la &vial et se retourne pour partir.
@note: En sortant, son regard s'attarde sur une [lettre](doc_suicidenote) posée sur la commode.
@p7: Oh &p12_firstname...`},veranda_3:{personIds:["p1","p2","p3","p4"],objects:[{id:"lighter",heldBy:"p1"}],links:["clubhouse_0","clubhouse_1","clubhouse_2","clubhouse_3","balcony_0","balcony_1","clubhouse_4"],clue:`@note: &p2 et &p3 arrivent sur la &veranda. &p4 sirote toujours son verre.
@p2: Mère ! Regarde qui est là ! M. &p3_lastname s'est fait une beauté. N'est-il pas élégant ?
@p4: Il présente bien, en effet. Une nette amélioration par rapport au gâchis sanglant qui est arrivé sur notre pas de porte.
@p3: Vous êtes trop bonne, Mme ?
@p4: Je vous en prie, appelez-moi &p4_firstname. Il n'y a pas de Mme ici, juste une ex-Mme.
@p3: Comme vous voudrez, &p4_firstname.
@p3: Si je puis demander... qui se trouve exactement sur la plantation en ce moment ? Cela semble... animé.
@p4: Oh, c'est un véritable cirque. Voyons voir...
@p4: Notre voisin est ici, &p5_firstname &p5_lastname. Je ne sais pas pourquoi. Il est toujours là. Ensuite, il y a &p6_firstname avec sa petite amie russe &p7_firstname. Ce sont de vieux amis de la famille. Bone est pratiquement un oncle pour Lune.
@p3: Pardon, Bone ?
@p4: Son nom est &p6_firstname, nous l'appelons affectueusement Bone, il n'y a aucune méchanceté derrière ce surnom.
@p4: Ensuite, il y a &p12_firstname, la... nouvelle épouse de Jeremiah.
@note: &p4 lève les yeux au ciel.
@p4: Et &p8_firstname est ici aussi. C'est l'avocate personnelle de Jeremiah. Soi-disant ici pour des "discussions juridiques et financières", mais d'un autre côté &p12_firstname était la nounou, donc on ne sait jamais avec &p1_firstname.
@p2: Elle est si jolie et élégante. J'adore ses lunettes.
@p3: C'est toute une assemblée.
@p4: Et nous ne pouvons pas oublier le personnel. Il y a &p10_firstname, il gère tout l'entretien du domaine.
@p2: Il m'a appris à pêcher !
@p4: En effet. Vous avez rencontré &p9_firstname, notre chef de la sécurité. Un vrai rayon de soleil, n'est-ce pas ? Et &p11_firstname dirige le personnel de maison.
@note: Des bruits de pas lourds s'approchent. &p1 fait irruption sur la &veranda.
@p1: Eh bien. L'étranger prodigue prend ses aises, à ce que je vois.
@p1: &p9_firstname me dit que vous prétendez être un agent du gouvernement.
@p3: M. &p1_lastname. Eh bien, je ne dirais pas ça. Je n'ai pas vraiment dit qui j'étais, &p9 l'a juste supposé et...
@note: Un gros BOUM résonne en direction du &clubhouse. Le plancher tremble.
@p1: Au nom de Dieu, qu'est-ce que c'était ?
@p4: Je crois que ça venait du &clubhouse.
@p3: On aurait dit une explosion. M. &p1_lastname, montrez le chemin.
@p2: Attendez-moi, s'il vous plaît.
@p3: Non, &p2_firstname, c'est trop dangereux. Restez ici avec &p4_firstname. Nous revenons tout de suite.
@p1: Où est &p9 ? Je me serais attendu à ce qu'il accoure ici pour s'assurer que nous allons bien.
@p3: Il est peut-être déjà au &clubhouse ?
@p1: Vous avez sans doute raison. Je vais devoir vous faire confiance pour l'instant, M. &p3_lastname, mais sachez que ce n'est pas fini. Nous reprendrons notre petite discussion très bientôt.
@note: Alors que les 2 hommes sortent en courant, je vois 2 autres femmes entrer sur la &veranda par l'arrière.`},clubhouse_0:{personIds:["p6","p10"],objects:[{id:"opium",heldBy:"p10"},{id:"pearl",heldBy:"p6"}],links:["clubhouse_1"],clue:`@note: &p6 est assis seul dans la lumière tamisée du &clubhouse.
@note: Sur la table devant lui se trouve un bocal de [Chandu](CHANDU), une petite lampe à huile et sa pipe.
@p6: <i>(Murmurant)</i> Patience, Bone. On y est presque.
@note: Il trempe une longue aiguille en acier dans la pâte sombre, en retirant une goutte de la taille d'un pois.
@note: La tenant au-dessus de la flamme de la lampe, il regarde l'opium faire des bulles.
@note: Il fait rouler la substance chaude contre la surface plane du fourneau de la pipe, la façonnant en un petit cône.
@note: Finalement, il place la pilule sur la douille en céramique.
@p6: Très bien. Où sont mes garçons ?
@note: &p10 entre dans la pièce.
@p6: Quand on parle du loup. As-tu vu Herr &p5_firstname ?
@p10: On commence par une bouffée ? Je ne vais pas pouvoir avoir les idées claires. Ne pourrions-nous pas d'abord terminer le travail ?
@p6: Arrête de t'inquiéter. Tout est prêt, une bouffée ne te fera pas de mal.
@p10: N'oublie pas que j'installe l'alambic pour toi comme une faveur. J'ai de meilleures choses à faire.
@p6: Allez, mon vieux. Ne sois pas rabat-joie.
@p10: Très bien. Une bouffée.
@p6: Brave homme. Tiens, prends un siège.
@note: &p6 se déplace vers le banc de bois, s'inclinant sur le côté. Il appuie sa tête sur un dur oreiller.
@note: Il maintient le fourneau de la pipe au-dessus de la lampe, positionnant la pilule cuite juste au-dessus de la chaleur, en prenant soin de ne pas toucher la flamme.
@note: Alors que l'opium se vaporise, libérant un arôme doux, &p6 prend une longue bouffée. Il la garde, les yeux se fermant d'extase.
@note: Il gratte la [dross](DROSS) ressemblant à du charbon de bois de la douille et la mélange avec une nouvelle noisette de Chandu.
@p6: Rien ne se perd, rien ne se crée.
@note: Il tend la pipe à &p10.
@note: &p10 reproduit le rituel, inhalant profondément. Un regard de profonde relaxation envahit ses traits.`},clubhouse_1:{personIds:["p6","p10"],objects:[{id:"opium",heldBy:"p10"},{id:"pearl",heldBy:"p6"}],links:["clubhouse_0","clubhouse_2","library_2"],clue:`@note: L'air dans le &clubhouse est lourd d'une fumée douce et florale. &p6 et &p10 sont allongés immobiles sur les bancs, les yeux vitreux.
@p6: &p10_firstname... Regrettes-tu toujours d'avoir été poussé là-dedans ?
@p10: ... mmm... silence...
@note: Les minutes passent en silence.
@note: Un coup timide à la porte résonne à travers la brume. Un serviteur jette un coup d'œil.
@unknown: Tuan Bone ? [Tuan Besar](TUAN_BESAR) vous réclame. Il vous attend dans la &library.
@note: &p6 grogne, protégeant ses yeux de la lumière extérieure.
@p6: Dis-lui... dis-lui que je suis indisposé.
@unknown: Il a dit que c'était urgent, Tuan. À propos des perles.
@p6: <i>(Soupire lourdement)</i> Très bien, dis-lui que j'arrive.
@note: Le serviteur s'incline et se retire.`},clubhouse_2:{personIds:["p10"],objects:[{id:"opium",heldBy:"p10"}],links:["clubhouse_1","clubhouse_3"],clue:`@note: &p10 est seul dans le &clubhouse.
@note: Il s'assoit sur le banc, se frottant les tempes, essayant de se secouer des dernières volutes de la drogue.
@p10: <i>(Gémissant)</i> Shimatta... ma tête. Idée stupide. Stupide, stupide idée.
@note: Il se lève en chancelant et se dirige vers l'armoire à boissons. Il se verse un verre d'eau, s'en aspergeant le visage.
@p10: Très bien. Reprends-toi, &p10_firstname. Concentre-toi.
@note: Il regarde dans le coin de la pièce où un amas de tuyaux en cuivre et une cocotte-minute sont empilés.
@p10: Si je n'arrive pas à faire fonctionner ce foutu alambic, Tuan Bone ne me le pardonnera jamais.
@note: &p10 retrousse ses manches, prend une clé plate et s'approche de l'équipement de distillerie improvisé.
@note: On peut entendre &p6 et &p5 rire juste derrière la porte.`},clubhouse_3:{personIds:["p5","p6","p10"],objects:[{id:"opium",heldBy:"p10"}],links:["clubhouse_2","clubhouse_4"],clue:`@note: &p6 et &p5 entrent crânement dans la pièce. &p5 agite une bouteille de [Kornbrand](KORNBRAND) en l'air.
@p6: Aha ! L'artisan chevronné à l'œuvre ! Comment avance l'entreprise, &p10_firstname ?
@p10: <i>(Serrant une valve)</i> Ça progresse. Je finis juste le serpentin de condensation.
@note: L'installation est une merveille d'improvisation. Une grande cocotte-minute repose sur un brûleur à gaz, reliée à un seau refroidi à l'eau faisant office de condenseur.
@p5: Wunderbar ! Ça a l'air... strictement scientifique.
@p10: C'est rudimentaire mais efficace. Versez-le dedans.
@note: &p5 verse l'alcool clair dans la cocotte-minute. &p10 ferme le couvercle et allume le brûleur.
@note: Ils regardent avec anticipation. Lentement, quelques gouttes claires tombent du tuyau de cuivre dans un bocal.
@p6: C'est tout ? Un filet ? Nous y passerons la nuit !
@p10: La distillation prend du temps, Tuan Bone. On ne peut pas brusquer la physique.
@p6: Sornettes. Plus de chaleur, plus de pression, plus de vitesse !
@note: &p6 tend la main vers le bouton de gaz.
@p10: Non ! Ne touchez pas à ça !
@p6: Juste un tout petit peu plus...
@note: &p6 monte la flamme. La cocotte commence à trembler violemment.
@p10: Baissez-vous !
@note: Le couvercle saute dans un grondement assourdissant, remplissant la pièce de vapeur et de vapeurs d'alcool.`},clubhouse_4:{personIds:["p1","p3","p5","p6","p9","p10"],objects:[{id:"opium",heldBy:"p10"},{id:"lighter",heldBy:"p1"}],links:["clubhouse_3","dining_5","jungle_5"],clue:`@note: &p1 et &p3 font irruption dans le &clubhouse, s'attendant au pire.
@note: Au lieu d'un carnage, ils trouvent &p5, &p6 et &p10 pliés en deux, hurlant de rire. La pièce sent fortement l'alcool et le poil roussi.
@p1: Que se passe-t-il ici, nom de tonnerre ? Nous pensions que les <c>Nips</c> avaient enfin débarqué !
@p6: <i>(Essuyant les larmes de ses yeux)</i> Oh, Jerry ! Pas tout à fait, mon vieux. Juste une petite... difficulté technique.
@p5: <i>(Gloussant)</i> Ja, un accroc. Grosser Gott, quel boucan !
@p10: Je vous l'avais bien dit que la pression était trop forte, M. &p6_lastname ! Je vous l'avais dit !
@p1: Expliquez-vous. Et faites vite.
@p6: Eh bien vois-tu, &p7_firstname se plaignait que sa vodka lui manquait. Et &p5_firstname ici présent avait tout ce [Kornbrand](KORNBRAND) qui traînait...
@p10: Alors M. &p6_lastname m'a chargé de monter un alambic pour le distiller. Pour lui donner un peu plus de mordant.
@p6: Une surprise pour la belle &p7_firstname !
@p5: C'était une merveilleuse surprise. Très bruyante.
@p1: Vous auriez pu raser ce fichu Clubhouse ! Vous auriez pu nous réduire tous en cendres !
@p6: Détails, détails. Tout le monde est intact. Et regarde !
@note: &p6 brandit un petit verre de liquide clair.
@p6: Nous avons réussi à sauver un pauvre verre. Pour la dame.
@note: &p1 soupire, la tension quittant ses épaules. Il secoue la tête, réprimant un sourire.
@p1: Vous êtes tous complètement marteau, tous autant que vous êtes.
@p3: <i>(Souriant)</i> Je crois que je vais très bien m'intégrer ici.
@p1: Quand vous vous serez calmés et que vous vous serez rendus présentables, le dîner sera servi. Vous pourrez tous nous rejoindre dans la &dining. &p10_firstname, tu peux nous rejoindre aussi si tu le souhaites. C'est le moins que je puisse faire car mes amis ici t'ont entraîné dans leur folie.
@p10: Je vous remercie très sincèrement, monsieur. Je suis très reconnaissant de votre générosité.
@note: &p9 se précipite enfin sur les lieux.
@p1: Tu arrives un peu tard à la fête, mon brave. Qu'est-ce qui a bien pu te retenir ?
@p9: Je vous implore de me pardonner, [Tuan Besar](TUAN_BESAR). J'étais tout au bout de la plantation, près de la &jungle.
@p9: Que s'est-il passé ? Tout le monde va bien ?
@p6: Tout est en ordre, &p9_firstname. Repos, mon vieux.
@note: Tout le monde part vers la &dining, laissant &p9 seul et perplexe face à ce qu'il vient de voir.
@p9: Je vais retourner à mes rondes, d'accord ?
`},dining_5:{personIds:["p1","p2","p3","p4","p5","p6","p7","p8","p10","p12"],objects:[{id:"opium",heldBy:"p10"},{id:"lighter",heldBy:"p1"},{id:"pearl",heldBy:"p8"},{id:"sample",heldBy:"p8"}],links:["dining_6","garden_2","study_0"],clue:`@note: La &dining est bondée. L'air est lourd de fumée et d'odeur de porc rôti.
@p1: Je tiens à accueillir notre invité inhabituel à notre petite réception. Je dois admettre que j'étais très méfiant à l'égard de ce jeune homme à son arrivée, mais on reconnaît la véritable nature d'un homme à ses actes.
@p1: Je dois dire que j'ai été agréablement surpris par la façon dont il a réagi à notre petit... incident. Je vois qu'il a du cœur par la manière dont il a protégé &p2 et de l'audace en n'hésitant pas à courir vers le &clubhouse.
@p1: Bien sûr, il s'est avéré que ce n'était qu'une fausse alerte, mais il ne le savait pas à ce moment-là.
@note: &p1 lève son verre.
@p1: Quoi qu'il en soit, je voulais juste porter un toast au jeune homme et lui souhaiter la bienvenue sur la plantation.
@p1: À &p3_firstname, santé !
@p3: Santé, M. Goodwill. Merci. Je me sens très bien accueilli et honoré.
@note: &p1 se rassoit et se tourne d'abord vers &p8 :
@p1: J'espère que nous vous avons fait sentir la bienvenue jusqu'à présent, mademoiselle &p8_lastname.
@p8: Oh oui. Tout le monde a été merveilleusement accueillant. Merci.
@p1: Et avez-vous réussi à contacter vos collègues pour les informer que vous êtes bien arrivée ?
@p8: J'ai demandé à l'opérateur d'envoyer un télégramme. Je crois que cela suffira.
@p1: Splendide. Profitons de la soirée alors. Santé.
@note: &p1 se tourne vers &p10 :
@p1: &p10_firstname, désolé pour Bone et Herr &p5_lastname. Ne te sens pas obligé de les aider dans leurs plans farfelus la prochaine fois. Ils peuvent être assez... Insistants et persuasifs.
@p10: N'y pensez plus, monsieur. Ce sont mes propres erreurs qui ont mené à l'incident. Je serai plus prudent la prochaine fois.
@note: Plus loin, &p3 est encadré par &p6 et &p5.
@p6: Alors M. &p3_lastname, qu'est-ce qui vous amène exactement de ce côté-ci du monde ? Pardonnez-moi d'être direct, mais vous avez l'air d'un bleu et seul un vieux briscard naviguerait dans ces mers dangereuses en tant qu'autre chose qu'un simple passager.
@p3: Croyez-moi monsieur, je suis tout à fait un vieux briscard ici malgré les apparences.
@note: &p3 remonte sa manche et tend son bras. Sa main tremble.
@p3: Je n'aime pas l'admettre, mais j'ai des tremblements. Trop de [Quinine](QUININE).
@p3: <i>(désignant les femmes)</i> Et si nous n'étions pas en si charmante compagnie, je vous montrerais mes cicatrices de la jungle sur mes tibias.
@note: &p6 rit de bon cœur et tape joyeusement &p3 dans le dos, le projetant en avant.
@p6: Brave homme, brave homme. Je suis impressionné que vous ayez réussi à tenir le [sallow](SALLOW) à distance, je dois dire.
@p3: Ce n'est pas faute d'avoir essayé. J'ai affronté la malaria pas mal de fois. J'ai juste eu de la chance. Ou alors, mon foie est fait d'acier.
@note: &p6 rit à nouveau.
@p6: Pas de chance ici. Mon foie est détruit. [Tidak apa](TIDAK_APA), c'est la vie.
@p6: J'étais moi-même dans la marine, vous savez.
@p2: &p3_firstname, vous allez aimer cette histoire. Oncle Bone était un héros.
@p3: Vraiment ?
@p6: J'étais sur le [Sunning](SUNNING). 1926.
@p3: Le Sunning ? Les officiers ont repris ce navire avec de l'eau bouillante et des haches d'incendie.
@note: &p6 remonte sa manche pour révéler une vilaine cicatrice de brûlure.
@p6: L'eau bouillante. Oui. Nous avons fait ce qu'il fallait faire.
@note: &p3 hoche la tête, un respect sombre se formant.
@p3: Savez-vous ce qui s'est passé en '27 ? La Royal Navy a nettoyé [Bias Bay](BIAS_BAY). La plupart des pêcheurs de la région, coupables de piraterie ou non, y ont été massacrés. Je n'étais qu'aspirant sur le HMS Hermes. C'était ma première affectation.
@p6: J'ai entendu parler de l'opération de '27. Ça a dû être un sacré spectacle.
@p2: &p3_firstname, vous êtes un héros aussi. Je le savais.
@note: Dans le coin, &p4 est assise tranquillement, sirotant son verre. &p5 se penche vers elle.
@p5: Ce dîner mondain me rappelle le bon vieux temps, &p4_firstname. Avant la Grande Guerre. Quand les plantations allemandes régnaient en maîtres.
@p4: &p5_firstname, quand vas-tu leur annoncer ?
@p5: Pas si fort. Ils vont t'entendre.
@p4: Ils ont le droit de savoir. Garder secret ce que tu m'as dit sur la pelouse tout à l'heure est indéfendable.
@p5: J'aurais cru que tu comprendrais, toi, parmi tous. Pourquoi devrais-je leur dire ?
@p5: Changeons de sujet, je sens que les autres commencent à tendre l'oreille.
@p10: Désolé, je ne voulais pas vous interrompre.
@note: De l'autre côté de la table, &p12 et &p7 servent du vin à &p8.
@p7: Bois, ma chérie. Ça t'aidera à te détendre. Les esprits ne peuvent parler si leur réceptacle est tendu.
@p12: Parlez-nous davantage de vos voyages ! Ça doit être si excitant d'être avocate en ville.
@p8: Oh, c'est surtout de la paperasse. Mais le voyage jusqu'ici depuis [Sandakan](SANDAKAN) a été... mouvementé.
@p3: <i>(Tournant la tête)</i> Je suis désolé de vous interrompre, mademoiselle &p8_lastname. Avez-vous dit que vous avez fait tout ce chemin depuis [Sandakan](SANDAKAN) ?
@p8: Mais oui. À bord du [Straits Steamship](STRAITS_STEAMSHIP).
@p3: Vous avez navigué 20 heures de [Sandakan](SANDAKAN) à Tawau à travers les eaux infestées de pirates de la mer de Sulu ? Pour une femme, c'est remarquablement intrépide. Voire carrément téméraire.
@note: &p8 rougit sous son regard insistant.
@p8: J'étais sous la protection de &p1_firstname, naturellement. Ses affaires juridiques nécessitaient mon attention, et je considérais qu'il s'agissait simplement d'une question de devoir.
@p2: J'ai visité [Sandakan](SANDAKAN) avec Père à plusieurs reprises. C'est un endroit grandiose. Je n'ai jamais vu un port aussi spectaculaire.
@p3: Avec tout le respect que je vous dois, &p2_firstname, [Sandakan](SANDAKAN) montre un tout autre visage selon que l'on fréquente ou non le cercle du Gouverneur. On dit qu'il compte plus de millionnaires que n'importe quelle autre ville sur terre, mais la dorure y est bien fine. La misère est grande une fois que l'on quitte les bungalows à flanc de falaise.
@p8: &p3_firstname a raison, même si je ne changerais rien pour rien au monde. Sinon, je n'aurais jamais rencontré mon promis.
@p12: Votre promis ? Vous êtes donc prise ?
@p8: Oui, je dois me marier à mon retour en ville. Je ne suis absente que depuis quarante-huit heures, et je dois avouer qu'il me manque cruellement.
@note: &p12 se tourne vers &p7 et sourit.
@p12: Je bois à cela.
@p7: Aux amoureux !
@note: Puis quelque chose survient brusquement. Un fracas bruyant, des halètements, et quelqu'un de nouveau fait son entrée. Son aura est très puissante, mais aussi très sombre. Je ne le connais pas. Qui est-ce ?`},dining_6:{personIds:["p1","p2","p3","p4","p5","p6","p7","p8","p10","p12","p13"],objects:[{id:"lighter",heldBy:"p1"},{id:"opium",heldBy:"p10"},{id:"pearl",heldBy:"p8"},{id:"sample",heldBy:"p8"}],links:["dining_5","dining_7","jungle_5"],clue:`@note: Un silence de mort s'abat sur la pièce alors que les portes s'ouvrent à la volée.
@note: Un grand homme blanc, &p13, entre à grands pas, deux habitants à l'air patibulaire se tiennent à l'extérieur de la pièce, gardant la porte. Il est lourdement armé.
@p13: Désolé de gâcher la fête, mesdames et messieurs. Ne faites pas attention à moi.
@note: &p3 s'apprête à se lever mais &p10 pose sa main sur son épaule.
@p10: <i>(Doucement)</i> Ne le fais pas. C'est &p13_lastname. Il ne vaut mieux pas s'y frotter, crois-moi.
@p1: Que faites-vous ici ? &p9, faites sortir cet homme !
@p13: Assieds-toi, &p1. &p9 ne viendra pas.
@p1: Que lui avez-vous fait ? Il a intérêt à être en vie.
@p13: Ton chien de garde est... en train de faire la sieste.
@p13: Je suis juste venu chercher ce qui m'appartient. Tu as raté l'échéance, &p1.
@p1: Je viens tout juste de rentrer de Sandakan. J'ai besoin de plus de temps.
@p13: Je me fiche de tes excuses.
@note: &p13 se dirige vers &p12 et &p8.
@p13: Excusez mon intrusion, mesdames. J'aurais aimé que nous nous rencontrions dans de meilleures circonstances, mais votre homme ici présent ne paie pas ses dettes.
@note: &p12 gronde après lui. &p8 garde les yeux baissés.
@note: &p13 sort une cigarette. Il tapote ses poches.
@p13: Quelqu'un a du feu ?
@note: &p1 hésite, puis fouille dans sa poche et sort son &lighter. Il l'allume et lui offre la flamme.
@p13: <i>(Inhalant profondément)</i> Merci.
@note: &p13 prend le &lighter de la main de &p1. Il l'observe sous tous ses angles, admirant le placage or.
@trigger:switch_owner:lighter:p13
@p13: Joli modèle. Du solide.
@p13: Je vais garder ça. En guise d'acompte.
@note: Il glisse le &lighter dans sa propre poche.
@p13: Je veux mon argent rapidement, Jeremiah Goodwill. Sinon je réduis tout cet endroit en cendres.
@p13: <i>(S'inclinant d'un air théâtral devant la table)</i> Mes excuses pour cette interruption, mesdames et messieurs. Je vous en prie, reprenez les festivités.
@note: &p13 tourne les talons et s'en va d'un pas militaire, son rire résonnant derrière lui.
`},guesthouse_4:{personIds:["p8"],objects:[{id:"sample",heldBy:"p8"},{id:"pouch",heldBy:"p8"},{id:"pearl",heldBy:"p8"}],links:["dining_5","clubhouse_4"],clue:`@note: &p8 se dirige vers la chambre d'amis pour se rafraîchir avant le dîner.
@note: Alors qu'elle entre dans le cabinet de toilette, elle sent une grosse pierre vaciller sous son talon.
@note: Curieuse, elle s'agenouille et la soulève. En dessous, elle trouve une lourde &pouch en cuir.
@note: Elle l'ouvre. À l'intérieur se trouvent un revolver et un petit flacon en verre avec une étiquette de risque biologique.
@p8: Que diable... ?
@note: Elle empoche le &sample et le revolver.
@note: Elle prend la &pouch vide et la jette dans les hautes herbes derrière le cabinet de toilette.
@note: Soudain, une forte explosion secoue le sol, venant de la direction du &clubhouse.
@note: Elle regarde impassible &p9 courir à toute vitesse depuis les &workerquarters vers la source de l'explosion.
@note: &p8 lisse calmement sa robe et se dirige de nouveau vers la &dining.`},balcony_3:{personIds:["p7","p12"],links:["veranda_4","clubhouse_4","balcony_2"],clue:`@note: &p12 et &p7 sont appuyées contre la rambarde, un verre à la main.
@p7: Tu te mets dans un état épouvantable, &p12_firstname. La petite mademoiselle &p8_lastname n'est... qu'une ressource professionnelle pour &p1_firstname. Ce n'est pas une mauvaise personne, elle a l'air assez courtoise.
@p12: Je me fiche de ses 'ressources' ou de sa gentillesse. Regarde-la.
@p7: C'est une dame de loi, chérie. Sa profession exige qu'elle soit à la fois imposante et décorative.
@p12: La trouves-tu séduisante ? Est-elle plus jeune que moi ? Je n'arrive pas à dire. Sa peau est si... tendue.
@p7: Tu es ravissante, &p12_firstname. Jerry t'a choisie.
@p12: Vraiment ? Ou étais-je simplement la seule jeune femme blanche à des lieues à la ronde dans cette jungle maudite ?
@note: Un grondement assourdissant déchire l'air. Le verre en cristal dans la main de &p12 glisse et se brise sur le plancher.
@p12: Doux Jésus ! Qu'est-ce que c'était ?
@p7: De la fumée s'échappe du &clubhouse...
@p12: Vite !
@note: Elles foncent vers la &veranda.`},workerquarters_3:{personIds:["p9","p11"],links:["clubhouse_4","kitchen_4"],clue:`@note: Dans l'ombre des quartiers, &p9 attrape le bras de &p11 alors qu'elle essaie de passer.
@p9: &p11_firstname, s'il te plaît. Écoute-moi une dernière fois. Nous partons aux premières lueurs de l'aube.
@p11: <i>(Dégageant son bras violemment)</i> Je n'écoute rien venant de toi, &p9_firstname. J'ai du travail à faire.
@p9: Les Japonais arrivent. Pas 'peut-être', ni 'bientôt'. Ils sont là.
@p9: Ils ont des projets pour cet endroit. Pour les Tuans. Tous ceux qui restent seront massacrés. Mais nous... nous leur sommes invisibles. Si nous partons maintenant, nous vivrons. Je t'aime, &p11_firstname. Je ne te verrai pas abattue pour l'amour de ces fantômes blancs.
@p11: <i>(Elle s'arrête, le regardant avec un froid mépris)</i> Tu penses que j'ai besoin de ta protection ? J'ai mes propres projets, &p9_firstname. Des projets déjà en marche qui offrent bien plus de sécurité que de courir dans la jungle avec un déserteur.
@p9: Un déserteur ?! J'essaie de nous sauver !
@p11: Tu abandonnes ton poste. Tu es un [Jaga](JAGA) qui fuit au premier signe de vrai danger. Je ne t'ai jamais aimé. Je te vois tel que tu es. Un chiot effrayé qui joue au soldat.
@p9: <i>(La voix tremblante de rage)</i> Que puis-je faire ? Dis-moi ! Comment te prouver que je vaux quelque chose ?
@p11: Tu veux aider ? Alors sois aveugle. Cette nuit, quoi que tu voies, quoi que tu entendes... tu ne fais rien. Tu ne dis rien.
@p9: Quelle... quelle perfidie prépares-tu ?
@p11: Ce n'est pas à toi de le savoir.
@p9: <i>(Il l'attrape par les épaules, la secouant)</i> Dis-moi !
@note: &p11 se contente de le fixer, le regard froid et inflexible.
@note: La main de &p9 se lève et la frappe au visage.
@note: &p11 ne bronche pas. Elle touche lentement sa joue, les yeux brûlants de haine.
@p11: Tu regretteras cette nuit. Quand la fin arrivera, &p9_firstname... Je m'assurerai que tu sois le tout premier à saigner.
@note: Elle s'éloigne vers la &kitchen, le laissant tremblant dans l'obscurité quand soudain une explosion retentit en direction du &clubhouse.
@p9: Alamak ! Que diable était-ce ?
@note: &p9 se précipite vers le &clubhouse pour enquêter.`},veranda_4:{personIds:["p2","p4","p7","p12"],links:["veranda_3","balcony_3","dining_5","clubhouse_4"],clue:`@note: &p2 et &p4 sont rejointes par &p12 et &p7 qui accourent du &balcony.
@p2: Maman ! Quel était ce bruit ? Est-ce eux ? Les <c>Nippons</c> sont-ils sur nous ?
@p4: Chut, &p2_firstname. Calme-toi.
@p2: Je savais que la radio mentait ! Père insistait pour dire qu'ils étaient à des lieues d'ici, mais je le savais... Je savais qu'ils viendraient nous chercher dans la nuit !
@p2: J'aurais dû y aller avec M. &p3_firstname. Je me sentirais infiniment plus en sécurité sous son aile. Il saurait quoi faire !
@p4: Sois raisonnable, chérie. S'il s'agissait d'une batterie japonaise, nous serions déjà mortes. C'est... une autre diablerie.
@p12: <i>(Riant nerveusement)</i> Ce n'est guère une façon de rassurer votre fille, &p4_firstname. "Nous n'avons pas encore été passées à la baïonnette" est une bien maigre consolation.
@p4: Je ne fais qu'énoncer des faits. L'hystérie est un luxe que nous ne pouvons nous permettre.
@p2: Je veux aller à la &chapel. J'ai besoin de prier. S'il te plaît, Mère.
@p12: Oh, pour l'amour du ciel... la fille est complètement à cran.
@note: Soudain, les portes du &clubhouse s'ouvrent à la volée. &p1, &p3, &p5 et &p6 trébuchent à l'extérieur, mais au lieu de sang et de bataille, ils hurlent de rire.
@p2: <i>(Essuyant ses larmes avec son mouchoir en dentelle)</i> Est-ce que ce sont... ? Ils rient ?
@note: Elle voit &p3 marcher presque indemne et un sourire soulagé perce à travers sa peur.
@p6: <i>(Agitant un verre de liquide transparent)</i> Vodka ! &p7_firstname ! Vodka !
@p7: <i>(Pousse un petit cri de joie)</i> Lyubimyy ! Espèce de bête folle ! Glorieux imbécile !
@note: &p7 court vers &p6, passant ses bras autour de lui alors qu'il lui offre le verre.
@p6: Pour toi, mon cœur ! À peine sortie du feu !
@note: Le groupe se réunit, les tensions se dissipant pour faire place au soulagement et à l'allégresse alors qu'ils se dirigent vers la &dining.`},kitchen_4:{personIds:["p11"],links:["jungle_5"],clue:`@note: &p11 se tient près de l'évier, pressant un linge humide contre sa joue. Elle siffle de douleur.
@p11: Qu'il soit maudit. Maudit soit ce misérable homme peureux.
@note: Elle jette un coup d'œil par la fenêtre dans l'obscurité grandissante.
@note: Une silhouette se déplace furtivement sur le domaine, du &clubhouse vers la &jungle. C'est &p9_firstname.
@p11: Que fait-il ? Il ne serait pas...
@note: Ses yeux s'écarquillent de réalisation.
@p11: Dieu du ciel. &p9_firstname, tu es un idiot fini !
@note: Elle jette le linge dans la bassine et sort en courant par la porte de derrière.`},jungle_5:{personIds:["p9","p11","p13"],links:["jungle_6"],clue:`@note: &p9 se déplace silencieusement à travers le feuillage dense, son arme dégainée. Il repère un mouvement devant lui, un groupe d'hommes armés attendant dans la clairière.
@p9: <i>(Chuchotant)</i> Des pirates... Je le savais.
@note: Il dégaine sa lame, prêt à frapper.
@note: Soudain, un coup lourd le frappe à l'arrière de la tête. La douleur explose derrière ses yeux et le monde bascule.
@note: &p9 s'effondre sur le sol, sa lame lui échappant des mains.
@note: Il lève les yeux, la vision floue, pour voir un grand homme le surplomber.
@p13: <i>(Ricanant)</i> Travail maladroit, mon vieux. Un homme entraîné comme toi devrait avoir des yeux derrière la tête en permanence.
@note: &p13 lève son pistolet, visant précisément entre les yeux de &p9.
@p11: Retenez votre main !
@note: &p11 sort de l'ombre des arbres.
@p13: Ah, le petit canari. As-tu un faible pour ce chien errant, alors ?
@p11: Il n'est rien. Mais une balle maintenant réveillera tout le domaine. Le coup de feu résonnera des falaises jusqu'à la &veranda.
@p13: <i>(Baisse légèrement l'arme)</i> Une juste observation.
@p11: Attachez-le. Laissez-le ici. Il ne peut pas vous arrêter.
@note: &p13 la dévisage un instant, calculant son prochain geste.
@p13: Très bien. Mais si cela se retourne contre moi, ma fille... c'est toi qui paieras pour ça.
@note: &p13 fait signe à ses hommes. Ils se précipitent, traînant &p9 à moitié conscient dans l'obscurité.`},jungle_6:{personIds:["p9","p11"],links:["jungle_5","railway_7","jungle_7"],clue:`@note: &p11 s'agenouille à côté de &p9, ses mains tremblantes alors qu'elle coupe les cordes liant ses poignets.
@p11: Je pensais... Je pensais pouvoir contrôler ça. Mais ce sont des monstres.
@note: &p11 vérifie le pouls de &p9, soufflant de soulagement lorsqu'elle trouve un faible battement de cœur. Elle l'aide à s'asseoir contre un arbre.
@note: Au loin, une grande silhouette s'extrait de l'entrée du bungalow principal vers le &railway. C'est le capitaine pirate et ses hommes.
@p11: &p13_firstname ne retourne pas dans la jungle. Il va vers la voie ferrée.
@p11: Pourquoi ? Que préparent-ils ?
@note: &p11 s'élance dans la nuit, suivant les hommes.`},jungle_7:{personIds:["p9"],links:["jungle_6","dining_8"],clue:`@note: &p9 s'agite, gémissant alors qu'il se tient la tête.
@p9: ...quoi... ?
@note: Les souvenirs lui reviennent brutalement. Le coup soudain. Les pirates. Et quelqu'un d'autre. Quelqu'un l'a détaché. Quelqu'un qu'il connaît, mais c'est encore trop flou.
@p9: Non. Non, non, non.
@note: Il se hisse sur ses pieds, chancelant, et regarde vers les lumières lointaines de la maison principale.
@p9: Ils vont tous les tuer.
@note: Ignorant la douleur lancinante dans son crâne, il titube et se lance dans une course désespérée vers la maison principale.`},jungle_8:{personIds:["p13"],objects:[{id:"lighter",heldBy:"p13"}],links:["jungle_9","railway_7"],clue:`@note: &p13 et ses hommes remontent depuis les voies ferrées, cherchant un endroit pour établir un camp temporaire.
@note: Ils allument un petit feu pour réchauffer des conserves.
@note: &p13 enlève son gilet, le briquet doré visible dans la poche avant, et s'assoit sur une bûche, aiguisant sa lame en préparation d'un combat.
`},jungle_9:{personIds:["p13","p14"],deaths:["p14"],objects:[{id:"key",heldBy:"p14"}],links:["jungle_8","railway_8","jungle_10"],clue:`@note: &p14 rattrape &p13 à la lisière de la jungle.
@p14: &p13_lastname ! Arrêtez ça ! Cela ne peut pas être le plan prévu par les Rajahs !
@p14: Le domaine ne vaudra absolument plus rien si vous y mettez le feu !
@note: &p13 se retourne lentement et rit.
@p13: Les Rajahs ? Je suis à la solde des Triades, espèce d'imbécile sans cervelle.
@p13: Ils se fichent de la plantation. Ils veulent juste s'emparer de la ferme perlière.
@p14: Les huîtres ? Mais les perles... elles ne valent rien ! Les perles sont gâtées !
@p13: Tu es aussi idiot que les autres. Il n'y a rien de mal avec les perles.
@p13: Bone est trop radin pour acheter de nouvelles cages. Il utilise les vieilles en fer des années 20. Elles rouillent dans l'eau et tachent les perles.
@p13: Cette spirale rouge ? Ce n'est rien d'autre qu'une corrosion ordinaire qui s'infiltre dans la nacre.
@p13: C'est pathétique, vraiment.
@p14: De la rouille ? Ce n'était que de la rouille ?
@note: &p14 recule en réalisant l'erreur qu'il a commise en courant jusqu'ici.
@p14: Vous êtes avec les Triades ?
@note: Il essaie de reculer, mais les autres pirates l'ont encerclé dans la pénombre.
@p14: Je vous en prie... Je...
@note: &p13 fait un simple signe de tête. Les pirates se jettent sur &p14.
@note: &p14 tombe, poignardé à mort par une douzaine de lames.`},jungle_10:{personIds:["p13"],objects:[{id:"lighter",heldBy:"p13"},{id:"key",heldBy:"p13"}],links:["jungle_9","jungle_11"],clue:`@note: &p13 fouille dans les affaires du cadavre.
@p13: Qu'est-ce que nous avons là ?
@note: Il trouve une &key et l'empoche.
@note: &p13 fait un geste à ses hommes pour qu'ils emmènent le corps. Il se ressaisit, remet son gilet. Il s'asperge le visage avec l'eau d'une gourde.
@note: Il regarde vers la plantation, maintenant presque entièrement plongée dans l'obscurité à l'exception de quelques lumières aux fenêtres.
@p13: Il est temps.
@p13: Rassemblez votre équipement. Vérifiez vos armes.
@p13: Cette nuit, la Plantation Goodwill tombe.`},dining_7:{personIds:["p1","p2","p3","p4","p5","p6","p7","p8","p10","p12"],objects:[{id:"opium",heldBy:"p10"},{id:"pearl",heldBy:"p8"},{id:"sample",heldBy:"p8"}],links:["dining_8","library_8","veranda_8","balcony_8","luneroom_8"],clue:`@note: Après une minute de silence inconfortable, &p4 s'approche de &p1 et le gifle violemment.
@p4: Qu'avez-vous fait, vous, idiot, stupide homme.
@note: &p4 s'éloigne en trombe, suivie par &p5.
@note: &p10 se sent de trop et essaie de s'éclipser discrètement vers la &library, &p6 le rejoint.
@p6: Allons boire un verre, &p10_firstname. C'est pour moi.
@note: &p2 se met à pleurer et sort de la pièce en courant.
@p3: &p2_firstname, revenez, tout va bien, c'est fini.
@note: Ils courent vers la &luneroom.
@note: &p12 et &p8 les regardent partir. &p12 se tourne vers &p1 et rit.
@p12: Vous avez vraiment fait fort, n'est-ce pas ?
@p12: J'ai hâte qu'ils reviennent et nous assassinent tous. Je suis sûre que &p8_firstname, &p7_firstname et moi serons les dernières à mourir. Ces hommes nous regardaient comme s'ils voulaient nous dévorer toutes crues.
@p12: Les filles, la chaleur m'accable. Allons sur le balcon pour nous rafraîchir. Je ferai monter des thés et des cafés.
@p1: J'ai bien peur d'avoir besoin de la compagnie de mademoiselle &p8_lastname.
@p1: Si vous voulez que je trouve un moyen de nous sortir de ce pétrin.
@note: &p12 regarde &p1 durement.
@p12: Profitez de votre compagnie, &p1_firstname. Je vous verrai demain matin. Ne venez pas dans la chambre tout à l'heure. Je n'aurai pas envie d'être réveillée.
@p12: Viens, viens &p7_firstname, allons-y.
@note: &p7 et &p12 sortent de la pièce, laissant &p1 et &p8 seuls.`},dining_8:{personIds:["p1","p8","p9"],objects:[{id:"pearl",heldBy:"p8"},{id:"sample",heldBy:"p8"}],links:["masterbedroom_9","jungle_7","kitchen_9","veranda_9"],clue:`@note: &p8 est visiblement secouée, ses mains tremblent alors qu'elle allume une cigarette.
@p8: Qui était cet homme, &p1_firstname ? Dans quoi vous êtes-vous fourré ?
@p1: Une erreur. Juste une erreur.
@note: &p1 se sert un verre.
@p1: Je dois avouer que je me suis mis dans une situation effroyablement délicate. J'ai emprunté assez lourdement sur le dos du domaine. J'ai pris un petit risque pour agrandir les parcs à huîtres. Je me disais que... eh bien, tout le monde est fou pour le caoutchouc et le pétrole depuis que le tabac a perdu de son éclat ici. J'ai pensé que si nous pouvions simplement doubler la récolte, nous pourrions nous tailler la part du lion sur le marché des coquillages et monopoliser le commerce de la nacre avant que les Hollandais ne s'en rendent compte.
@p1: Mais l'entreprise est une perte sèche. Un désastre complet. Les perles sont tout à fait sans espoir. Des trucs cramoisis véreux sans un poil d'orient. Maintenant, je me retrouve à fixer une montagne de chaux morte et une montagne de dettes.
@note: &p8 prend une grande inspiration et éteint sa cigarette.
@p8: Très bien. Nous avons des options. Nous pouvons vendre les terres aux Rajahs. La famille Brooke lorgne sur cette côte depuis des années.
@p1: <i>(Explosant)</i> Absolument pas ! C'est ma plantation ! Je ne bouge d'ici !
@p8: Il se peut que ce ne soit bientôt plus de votre ressort, M. &p1_lastname. Si les Japonais envahissent comme prévu, ils prendront tout par la force de toute façon. Vous devriez partir tant que vous le pouvez. Vendez, prenez l'argent, et partez.
@note: &p1 détourne le regard, sa colère retombant.
@p1: Les ouvriers... les [Bajau](BAJAU)... ils sont inquiets eux aussi, alors qu'ils sont d'un naturel parfaitement calme d'habitude. S'ils ont peur...
@p1: Je... j'ai besoin d'y réfléchir.
@p1: La chambre d'amis a été préparée pour vous. Mais j'ai bien peur que vous ne deviez la partager avec M. &p3_lastname. Nous n'avons qu'une seule maison d'hôtes, bien qu'elle comporte plusieurs chambres.
@note: &p8 rougit d'un cramoisi profond.
@p8: Partager avec un homme ? J'en refuse catégoriquement ! C'est tout à fait inconvenant !
@p8: Mme &p12_lastname m'a fait une proposition tout à l'heure. Je resterai avec elle dans votre chambre.
@p1: <i>(Riant amèrement)</i> Dans la &masterbedroom ? Allez donc profiter de mon lit conjugal avec ma femme alors. Je vous verrai demain matin.
@note: &p9 fait irruption dans la pièce.
@p9: [Tuan Besar](TUAN_BESAR), vous allez bien ? Tout le monde va bien ?
@p1: Mon cher ami, vous prenez l'habitude d'arriver après la bataille.
@p9: J'ai bien peur d'avoir été pris au dépourvu et assommé près de la &jungle.
@p1: J'en suis vraiment navré, c'est terrible. Mais oui, nous allons tous bien. C'était entièrement de ma faute et cela ne se reproduira plus.
@p9: Je ne comprends pas. Nous avons eu des pirates sanguinaires sur notre domaine et vous agissez comme si de rien n'était ?
@p9: Je dois appeler des renforts. Nous devons sécuriser les lieux. Nous devons...
@note: &p1 pose sa main sur l'épaule de &p9.
@p1: Demain. Il n'y a pas d'urgence. Ils vont nous laisser tranquilles. Pour un moment au moins.
@p1: Ce soir nous nous reposons et demain vous ferez ce que vous voudrez.
@note: &p9 accepte le conseil de son maître et s'incline. Il se dirige vers la &kitchen et &p8 vers la chambre alors que &p1 sort pour trouver un peu de compagnie.
`},railway_7:{personIds:["p11","p13"],objects:[{id:"lighter",heldBy:"p13"}],links:["jungle_6","jungle_8","beach_8"],clue:`@note: &p11 émerge des hautes herbes pour voir &p13 debout près de la vieille locomotive à vapeur. Ses hommes aspergent les wagons en bois de kérosène.
@p11: Que faites-vous ? C'est de la folie !
@p11: Pourquoi détruire la locomotive à vapeur ? Vous avez effrayé &p1_lastname, vous obtiendrez ce que vous voulez.
@p13: J'ai une aversion pour les affaires inachevées. Je suis un homme qui croit en une petite assurance.
@p13: Cette [route de fer](IRON_ROAD) est une arme à double tranchant. C'est la voie la plus rapide pour que ton maître prenne la fuite ou pour que la police armée envoie ses salutations à la hâte.
@p13: Je préfère que mes invités restent sur place. Et que mes ennemis marchent.
@note: &p13 jette son cigare allumé sur un wagon imbibé de kérosène.
@note: Dans un rugissement, le chariot s'enflamme, les flammes bondissant vers le ciel nocturne. &p11 regarde sous le choc alors que le feu se reflète dans ses grands yeux.
@p13: Du nerf les gars, on y va.
@note: &p11 crie et se jette sur &p13, saisissant sa lame. L'un de ses hommes lui tire dessus avant qu'elle ne puisse frapper.
@note: &p13 fait signe à ses hommes de la laisser alors qu'il s'agenouille pour reprendre sa lame.
@p13: Pas une mauvaise tentative, petit oiseau. Tu as du cran, on dirait.
@note: &p11 s'effondre, se tenant le côté. Elle commence à ramper vers la crique, laissant une traînée de sang derrière elle.
@note: &p13 fait signe à ses hommes de rejoindre l'obscurité de la &jungle alors qu'il la regarde s'éloigner.`},balcony_8:{personIds:["p7","p12"],links:["masterbedroom_1","study_9","masterbedroom_9"],clue:`@note: L'air sur le &balcony est frais, mais &p12 frissonne pour autre chose que le vent. &p7 se tient près d'elle.
@p7: &p12_firstname... Je dois avouer quelque chose. J'étais dans ta chambre plus tôt.
@p12: Dans mes quartiers ? Pourquoi donc ?
@p7: J'ai vu la lettre. Celle posée sur la coiffeuse. &p12_firstname, comptais-tu vraiment... comptais-tu en finir ?
@note: &p12 détourne le regard, fixant les profondeurs encrées de la mer de Sulu. Elle lâche un rire cassé, saccadé.
@p12: C'était seulement... une envie passagère.
@p7: Une envie passagère ? On n'écrit pas des adieux sur une envie passagère. C'est un appel à l'aide.
@p12: J'imagine que oui. J'ai été anéantie, &p7_firstname. Tout simplement anéantie. Jerry est parti pendant ce qui a semblé être une éternité, et puis... puis j'ai appris qu'ELLE arrivait.
@p12: L'idée d'elle ici, avec lui... c'était comme un chien noir sur mon dos. Je me suis mise dans un état absolument épouvantable.
@p7: Donc tu as écrit ces mots seulement pour lui faire peur ?
@p12: Je voulais qu'il les trouve. Je voulais qu'il me trouve, peut-être au bord du précipice, ou peut-être seulement le mot. Je voulais qu'il s'inquiète. Qu'il panique.
@p12: J'ai pensé... s'il croyait qu'il allait me perdre, vraiment me perdre... il se battrait peut-être pour nous. Il essaierait peut-être de sauver cette imposture creuse que nous appelons un mariage.
@p12: Mais je n'aurais jamais été jusqu'au bout. Je n'en ai pas le cran. Ou peut-être que je ne suis pas si imprudente.
@note: &p12 soupire et pose son front sur l'épaule de &p7.
@p7: Les hommes comme &p1_firstname... ils ne sauvent pas les choses, ma chère. Ils ne font que les acquérir.
@p12: Je sais. Mais une fille a bien le droit de rêver, non ?
@p12: Et il s'avère que je m'étais trompée sur &p8_firstname. Elle n'est pas si mauvaise, en fin de compte.
@p7: L'as-tu vraiment invitée dans ta propre chambre à coucher ?
@p12: J'ai juste pensé que ça l'enragerait vraiment. Un peu de rancune pour pimenter la soirée.
@p7: &p12_firstname... tu es monstrueusement méchante.
@p7: Je dois confesser autre chose.
@p12: Je t'en prie, continue.
@p7: Je dois te demander la permission de me retirer. J'ai certaines... affaires privées qui requièrent mon attention.
@p12: Quel effroyable mystère. File donc, chérie. Je vais rester ici encore un peu. Je soupçonne que &p8_firstname sera encore un moment avant de conclure ses affaires avec Jerry.
@p12: Je la rejoindrai bientôt dans la &masterbedroom avec un dernier verre. Peut-être que je pourrai lui soutirer quelques ragots sur Jerry.
@p12: Je te verrai au petit-déjeuner.
@p7: Dors bien, ma chère.
`},library_8:{personIds:["p6","p10"],objects:[{id:"opium",heldBy:"p10"}],links:["theresaroom_9","veranda_9"],clue:`@note: La bibliothèque est faiblement éclairée, sentant le vieux papier et la fumée froide. &p6 lutte avec la serrure d'une vitrine.
@p6: Au diable. Jerry a toujours gardé les bonnes bouteilles sous clé. Et avec le &clubhouse qui a l'air d'avoir essuyé une bordée complète, on est forcé de se ravitailler par ses propres moyens.
@note: &p6 sort un petit couteau de sa ceinture et l'enfonce dans le mécanisme. Avec un craquement net, le bois cède.
@p6: Sésame, ouvre-toi.
@note: Il attrape une bouteille de scotch et deux verres, leur servant une bonne rasade à tous les deux.
@p10: Vous n'auriez vraiment pas dû faire ça, Tuan &p6_lastname. Tuan &p1_lastname sera positivement fou de rage.
@p6: Jerry a d'autres chats à fouetter ce soir. Sans compter que l'homme m'est redevable, qu'il veuille l'admettre ou non.
@p6: <i>(Levant son verre)</i> À notre survie cette nuit, n'est-ce pas ? Et pour garder nos têtes sur nos épaules.
@p10: <i>(Sirotant nerveusement)</i> Pensez-vous qu'ils reviendront ? Les pirates ?
@p6: &p13_lastname ? C'est un requin. Il a senti l'odeur du sang dans l'eau. Il tournera en rond jusqu'à ce qu'il obtienne ce qu'il veut.
@p6: J'ai déjà vu des hommes de son acabit. En 26. Des hommes qui pensent pouvoir prendre ce qu'ils veulent.
@p10: Vous les avez repoussés alors, n'est-ce pas, monsieur ?
@p6: Nous leur avons offert une belle bagarre. C'est là toute la différence. Jerry... il s'imagine pouvoir négocier un arrangement. On ne peut pas parlementer avec un requin, mon vieux. Il faut lui frapper directement sur le museau.
@note: &p10 avale son verre d'un trait et le repose.
@p10: Je... Je dois vraiment vous tirer ma révérence, M. &p6_lastname.
@p6: Vous décampez si tôt ? La bouteille est à peine entamée.
@p10: Je dois... eh bien, je dois aller voir un homme à propos d'un chien, comme on dit.
@note: &p6 s'arrête, un lent sourire entendu s'étirant sur son visage.
@p6: Un chien, vraiment ? Ou une chienne en chaleur, peut-être ?
@p10: <i>(Rougissant)</i> Je... Je ne suis pas sûr de saisir votre sous-entendu, monsieur.
@p6: Oh, ne jouez pas l'innocent avec moi, mon vieux. J'ai des yeux.
@p6: <i>(Faisant un clin d'œil)</i> Filez, alors. Motus et bouche cousue. Mes lèvres sont scellées plus serrées qu'une palourde.
@p10: Merci, M. &p6_lastname.
@note: &p10 file à l'anglaise de la pièce.
@note: &p6 vide son verre rapidement et le repose.
@p6: Bien. Où est la fête maintenant ? Je ne peux pas être le seul à avoir encore besoin d'un bon verre corsé après les événements de ce soir.
@note: &p6 entend la voix d'un ami venant de la &veranda et va jeter un coup d'œil.`},luneroom_8:{personIds:["p2","p3"],links:["guesthouse_9"],clue:`@note: &p2 se jette sur son lit, enfouissant son visage dans les oreillers. &p3 s'assoit sur le bord, gardant une distance respectueuse.
@p3: &p2_firstname... s'il vous plaît. C'est fini maintenant. Ils sont partis.
@p2: <i>(Sanglotant)</i> Ils reviendront ! Je sais qu'ils reviendront ! Et Père... Père est impuissant pour les arrêter !
@p2: <i>(Elle s'assoit, essuyant ses yeux)</i> Mais vous... vous pouvez les arrêter, n'est-ce pas ?
@p2: Je sais qui vous êtes. Je connais votre secret.
@note: &p3 se fige. Son expression se durcit instantanément.
@p3: Je n'ai pas la moindre idée de ce dont vous parlez.
@p2: Vous n'avez pas besoin de continuer cette mascarade avec moi ! Je le sais depuis que je vous ai vu sur la plage !
@p2: Vous êtes mon frère ! Vous êtes revenu d'Angleterre !
@note: &p3 cligne des yeux, la tension retombant pour laisser place à la confusion.
@p3: Votre... frère ?
@p2: Vous êtes venu m'emmener ! Me ramener à Londres, comme j'en rêve depuis dix ans ! Vous êtes venu me sauver de cette jungle !
@note: &p3 soupire, passant une main dans ses cheveux. Il la regarde avec un mélange de pitié et de tristesse.
@p3: &p2_firstname... écoutez-moi très attentivement. Je ne suis pas votre frère.
@p2: Vous... vous ne l'êtes pas ? Mais...
@p3: Mais vous avez raison sur un point. J'ai un secret. Et vous devez jurer sur votre vie de le garder.
@p2: <i>(Les yeux écarquillés)</i> Je le jure !
@p3: Je suis un agent des services secrets britanniques.
@p2: <i>(Haletante)</i> Un espion ? Comme dans les romans ?
@p3: J'ai été envoyé pour enquêter sur les mouvements militaires japonais en mer de Chine méridionale. Cette brume verte... ce n'est pas naturel. C'est une arme chimique.
@p3: Mon équipage n'a pas été massacré par des pirates, &p2_firstname. Nous avons été interceptés par un destroyer japonais. Ils nous ont pris en flagrant délit avec des preuves de leurs tests.
@p2: Oh mon Dieu...
@p3: J'ai réussi à récupérer un &sample de l'agent. Je l'ai caché dans le cabinet de toilette à la &guesthouse, avec mon revolver de service.
@p3: Je dois les récupérer. Entre les pirates et les <c>Nippons</c>, je dois être armé pour vous protéger et protéger le &sample.
@p2: Vous... vous allez nous sauver ?
@p3: Je ferai de mon mieux. Maintenant, restez ici et verrouillez la porte, essayez de dormir un peu.
@p2: Je ne peux pas dormir maintenant. Je viens avec vous.
@note: &p3 hoche la tête et se dirige vers la porte, &p2 à sa suite.`},study_9:{personIds:["p7"],objects:[{id:"vial",heldBy:"p7"}],links:["masterbedroom_1","study_10","masterbedroom_10"],clue:`@note: La &study est d'un silence de mort. &p7 se faufile dans la pièce, plaçant le flacon de teinture qu'elle a récupéré dans la &masterbedroom et un verre d'eau sur la table d'appoint en acajou.
@p7: <i>(Chuchotant)</i> Espérons qu'il pense que &p11_firstname l'a apporté de ses quartiers.
@note: Elle s'apprête à se détourner lorsqu'elle entend &p1 dans le couloir à l'extérieur.
@note: &p7 sursaute. La &vial qu'elle serrait lui échappe des doigts.
@note: Elle heurte le tapis avec un bruit sourd étouffé et roule sous le lourd fauteuil en cuir.
@p7: <i>(Haletante)</i> Oh non !
@p1: <i>(Depuis le couloir)</i> : Qui est là ? &p7_firstname ?
@note: &p7 se fige, incapable de récupérer la fiole sous le regard de &p1.
@p1: Que diable faites-vous ici ? Vous avez l'air positivement hanté.
@p7: Je... Je vous demande pardon, &p1_firstname. J'étais juste... en route pour la &bonfireroom.
@p1: Pourquoi tremblez-vous ainsi ? Vos mains tremblent comme une feuille.
@p7: C'est le choc de la soirée. Je crois que j'ai besoin de m'allonger.
@p1: Tout à fait. Eh bien, je ne vous retiens pas.
@note: &p7 jette un regard paniqué vers le fauteuil, puis se retourne et se dépêche de sortir de la pièce.
@p1: <i>(Entrant dans la &study)</i> Femme singulière. Positivement étrange.`},study_10:{personIds:["p1"],deaths:["p1"],objects:[{id:"vial",heldBy:"p1"}],links:["masterbedroom_10","study_11","study_9","theresaroom_10"],clue:`@note: &p1 s'assoit dans son fauteuil. Il prend le verre.
@note: Il prend sa [Dose du Tuan](TUAN_DOSE).
@p1: <i>(Fronçant les sourcils)</i> Ça... ça n'a pas un goût normal.
@note: Il commence à tousser. Il porte la main à sa gorge.
@p1: Je me sens terriblement mal...
@note: Il essaie de se lever, mais il perd l'équilibre. Il tombe lourdement sur le tapis.
@note: Cherchant son souffle, il repère la &vial sous le fauteuil.
@note: Il la ramasse, la fixant avec horreur.
@p1: &p7_firstname... qu'avez-vous fait ?
@note: La &vial lui glisse des doigts alors qu'il meurt là, sur le sol de la &study.
@note: Une ombre se profile dans le couloir, regardant avec horreur la scène qui se déroule.
@p7: Bozhe moy ! Jerry ? Jerry, sois chic et réveille-toi ! C'est impossible ! Ce n'était pas le plan !
@note: &p7 s'enfuit, ses sanglots étouffés résonnant dans la maison alors qu'elle court.
@note: Après ce qui semble être une éternité, &p9 entre dans la &study et découvre le corps. Sous le choc, il recule en titubant et court rapidement chercher de l'aide.`},veranda_8:{personIds:["p4","p5"],links:["theresaroom_9","garden_2","beach_9","veranda_9"],clue:`@note: &p4 et &p5 sont assis sur les chaises en osier, un verre à la main.
@p4: &p5_firstname, vous devez leur dire. &p1_firstname et Bone... ils courent après des chimères avec ces bêtises de malédiction...
@p5: Je ne leur dirai rien, ma chère.
@p4: Mais pourquoi ? C'est cruel.
@p5: Pourquoi devrais-je sauver l'empire de &p1_firstname alors que je suis sur le point d'en hériter ?
@p4: L'hériter ? De quoi parlez-vous ?
@p5: Les [Rajahs Brooke](BROOKE_RAJAHS) avancent leurs pions. Avec la faiblesse de la Compagnie et la guerre qui approche, ils étendent leur influence.
@p5: Et moi... j'ai facilité leur arrivée.
@p4: Vous... vous travaillez avec eux ?
@p5: Et les pirates. Le capitaine &p13_lastname est un instrument contondant, certes, mais efficace. Il nettoie l'échiquier pour que nous puissions y disposer nos propres pièces.
@p4: Vous avez aidé les pirates ? Les hommes qui nous ont attaqués ? Comment avez-vous pu ?
@p5: Je l'ai fait pour nous ! Pour vous ! Je vous connais, &p4_firstname. Vous avez des goûts de luxe. Vous n'auriez jamais accordé un regard à un <c>Boche</c> sans le sou. Mais un <c>Boche</c> propriétaire de la plantation Goodwill ? C'est une autre affaire.
@p5: Rejoignez-moi. Devenez ma femme. Nous pouvons faire ça ensemble.
@p4: Espèce d'idiot. D'idiot arrogant.
@p5: &p4_firstname ?
@p4: Croyez-vous que je me soucie de l'argent ? Croyez-vous que je me soucie de cette misérable plantation ?
@p4: Vous avez amené des pirates à notre porte ! Vous avez mis &p2_firstname en danger !
@p5: &p2_firstname sera en sécurité. J'ai des garanties.
@p4: Des garanties de pirates ? De voleurs de terres ?
@p4: Je me fiche éperdument de ce qui arrivera à &p1_firstname. Ou à moi. Ou à vous, d'ailleurs ! Nous pouvons tous rôtir en enfer pour nos péchés.
@p4: Mais si l'on touche à un seul cheveu de la tête de ma fille... je vous tuerai moi-même, &p5_firstname.
@note: Un coup sec sur la vitre de la &veranda les fait sursauter.
@p5: Qu'est-ce que c'était ?
@p4: <i>(Se levant brusquement)</i> Je dois y aller. Restez loin de moi. Et restez loin de ma fille.
@note: &p4 retourne dans la maison à grands pas, laissant &p5 seul avec son verre.
@note: On entend &p1 et &p6 arriver de l'intérieur de la maison. &p5 fait une sortie rapide par la porte extérieure.`},beach_8:{personIds:["p11"],deaths:["p11"],clue:`@note: &p11 sort en titubant du sentier de la jungle sur le sable, se tenant le côté. Une tache sombre se propage rapidement sur son uniforme blanc.
@note: Elle s'effondre près des grottes creusées dans le calcaire, sa respiration saccadée et irrégulière.
@p11: <i>(Faiblement, scrutant les ombres)</i> &p5_firstname ? &p5_firstname !
@note: La plage est vide. Il n'y a pas de &p5.
@p11: Vous aviez dit... vous aviez dit que vous seriez ici.
@p11: <i>(Crachant du sang)</i> "Attends près des rochers," aviez-vous dit. "Nous partirons."
@p11: Vous aviez promis...
@note: Elle essaie de ramper vers l'eau, mais ses forces l'abandonnent.
@note: Sa main retombe, inerte, sur le sable alors que la marée vient doucement lui lécher les pieds et que la vie la quitte.`},beach_9:{personIds:["p5"],links:["beach_8","beach_10"],clue:`@note: &p5 sprinte sur le sable, hors d'haleine.
@note: Il s'arrête brusquement lorsqu'il voit la silhouette immobile de &p11 effondrée sur la plage.
@p5: &p11_firstname ! Non, non, non !
@note: Il se précipite à ses côtés et cherche un pouls, mais n'en trouve aucun.
@note: De la [suie noire](BLACK_SMOKE) commence à pleuvoir du ciel, des cendres tachant son visage et ses vêtements alors qu'il est agenouillé près d'elle, incrédule face à ce qui se passe.
@p5: Verdammt ! Ça ne devait pas se passer comme ça !
@note: Il regarde frénétiquement autour de lui, scrutant l'horizon sombre.
@p5: Où est la vedette ? Où est la fusée de détresse ?
@note: Un rugissement provenant de derrière lui le fait se retourner.
@note: Haut sur la crête, le feu dévore les wagons du chemin de fer. La lueur orange illumine la scène de façon sinistre.
@p5: Ils nous bloquent... Le bateau ne comptait jamais venir et maintenant la locomotive est perdue.
@p5: <i>(Il regarde &p11, puis vers la mer)</i> Les Rajahs ne nous exfiltrent pas.
@p5: Nous ne sommes pas des partenaires. Nous sommes des témoins gênants. J'ai été pris pour un idiot.
@note: &p5 s'effondre sur le sable, la tête dans les mains.`},beach_10:{personIds:["p5"],links:["beach_9","jungle_11"],clue:`@note: &p5, toujours à genoux, aperçoit une lumière sur l'océan.
@note: Il se lève d'un bond, agitant frénétiquement les bras.
@p5: Par ici ! Par ici !
@note: La lumière devient plus vive. Puis une autre apparaît. Et une autre. Toute une ligne.
@note: &p5 arrête de faire des signes. La silhouette d'une énorme coque de fer surgit de la brume.
@p5: Ce sont les <c>Nippons</c>...
@note: Il entend le barattement des moteurs et le fracas des péniches de débarquement frappant l'eau.
@p5: Une invasion. Pas une exfiltration. Une invasion.
@note: Il baisse les yeux vers &p11.
@note: Avec un grognement d'effort, il prend le corps sans vie de &p11 dans ses bras.
@note: &p5 tourne le dos à la flotte en approche et court vers le couvert de la jungle.`},veranda_9:{personIds:["p1","p6"],objects:[{id:"croquetbat",heldBy:"p6"}],links:["study_10","railway_10"],clue:`@note: &p1 et &p6 sont dans la &veranda, riant sous cape alors qu'ils se servent un autre verre.
@p1: Vous avez vu la tête de ce jeune blanc-bec ? Complètement terrorisé par une bande de diables de Sulu !
@p6: On ne peut pas lui en vouloir trop, Jerry. Il se croit dur à cuire, mais il n'a pas le tempérament qu'il faut pour ce coin du monde.
@p1: Ha ! Mous comme du beurre, tous autant qu'ils sont. Ils n'ont pas le fer dans le sang que nous avions de notre temps, hein, Bone ?
@p6: En effet. Mon esprit s'est égaré ce soir vers '15 et [l'affaire de Rundum](RUNDUM_REBELLION).
@p1: Traverser ce maudit pays Murut pendant des semaines à pied. Les bottes pourries d'humidité et la crainte permanente d'une fléchette empoisonnée dans la nuque.
@p6: Le silence était le pire. On n'entendait jamais la sarbacane. Juste le son des fléchettes qui trouvaient les hommes qui marchaient à côté de vous.
@p1: Et ces forts souterrains ! Nous pourchassions des fantômes dans la boue. En infériorité dans la jungle profonde face à un ennemi qu'on ne voyait même pas.
@p1: Mais nous avons tenu la ligne, n'est-ce pas ? Nous tenons toujours la ligne.
@p6: Nous l'avons tenu, Jerry. Nous l'avons tenu.
@p1: <i>(Soupirant)</i> Je me sens plutôt las, mon vieux. Je crois que l'agitation m'a épuisé.
@p1: Je ne sais pas si j'ai encore ce qu'il faut. Je ne suis plus l'homme que j'étais, Bone. Je n'ai plus le courage d'une nouvelle bagarre.
@p1: J'avais vraiment cru que le tabac était un commerce éternel. Je n'avais pas prévu que le monde s'entiche de ces maudites cigarettes et rende notre feuille à cigare complètement obsolète.
@p1: Et nous avions toujours les coquilles, n'est-ce pas ? La nacre devait être le socle, et puis... elle a tout simplement disparu sous nos pieds.
@note: &p1 regarde dans la nuit. De la fine suie noire, la cendre des champs de pétrole incendiés au sud, commence à pleuvoir du ciel.
@p1: Et puis il y a la guerre. Je suis fatigué, mon ami. Si fatigué.
@p1: Je vais me retirer dans la &study. Essayer de m'éclaircir les idées.
@p6: Je finirai mon verre ici. Je veillerai à l'affût de tout autre... visiteur importun.
@p1: Brave homme.
@note: &p1 tape sur l'épaule de &p6 et rentre vers la &study.
@note: &p6 s'attarde encore un peu, regardant le ciel tandis que la suie noire continue de tomber.
@note: Il tourne ensuite la tête vers l'arrière de la plantation et voit une étrange lueur orange au loin.
@p6: Mais qu'est-ce que diable... ?
@note: &p6 attrape un &croquetbat derrière le bar et se dirige vers la source de cette lueur.
`},railway_10:{personIds:["p6"],objects:[{id:"croquetbat",heldBy:"p6"}],links:["beach_9","jungle_11"],clue:`@note: &p6 arrive à l'arrêt de chemin de fer, il s'arrête net, la bouche bée.
@p6: Bon sang...
@note: Les wagons en bois sont engloutis par les flammes, la chaleur est intense même d'où il se tient. Les voies sont tordues et noircies.
@p6: L'œuvre de &p13_lastname, sans aucun doute. Il a incendié la seule issue.
@note: &p6 court vers le château d'eau, attrape un seau. Il jette de l'eau sur le wagon le plus proche, mais le feu rugit de plus belle avec une fureur redoublée.
@p6: C'est inutile. C'est trop tard.
@note: Il jette le seau par terre de frustration.
@p6: Je dois aller prévenir Jerry et les autres.
@note: Il se retourne pour partir mais aperçoit un mouvement près de la &jungle. Une silhouette émerge de la lisière des arbres, depuis la direction de la &beach, portant quelque chose de lourd dans ses bras.
@p6: Qui va là ?
@note: Il plisse les yeux à travers la fumée. C'est &p5, titubant sous le poids d'un corps inerte.
@p6: &p5_firstname ?
@note: &p6 se précipite vers lui.`},jungle_11:{personIds:["p5","p6","p13"],objects:[{id:"lighter",heldBy:"p13"},{id:"croquetbat",heldBy:"p6"},{id:"key",heldBy:"p13"}],links:["railway_10","garden_12","beach_9"],clue:`@note: &p6 fixe le corps dans les bras de &p5. Il recule d'horreur.
@p6: Est-ce que c'est... est-ce que c'est &p11 ?
@p5: <i>(La voix tremblante)</i> Elle est partie, Bone.
@p6: Que s'est-il passé ? Comment ?
@p5: On n'a pas le temps, Bone ! Les Japonais débarquent sur la plage !
@p6: Les <c>Nippons</c> ? Ici ?
@p5: Une force d'invasion entière. Des destroyers, des péniches de débarquement... des dizaines. Nous devons prévenir les autres ! Nous devons amener tout le monde à l'intérieur des terres !
@p6: Mais &p11... nous ne pouvons pas la laisser là.
@note: Une voix grave résonne depuis l'ombre des arbres.
@p13: Il a raison, vieil homme. Il n'y a pas de temps pour le deuil.
@note: &p13 s'avance dans la lumière, flanqué de deux de ses hommes. &p6 se crispe, levant le &croquetbat.
@p13: Doucement. Je ne suis pas votre ennemi. Plus maintenant.
@p5: Vous... vous avez incendié la locomotive ! Vous nous avez piégés ici !
@p13: J'ai coupé la voie de fuite d'un lâche. Je ne savais pas que le loup était déjà à la porte.
@p13: <i>(Il regarde le corps de &p11, une lueur de regret dans les yeux)</i> Je suis désolé pour la fille. Vraiment. Elle s'est battue comme une tigresse. Elle méritait une mort de guerrier, pas... ça.
@p13: C'était de la légitime défense. Mes hommes... ils sont nerveux.
@p6: De la légitime défense ? C'était une servante !
@p13: Elle avait un couteau sous ma gorge avant même que je sache qu'elle était là. Elle avait du cran.
@p13: Mais se disputer ne la ramènera pas.
@p13: Mes hommes et moi... nous pouvons vous aider à vous battre. Ou du moins, vous aider à vous échapper.
@p5: Pourquoi devrions-nous vous faire confiance ?
@p13: Parce que l'ennemi de mon ennemi est mon ami. Et parce que si les Japonais prennent cette île, il n'y aura plus de place pour les hommes libres.
@note: &p6 regarde &p13 puis &p5, puis de nouveau la locomotive en feu.
@p6: Très bien. Mais si vous nous trahissez, &p13_lastname...
@p13: Gardez vos menaces pour les <c>Nippons</c>, l'Anglais. Vous en aurez besoin.
@note: Ils se dirigent tous vers la maison en traversant la pelouse et en passant devant le club-house.`},masterbedroom_9:{personIds:["p12","p8"],objects:[{id:"pearl",heldBy:"p8"},{id:"sample",heldBy:"p8"}],links:["masterbedroom_10","library_3"],clue:`@note: &p8 sert une généreuse dose de gin dans deux verres. &p12 en saisit un et s'assoit sur le lit.
@p12: À nos choix.
@note: Elles trinquent et boivent une longue gorgée.
@p12: Vous savez, je vous envie positivement, &p8_firstname. Une femme avocate. Indépendante. Une femme avec une carrière à part entière.
@p8: Oh, ne gaspillez pas votre envie pour moi, Mme &p12_lastname. Le barreau est un club de garçons. Ils regardent une femme dans les cabinets comme si elle était un phoque de cirque. "Remarquable pour un membre du beau sexe" disent-ils, avec ce ton d'une condescendance écœurante.
@p8: Et la pression... Mère ne cesse de me demander quand je compte m'installer. "Tu ne pourras pas plaider pour toujours, &p8_firstname. Pense à tes ovaires."
@p12: <i>(Gloussant)</i> Ovaires !
@p8: Comme si les fonctions d'une femme avaient une date de péremption estampillée dessus.
@p12: Au moins, vous avez une vie à vous. J'ai... ça. Attendre Jerry. Craindre &p1_firstname.
@p12: Je rêvais de brûler les planches, vous savez. Sur une scène à Londres.
@p8: Vous en avez le visage. Et le sens de la mise en scène, je vous l'accorde.
@p12: <i>(Se levant avec difficulté)</i> N'est-ce pas ?
@p12: Jouons à nous déguiser ! Devez-vous toujours porter ces tenues si ternes et guindées ? Laissez-moi vous voir dans quelque chose... de divin.
@p8: Oh, je ne pourrais pas... enfin, peut-être juste pour essayer.
@note: &p12 sort une robe en soie scintillante de l'armoire.
@p12: Mettez ça ! C'est parisien. Jerry me l'a achetée pour que je la porte au bal du Gouverneur, mais je ne l'ai jamais fait.
@note: &p8 enfile gauchement la robe. Elle lui va étonnamment bien.
@p12: Oh mon Dieu... vous êtes ravissante, &p8_firstname ! Une vraie sirène du cinéma !
@p8: <i>(S'admirant dans le miroir)</i> C'est plutôt... fringant, n'est-ce pas ?
@note: Elle tourne sur elle-même en gloussant. Ce faisant, elle fait tomber son chemisier d'une chaise voisine et la &pearl ainsi que le &sample volent de sa poche et s'éparpillent sur le sol.
@note: &p12 s'arrête instantanément de rire, fixant les perles.
@p12: Ce... ce sont les perles de Jerry. Celles qui sont maudites.
@p12: Pourquoi les avez-vous ? Êtes-vous en train de nous voler ? Ou est-ce pire ?
@p12: J'ai entendu des histoires sur les triades de [Sandakan](SANDAKAN). Elles paient bien pour avoir des taupes. C'est ça ? Ce numéro "d'avocate de la haute société" n'est qu'une couverture ?
@p8: Ne soyez pas absurde ! Je les ai trouvées dans la &library. Elles étaient juste par terre. Je les ai ramassées pour les garder en sécurité, pour les rendre à M. &p1_lastname !
@p8: Il semble que la confiance soit une denrée rare par ici.
@note: L'air de la pièce devient lourd de tension.
@note: Puis &p7 fait irruption par la porte, des larmes inondant son visage.
@p12: Vita ? Que se passe-t-il ?`},masterbedroom_10:{personIds:["p7","p12","p8"],links:["masterbedroom_9","study_10","study_9","garden_11","chapel_0"],clue:`@note: &p7 tombe à genoux au pied du lit, sanglotant de façon incontrôlable.
@p12: Vita ? Parlez-moi ! Que s'est-il passé ?
@p7: Ça ne devait pas finir comme ça ! Il ne devait pas mourir !
@p12: Mourir ? Qui ? Qui est mort ?
@p7: Jerry... &p1_firstname...
@p12: <i>(Se figeant)</i> Jerry ? Non. Non, vous êtes ivre, Vita. Il est dans le bureau.
@p7: Je l'ai tué ! Je ne le voulais pas, je le jure !
@p8: <i>(Dessaoulant instantanément, la voix tranchante)</i> Expliquez-vous, &p7_firstname. Qu'avez-vous fait ?
@p7: La malédiction... les perles... Je voulais juste sauver la plantation.
@p7: Je suis allée voir le Bomoh. C'est lui que j'allais voir à la &chapel. &p14, il m'a promis un remède. Une potion pour purifier les huîtres.
@p7: Mais il m'a trompée ! Ce n'était pas un remède... c'était un [Tuju](TUJU) !
@p7: Je le lui ai donné... dans ses médicaments... pensant que ça enlèverait le sort qu'on lui avait jeté... et puis il est tombé... et il ne s'est pas réveillé.
@p12: <i>(Le regardant fixement)</i> Vous... vous l'avez empoisonné ?
@p7: C'était un accident ! J'aime Jerry ! Vous savez que je ne lui ferais pas de mal !
@p8: Un Tuju... ? Il vous a donné un Tuju pour tuer M. &p1_lastname ?
@p7: Il a dit que ça chasserait les mauvais esprits ! Mais c'était du poison !
@p12: <i>(Un cri montant dans sa gorge)</i> Non ! NON !
@note: &p12 se précipite hors du lit, trébuchant sur sa robe, et s'enfuit de la pièce vers le &garden.
@p8: &p12_firstname, attendez !
@note: &p8 attrape &p7 par le bras, la hissant sur ses pieds.
@p8: Nous devons y aller. Maintenant. Avant que vous ne disiez un mot de plus à qui que ce soit.
@note: &p8 ramasse le &sample et traîne &p7 qui gémit hors de la pièce, poursuivant &p12.`},garden_11:{personIds:["p12","p8","p7"],objects:[{id:"sample",heldBy:"p8"}],links:["masterbedroom_10","garden_12","study_12"],clue:`@note: &p12 traverse la pelouse de croquet en titubant, sanglotant de façon hystérique. Elle trébuche sur un arceau de laiton et s'étale sur l'herbe.
@note: Elle pousse un gémissement perçant, un son d'un pur chagrin.
@note: &p8 et &p7 la rattrapent.
@note: &p7 attire &p12 dans une étreinte forte.
@p7: Chut, chut, mon amour. Je suis là. Je suis là.
@p12: Il est parti ! C'est ce que vous avez fait ! Votre action vile et misérable !
@note: Pendant que &p7 la serre fort, &p12 commence à marteler la poitrine de Vitalina de ses poings, la frappant encore et encore dans une fureur aveugle et hystérique.
@note: De la [cendre noire](BLACK_SMOKE) commence à pleuvoir plus fort, recouvrant leurs cheveux et leur peau de suie.
@note: &p8 lève les yeux, protégeant son regard. Au loin, elle voit les lumières des péniches d'invasion atterrir sur la plage.
@p8: Dieu du ciel...
@note: &p8 passe la main sous sa robe et en sort un revolver.
@note: &p12 s'arrête de pleurer, fixant l'arme.
@p12: Vous... Qui diable êtes-vous, vraiment ?
@p8: Vous aviez raison d'être méfiante, &p12_firstname. Je ne suis pas celle que je dis être.
@p8: Mais cela n'a pas d'importance maintenant. Ce qui compte, c'est que nous sommes en grand danger.
@p8: Les Japonais ont débarqué. Et nous devons nous dépêcher.
@note: &p8 aide les femmes à se lever.
@p8: Nous devons rassembler les autres. À la &study. En double vitesse !
@note: Alors qu'elles entrent dans la maison, le groupe de &p13 est visible au loin, arrivant avec des torches dans l'obscurité.`},kitchen_9:{personIds:["p9"],links:["study_10","beach_9"],clue:`@note: &p9 entre dans la &kitchen, essuyant la sueur de son front.
@note: Il s'arrête, regardant la pièce vide.
@p9: &p11_firstname ?
@note: Le poêle est froid et il n'y a aucun signe de &p11 nulle part.
@p9: C'est étrange. Elle n'est jamais absente de son poste.
@note: Il vérifie la porte de derrière. Déverrouillée.
@p9: Où est passée cette fille ?
@note: Il fait les cent pas pendant un moment, un sentiment de malaise grandissant dans ses tripes.
@p9: Quelque chose ne va pas. Je le sens dans mes os.
@p9: Je dois informer Tuan &p1_lastname immédiatement.
@note: Il se hâte de sortir de la &kitchen, se dirigeant vers la &study.`},guesthouse_9:{personIds:["p3","p2"],links:["workerquarters_10","theresaroom_9","guesthouse_4"],clue:`@note: &p3 émerge du petit lavoir, le visage pâle et sombre. &p2 l'attend sur le chemin.
@p3: Elle n'y est plus.
@p2: Qu'est-ce qui n'y est plus ?
@p3: Mon... kit. La pochette. C'était caché juste ici sous la lame de plancher desserrée. Quelqu'un l'a pris.
@p2: Prendre des choses qui ne leur appartiennent pas semble être à l'ordre de la nuit.
@p3: Vous ne comprenez pas. J'ai besoin d'une arme. Le revolver était dedans. Si ça tourne mal... Et cet échantillon est dangereux. Si quiconque l'a ne sait pas ce que c'est, qui sait ce qui pourrait arriver.
@p2: Suivez-moi. Les &workerquarters. Nous y gardons des fusils pour les sangliers.
@note: Ils se dépêchent le long du chemin. Alors qu'ils passent devant la &theresaroom, ils entendent des cris venant de l'intérieur.
@p3: Bon Dieu... qu'est-ce que c'est ? Quelqu'un est blessé ?
@p2: Continuez de marcher, Lucas.
@p3: Mais on dirait...
@p2: J'ai dit continuez de marcher. C'est juste Mère. Il vaut mieux ne pas demander.`},workerquarters_10:{personIds:["p3","p2"],links:["guesthouse_9","railway_10","beach_10","jungle_11"],clue:`@note: &p3 et &p2 pénètrent dans les &workerquarters.
@note: Par la fenêtre qui donne sur la plantation — les quartiers étant perchés sur une colline — ils ont une vue terrifiante.
@note: Au sud, la [route de fer](IRON_ROAD) est un enfer, les flammes léchant le ciel nocturne. À l'est, dans la crique, des soldats japonais débarquent de chalands d'assaut sur le sable, et partout autour d'eux le ciel est [noir de suie](BLACK_SMOKE).
@p3: <i>(Chargeant un fusil avec une aisance consommée)</i> C'est pire que ce que je craignais. Ils nous encerclent.
@p2: <i>(Les yeux fixés sur la plage)</i> Ils sont si nombreux...
@note: &p3 attrape des &binoculars et observe attentivement les alentours.
@p3: Bien. Je vois 6 chalands accoster sur la plage avec une douzaine d'hommes dans chacun.
@p3: Et l'incendie m'offre une bonne vue de ce qui se passe du côté de la &jungle malgré l'obscurité.
@p3: Il semble que &p6_firstname et &p5_firstname soient là-bas avec notre ami le capitaine &p13_lastname. Ils regagnent la maison.`},workerquarters_11:{personIds:["p3","p2"],objects:[{id:"binoculars",heldBy:"p3"}],links:["workerquarters_10","study_12"],clue:`@note: &p3 fourre des poignées de munitions dans un sac en toile. Il jette trois fusils en bandoulière sur son épaule et en tend deux autres à &p2.
@p3: Prenez ça. Savez-vous tirer ?
@p2: Je... je crois. Mon père m'a appris.
@p3: Bien. Visez le centre de masse. N'hésitez pas.
@p3: Nous devons trouver votre père. Il peut nous aider à déterminer la meilleure façon de faire sortir tout le monde d'ici.
@p2: Il sera dans le &study.
@p3: Restez près de moi, &p2_firstname. Quoi qu'il arrive, ne quittez pas mon côté.
@note: Ils jaillissent des quartiers et filent en courant vers la maison principale.`},theresaroom_9:{personIds:["p4","p10"],objects:[{id:"opium",heldBy:"p10"}],links:["theresaroom_10","veranda_8"],clue:`@note: &p4 entraîne &p10 dans la chambre et l'embrasse avec une faim dévorante.
@p4: Enfin. Je pensais que cette soirée ne finirait jamais.
@p10: &p4_firstname... es-tu certaine que personne ne nous a vus ? Le Tuan &p5_firstname...
@p4: Oublie-le. C'est un homme mauvais, c'est ce que j'ai appris ce soir. Je ne veux pas parler de lui ni de ses manigances.
@note: Elle le pousse sur le lit.
@p10: Tu m'as manqué. Dieu m'en est témoin.
@note: Leur étreinte est désespérée, animale. &p4 pousse un cri.
@note: Les ébats passionnés se prolongent un long moment, leurs corps trempés de sueur dans la chaleur oppressante.`},theresaroom_10:{personIds:["p4","p10","p9"],objects:[{id:"opium",heldBy:"p10"}],links:["theresaroom_9","study_11","study_10","theresaroom_11"],clue:`un coup frappé à grand bruit à la porte les interrompt.
@p9: (De l'autre côté) &p10_firstname ? Mem ?
@note: &p4 se fige. &p10 se dépêche de se couvrir.
@p4: Va-t'en, &p9_firstname !
@note: &p9 ignore ses supplications et entre.
@p9: Je vous demande pardon, Madame. Mais je sais que &p10_firstname est avec vous.
@p9: J'ai besoin de son aide. Immédiatement. Cela concerne le Tuan.
@p10: (Chuchotant) Le Tuan &p1_lastname ?
@p4: (Sifflant) Ne l'écoute pas, &p10_firstname.
@p9: C'est une question de vie ou de mort.
@note: &p10 regarde &p4, puis la porte. Il commence à s'habiller, le visage blême.
@p10: Je dois y aller, &p4_firstname.
@p4: Tu t'en vas ? Pour lui ?
@p10: Si c'est une question de vie ou de mort... Je connais &p9_firstname, il ne dirait pas ça à la légère. Laisse-moi voir de quoi il s'agit.
@p4: <i>(Se détournant)</i> Va donc. Cours vers ton Tuan.`},theresaroom_11:{personIds:["p4"],links:["theresaroom_10","veranda_12"],clue:`@note: &p4 fait les cent pas dans la chambre, furieuse. Elle donne un coup de pied dans le tas de vêtements par terre.
@p4: Des salauds. Jusqu'au dernier.
@note: La chambre est d'une chaleur épouvantable. Elle s'essuie le front.
@p4: Je n'arrive pas à respirer ici. C'est comme un tombeau.
@note: Elle enfile à la hâte une robe légère, abandonnant ses sous-vêtements dans la touffeur.
@p4: J'ai besoin d'air... et d'un gin pour calmer mes nerfs.
@note: Elle quitte sa chambre et se dirige vers la &veranda.`},study_12:{personIds:["p3","p2","p9","p12","p7","p8"],objects:[{id:"sample",heldBy:"p8"},{id:"binoculars",heldBy:"p3"}],links:["study_11","garden_11","workerquarters_11","veranda_13","clubhouse_13","library_13","beach_10","guesthouse_4","jungle_11"],clue:`@note: &p9 est déjà dans le bureau, faisant les cent pas nerveusement.
@note: &p2 et &p3 entrent dans la pièce.
@note: &p2 s'arrête net, les yeux fixés sur le corps allongé sur le sol.
@p2: Papa ?
@note: Elle se précipite vers &p1. Elle le secoue, mais il est froid.
@p2: Papa ! Réveille-toi ! Tu me fais peur !
@note: &p2 hurle. Elle tente de le soulever, mais il est lourd comme du plomb.
@p3: <i>(Cherchant le pouls, puis secouant la tête)</i> Il est parti, &p2_firstname. Je suis désolé.
@note: &p2 s'effondre dans les bras de &p3, sanglotant sans retenue. Il la tient serrée, le regard dur posé sur l'autre homme dans la pièce.
@p9: C'est... c'est une mésaventure. Une surdose. La pipe l'a finalement emporté. Il a pris trop de [Chandu](CHANDU).
@p3: Une surdose ? Regardez ses yeux ! L'opium ne provoque pas ça, c'est du poison.
@p3: <i>(Levant son fusil, le mettant en joue)</i> C'est vous qui avez fait ça. Vous étiez la seule âme qui vive dans cette pièce !
@p9: Non ! Je le jure sur ma vie ! Je l'ai trouvé dans cet état !
@note: &p12, &p7 et &p8 se précipitent dans la pièce.
@p7: Baissez votre arme ! Ne tirez pas ! Ce n'est pas lui le coupable !
@p7: C'était moi.
@note: Le silence tombe sur la pièce. &p2 relève les yeux de la poitrine de &p3, les siens rouges et égarés.
@p2: Vous ?
@note: &p12 est sous le choc. Elle fixe le corps sans vie de &p1, des larmes coulant sur son visage couvert de suie, sa robe déchirée et souillée de boue après sa chute dehors.
@p12: Mon amour...
@p7: C'était un accident ! Je lui ai donné le Tuju... je croyais que c'était un remède !
@note: L'expression de &p2 passe du chagrin à une colère froide. En un éclair, elle arrache le fusil des mains de &p3.
@p3: &p2_firstname, non !
@note: &p2 tire. La détonation retentit très fort dans la petite pièce.
@note: &p7 pousse un cri strident, agrippant sa main. Du sang goûte sur le tapis.
@p8: Ça suffit !
@note: &p8 s'avance à grands pas, gifle &p2 violemment avant de lui arracher l'arme des mains.
@p8: Asseyez-vous et taisez-vous, jeune fille ! Nous sommes des sujets de la Couronne, pas des sauvages !
@p8: &p9_firstname, soignez la main de cette femme avant qu'elle ne se vide de son sang sur le parquet.
@note: &p9 se précipite vers &p7, arrachant une bande de lin de sa chemise pour panser la blessure.
@p8: Maintenant, écoutez-moi tous. &p1_firstname est parti et aucune crise d'hystérie ne le ramènera.
@p8: Mais les Japonais sont sur la plage et arrivent vite. Si nous restons ici à nous quereller, nous le rejoignons.
@p3: <i>(Abaissant son fusil, regardant &p8 avec méfiance)</i> Vous donnez des ordres comme un sergent-major, Mademoiselle &p8_lastname. Qui diable êtes-vous ?
@p8: MI5. Je suivais une opération de la Triade à travers le Détroit. Le fiasco des perles de &p1_firstname attirait leur attention.
@p8: Et &p14 qui a fourni le Tuju, sans doute l'un de leurs agents.
@note: &p3 tend la main à &p8 pour une poignée de main.
@p3: [SIS](SIS). Surveillance de la [Cinquième Colonne](FIFTH_COLUMN) et collecte de renseignements humains sur les puissances étrangères, envoyé ici expressément pour surveiller les activités japonaises.
@p8: En ce cas, « Monsieur &p3_lastname ». Il semble que nous soyons du même côté.
@p8: Nous devons mettre ces gens en sécurité.
@p3: Convenu, mais ce n'est pas si simple. Les <c>Nips</c> arrivent par la mer mais j'ai repéré les pirates qui rebroussent chemin par les mangroves. Ils ont mis le feu à la &railway.
@p3: &p6_firstname et &p5_firstname sont avec eux.
@p7: Mon Lyubimyy ? Oh, ciel miséricordieux... dites-moi qu'il est sain et sauf.
@p3: Il m'avait l'air en bonne forme d'après ce que j'ai pu voir. Cet homme sait se défendre, &p7_firstname.
@p9: &p11 les a aidés. Je m'en rends compte maintenant. J'étais dans un brouillard quand je l'ai vue traiter avec leur capitaine, mais tout s'assemble désormais.
@p3: Je propose que nous tentions de rejoindre le &boathouse et d'atteindre mon embarcation. C'est un spectacle sinistre mais c'est sans doute notre seule issue à ce stade.
@p12: Nous pouvons atteindre le &boathouse sans être vus en empruntant le &companionway jusqu'à la &chapel. Il commence derrière les lambris du &clubhouse mais il nous faudra la clé cachée dans la &library.
@p3: &p9_firstname, &p8_firstname, escortez les dames jusqu'au &clubhouse. &p12, prenez un fusil et venez avec moi. Vous connaissez la cachette.
@p2: Je me joins au groupe. Vous avez juré de me protéger.
@p3: Soit. Mais plus de tirs sur nos amis, vous m'entendez ?
@p2: Je... je suis terriblement désolée, Vita. Je n'arrive tout simplement pas à croire que Papa est parti.
@note: Des coups de feu se font entendre depuis l'extérieur. Tout le monde s'approche de la fenêtre. Certains des groupes dehors ont des torches, mais il est difficile de voir quoi que ce soit dans l'obscurité avec la suie qui continue de tomber — c'est le chaos total.
@p2: Et mère ? Où est mère ?
@p9: On peut espérer que &p10_firstname veille sur elle. Nous ne pouvons que prier pour qu'ils voient où le vent souffle et trouvent un moyen de s'en sortir.
@p2: Non, nous ne pouvons pas nous contenter d'espérer. C'est ma mère. Je ne vais pas la perdre elle aussi.
@p9: Très bien, petite Mem. Changement de plan. Je vais partir chercher votre mère et &p10_firstname. Les autres, continuez comme prévu.
@p2: C'est décidé alors. Je viens avec vous, &p9_firstname.
@note: &p2 se tourne vers &p3.
@p2: Pardonnez-moi &p3_firstname, nous devons nous séparer maintenant. C'est ma mère, on ne peut pas faire autrement.
@note: &p3 lui serre la main.
@p3: On se retrouve de l'autre côté, mademoiselle.
@note: &p8 sort le &sample de sa poche.
@p8: Une dernière chose. Monsieur le SIS, je présume que ceci est à vous.
@p3: En effet. C'est un échantillon de la brume verte. Un agent chimique que les Japonais ont mis au point dans la mer de Sulu.
@p3: Beaucoup de bons hommes sont morts pour obtenir cet échantillon. Je suis soulagé qu'il ne soit pas perdu... encore.
@note: &p8 remet le &sample à &p3.
@trigger:switch_owner:sample:p3
@note: &p3 distribue les fusils et les munitions et ils se dispersent tous.
@p8: Bonne chance à tous.
`},garden_12:{personIds:["p13","p5","p6"],objects:[{id:"lighter",heldBy:"p13"},{id:"croquetbat",heldBy:"p6"},{id:"key",heldBy:"p13"}],links:["jungle_11","study_13","veranda_13","veranda_12"],clue:`@note: &p13, &p5 et &p6 débouchent sur la pelouse de croquet avec l'équipage de pirates du capitaine &p13.
@note: Ils sont armés de pistolets, de lames et de torches enflammées. &p6 tient toujours le &croquetbat.
@p6: Attendez. Je crois voir Vita qui entre dans la maison là-bas.
@p5: Silence !
@note: Une rafale de coups de feu éclate dans l'obscurité près du sentier de la plage.
@note: Deux membres de l'équipage pirate tombent, fauchés instantanément.
@p5: <i>(Agrippant son épaule alors qu'une balle l'effleure)</i> Verdammt ! Ils sont là !
@p13: <i>(Tirant à l'aveugle dans l'obscurité)</i> Embuscade ! En arrière !
@p6: Il nous faut une diversion ! Les <c>Japs</c> vont nous submerger si nous essayons de tenir ici.
@p6: L'alambic du !&clubhouse! C'est une poudrière prête à exploser !
@p5: Tu veux faire sauter l'alcool ?
@p6: Ça créera assez de chaos pour couvrir notre retraite ! Nous devons rejoindre la maison principale et rassembler les autres.
@p13: Faites-le !
@note: &p6 et les hommes de &p13_lastname lancent leurs torches sur le toit de chaume du &clubhouse.
@note: Le toit sec s'embrase instantanément.
@p6: Courez ! Vers le &study !
@note: Ils filent vers la maison principale tandis que les flammes commencent à dévorer le &clubhouse.
@note: &p5 aperçoit &p4 sur la &veranda et se sépare du reste du groupe.`},clubhouse_13:{personIds:["p8","p7"],deaths:["p7"],links:["garden_12","chapel_14"],clue:`@note: &p8 et &p7 foncent vers le &clubhouse, courbées pour esquiver les balles perdues qui sifflent dans l'air.
@note: Elles atteignent le bord de la clairière au moment précis où le toit est entièrement consumé par les flammes.
@p7: Le passage secret ! Il est derrière les lambris ! Nous devons...
@note: Une explosion monumentale dévaste le bâtiment lorsque l'alambic saute.
@note: Le souffle projette &p8 en arrière dans les buissons. Des poutres et des chaume enflammés tombent tout autour d'elle.
@note: Toussant et sonnée, elle se remet péniblement sur pied.
@p8: &p7_firstname ! &p7_firstname !
@note: Aucune trace de &p7. Seulement des flammes rugissantes et le bruit de la bataille qui se rapproche.
@note: Dans la fumée, elle aperçoit des silhouettes de pirates aux prises avec des soldats en uniforme.
@p8: Sacré nom ! Toute l'affaire est complètement partie à vau-l'eau.
@note: Elle repère une brèche dans les combats vers le bord de la plantation.
@p8: Les autres auront entendu ça. Ils sauront que la route est coupée.
@p8: Je dois gagner la &chapel seule. Atteindre le point de rendez-vous prévu. C'est la seule carte qu'il me reste à jouer.
@note: &p8 reste basse, contournant le carnage, laissant derrière elle l'inferno rugissant du &clubhouse.`},study_13:{personIds:["p6","p13"],deaths:["p13"],objects:[{id:"lighter",heldBy:"p13"},{id:"croquetbat",heldBy:"p6"},{id:"key",heldBy:"p13"}],links:["clubhouse_13","garden_12"],clue:`@note: &p6 et &p13 se glissent dans le bureau.
@note: Ils s'arrêtent net à la vue du corps de &p1 sur le sol.
@p6: Jerry ?
@note: &p6 tombe à genoux, lâchant le &croquetbat, examinant son ami. Il lève les yeux, perdu et dévasté.
@trigger:switch_owner:croquetbat:p0
@p6: Il est... il est mort.
@note: &p13 laisse échapper un rire sombre.
@p13: Une comédie d'erreurs. Je viens réclamer une dette de sang et je trouve que tout le monde fait mon travail à ma place.
@p6: Arrêtez ! Vous n'avez aucun respect ?
@p13: Le respect est pour les vivants, l'Anglais. Les morts s'en moquent.
@note: &p6 se lève, furieux, et se dirige vers la fenêtre.
@p6: Nous avons raté les autres... Où peuvent-ils être ?
@note: Il se fige. À travers la vitre, il voit &p7 et &p8 courir vers le &clubhouse en flammes.
@p6: Non... &p7_firstname ! NON !
@note: Sous ses yeux, le &clubhouse explose en une boule de feu.
@p6: VITA !
@note: &p6 se précipite vers la porte. &p13 lui attrape le bras.
@p13: Laissez-la. L'endroit grouille de Japonais. C'est du suicide.
@p6: Lâchez-moi ! Elle est là-bas !
@note: &p6 se dégage et sprinte hors de la pièce en direction de l'inferno.
@note: &p13 le regarde partir en secouant la tête.
@p13: Des fous. Tous autant qu'ils sont.
@note: Il inspecte la pièce silencieuse. Il s'approche du bureau, sort un cigare de la boîte et l'allume avec le &lighter qu'il tire de sa poche.
@note: Il en tire une longue bouffée, puis se penche et glisse le &lighter dans la poche de poitrine de &p1.
@p13: Je crois que ceci est à vous.
@note: &p13 se retourne et s'en va dans la nuit, disparaissant dans les ombres.
@note: Son aura quitte la plantation. C'est la dernière fois que &p13 fut ici. On ne peut plus le sentir après cela.`},veranda_12:{personIds:["p4","p10"],deaths:["p10"],objects:[{id:"vial",heldBy:"p10"}],links:["garden_12","veranda_13"],clue:`@note: &p4 est assise seule dans le fauteuil en rotin, perdue dans ses pensées, un verre de gin à la main.
@note: &p10 longe la &veranda en hâte, ayant l'intention de passer son chemin, mais s'arrête en la voyant.
@note: Il hésite, écartelé entre le devoir et l'émotion. Il prend une grande inspiration pour se composer, mais un sanglot lui échappe.
@p10: &p4_firstname...
@p4: <i>(Sans se retourner)</i> Qu'est-ce encore, &p10_firstname ? Une autre calamité pour nous voler nos heures dérobées ?
@p10: C'est le Tuan. C'est le Tuan &p1_lastname.
@p4: Qu'a-t-il fait cette fois qui puisse être pire que nous vendre à des pirates ?
@p10: Il est mort, &p4_firstname.
@note: &p4 se fige. Le verre tremble dans sa main.
@p4: Ne dites pas de sottises. Les hommes comme lui ne meurent pas comme ça.
@p10: Nous l'avons trouvé dans le bureau. Il... il était parti.
@note: &p10 sort le &vial de sa poche, la main tremblante.
@p10: Je l'ai trouvé près de lui.
@note: &p4 regarde fixement le &vial, puis &p10. Son visage est blême, la bouche légèrement entrouverte.
@p4: Mort ? Vraiment et définitivement ?
@p4: Je... je le haïssais. Je le méprisais.
@p4: Mais je l'aimais. Dieu m'en pardonne, je l'aimais plus que tout au monde.
@note: Soudain, des cris éclatent depuis le jardin. Des torches s'enflamment dans l'obscurité, suivies par des coups de feu.
@note: Ils regardent avec stupeur le &clubhouse s'embraser.
@p4: <i>(Chuchotant)</i> Le monde est en train de finir.
@p4: Est-ce que... le saviez-vous ?
@p10: <i>(Secouant la tête)</i> Non. Je ne suis pas un traître.
@note: &p4 verse une nouvelle rasade de gin, la main étonnamment stable à présent. Elle l'avale d'un trait.
@note: Elle se lève et attrape &p10, le serrant contre elle.
@note: Elle l'embrasse, un baiser désespéré, passionné.
@p4: Tu es un homme bien, &p10.
@p4: Tu dois te trouver une femme bien. Quelqu'un qui ne soit pas brisé. Avant qu'il ne soit trop tard.
@p10: <i>(Lui caressant tendrement le visage)</i> J'ai une femme bien juste ici.
@note: Un vrai sourire illumine le visage de &p4.
@note: Un coup de feu retentit et &p10 s'effondre sur le sol, mort.
@note: &p4 le regarde, horrifiée. Le sang de &p10 maculant toute sa robe. Elle hurle.`},veranda_13:{personIds:["p5","p4","p9","p2"],deaths:["p5"],links:["veranda_12","garden_12","kitchen_14","clubhouse_13"],clue:`@note: &p5 monte sur la &veranda, le visage tordu dans un rictus de haine.
@note: Il braque son pistolet fumant sur &p4.
@p5: <i>(Crachant les mots)</i> Les domestiques ? Tu ne voulais pas de moi mais tu t'es offerte aux domestiques ? À un <c>Jap</c> par-dessus le marché ? Avec tout ce qui se passe ?
@p4: <i>(Les yeux fixés sur le corps de &p10, engourdie par le choc)</i> Tu... tu l'as tué.
@p5: Putain !
@note: &p5 s'avance sur elle, levant le pistolet.
@p2: Mère !
@note: Le cri de &p2 déchire la nuit.
@note: &p5 se retourne, distrait.
@note: &p9 lève son fusil sans hésiter et tire.
@note: &p5 semble incrédule tandis que le sang commence à ruisseler sur son visage, un trou sombre apparaissant au milieu de son front. Il s'effondre par-dessus la rambarde de la &veranda, mort avant de toucher le sol.
@note: Une explosion colossale secoue la propriété, le sol tremblant sous leurs pieds. Le &clubhouse n'est plus.
@p9: Il faut bouger ! Maintenant !
@p4: <i>(Les yeux toujours fixés sur &p10)</i> &p10_firstname...
@p9: <i>(La saisissant par le bras)</i> Il est parti, Mem. Mais &p2_firstname est là et elle a besoin de vous.
@p2: <i>(Sanglotant)</i> Mère, je vous en supplie !
@p9: Le &clubhouse est détruit. Notre route est coupée.
@p9: Nous devons passer par la fenêtre de la &kitchen et contourner par-derrière jusqu'au &boathouse. C'est notre seule chance.
@p4: <i>(Regardant sa fille, reprenant lentement pied dans la réalité)</i> Oui. Oui, bien sûr.
@p9: Suivez-moi. Restez bas.`},kitchen_14:{personIds:["p9","p4","p2"],deaths:["p9"],links:["boathouse_15"],clue:`@note: La &kitchen est plongée dans l'obscurité. &p2 monte la garde tandis que &p9 force le loquet de la fenêtre arrière.
@note: Il passe à moitié à travers, vérifiant le périmètre.
@p9: La voie semble libre. Allez-y, Mem.
@note: Il tend la main en arrière pour aider &p4.
@note: Soudain, il aperçoit un mouvement dans les buissons dehors.
@p9: En arrière !
@note: Une rafale de tirs automatiques déchiquète le cadre de bois de la fenêtre.
@note: &p9 est touché plusieurs fois. Il se convulse violemment et retombe à l'intérieur de la &kitchen, le sang se répandant sur les carreaux.
@p4: &p9_firstname !
@note: Un soldat japonais apparaît à la fenêtre, pointant son arme sur &p4.
@note: &p2 hurle et lève son fusil.
@note: Elle tire et la tête du soldat part en arrière, il s'affaisse hors de vue.
@note: &p2 saisit la main de &p4.
@p2: Cours, Mère ! Cours !
@note: Elles enjambent le corps de &p9 et passent par la fenêtre fracassée, filant dans l'obscurité vers le &boathouse.`},clubhouse_14:{personIds:["p6"],deaths:["p6"],links:["clubhouse_13"],clue:`@note: &p6 traverse le jardin comme un démon, se frayant un chemin à travers les envahisseurs à coups de feu.
@note: Trois soldats japonais tombent en rapide succession. Il vide le revolver et le lance à la figure d'un soldat.
@note: Une baïonnette s'élance. &p6 la dévie, dégainant son couteau en un éclair. La lame trouve la gorge du soldat.
@note: &p6 reçoit une balle dans la cuisse. Il grogne mais ne ralentit pas.
@note: Il s'empare du pistolet d'un soldat mort et tire à bout portant sur l'assaillant suivant.
@note: Il est cerné. Un soldat lève son fusil pour l'exécuter.
@note: Un pirate jaillit des buissons, un kris flamboyant à la lueur des torches. Le soldat est embroché.
@note: D'autres pirates se joignent à la mêlée, engageant les Japonais dans un corps à corps brutal.
@note: &p6 continue d'avancer en titubant, ignorant le chaos, les yeux fixés sur le &clubhouse en flammes.
@note: Il reçoit un autre coup à l'épaule. Et encore un dans le ventre.
@note: Il atteint l'inferno et voit une main dépassant de sous une poutre effondrée.
@p6: VITALINA !
@note: Il plonge les mains dans les décombres en feu, la chair grésillant. Il soulève la poutre dans un rugissement de pure agonie.
@note: Il traîne le corps brisé de &p7 sur le sable. Elle est partie.
@note: &p6 s'effondre à côté d'elle. Il essuie la cendre de son visage d'une main tremblante.
@p6: Je suis là, mon amour. Je suis là.
@note: Il l'embrasse sur le front une dernière fois.
@note: Il lève les yeux et voit des lumières au loin depuis le rivage.
@p6: Regarde, mon amour. Une [embarcation](&boat). Elle vient nous sauver. Nous pouvons encore y arriver.
@note: Il ne bougera plus jamais.
@note: Le feu rugit au-dessus d'eux, consumant le clubhouse et les amants ensemble.`},library_13:{personIds:["p3","p12"],objects:[{id:"binoculars",heldBy:"p3"},{id:"sample",heldBy:"p3"}],links:["clubhouse_13","companionway_1","roof_14"],clue:`@note: &p3 et &p12 gravissent les escaliers en courant, les balles écaillant le plâtre autour d'eux.
@note: Des soldats japonais envahissent le couloir du bas.
@p3: Dans la bibliothèque ! Vite !
@note: Ils se précipitent dans la &library et &p3 claque la lourde porte en chêne, tirant le verrou au moment même où un choc violent ébranle le cadre.
@note: Les balles commencent à faire éclater le bois.
@p3: Ça ne tiendra pas longtemps ! Il nous faut cette clé !
@p12: <i>(Fouillant frénétiquement dans un livre évidé)</i> La clé n'est pas là ! Quelqu'un l'a déjà prise.
@note: La pièce est soudainement illuminée par une vive lumière venant de l'extérieur.
@note: Ils se précipitent à la fenêtre et voient le &clubhouse s'élever en un pilier de feu.
@p12: Le &clubhouse est parti. Le passage secret ne sert plus à rien maintenant.
@p3: <i>(Rechargeant son fusil)</i> Que faisons-nous ? Nous sommes pris au piège.
@p12: Si nous sortons par la fenêtre de la bibliothèque, nous pouvons atteindre le &roof. Il y a une échelle de sécurité qui descend jusqu'au &balcony.
@p3: Et ensuite ? Sauter ? C'est du suicide !
@p12: <i>(Riant)</i> J'ai toujours envisagé de sauter de là comme une belle façon de partir.
@p12: Mais non... la marée est haute. C'est assez profond, ça devrait être parfaitement sûr à cette heure... enfin, plus sûr que de rester ici, de toute façon.
@p3: Bien. Soit, allons-y.
@note: &p3 brise la vitre de la fenêtre d'un coup de crosse.`},roof_14:{personIds:["p3","p12"],objects:[{id:"binoculars",heldBy:"p3"},{id:"sample",heldBy:"p3"}],links:["clubhouse_14","chapel_14","balcony_15"],clue:`@note: &p3 sort le premier, cherchant une prise précaire sur les tuiles glissantes de suie. Il tend la main en arrière pour aider &p12.
@note: &p12 se bat avec sa volumineuse robe de soie, le vent fouettant le tissu autour de ses jambes. Elle glisse, une tuile dégringolant dans l'obscurité en bas.
@p3: <i>(L'attrapant par le poignet)</i> Je vous tiens ! Doucement !
@p12: Cette maudite robe ! J'aurais dû mettre un pantalon !
@note: Ils se hissent jusqu'au faîte du toit, à bout de souffle.
@p3: Regardez... le soleil se lève, l'obscurité se dissipe.
@note: À la lumière de l'aube naissante, l'horreur de la nuit se révèle dans toute sa crudité. Des colonnes de fumée s'élèvent comme des piliers noirs au-dessus de la propriété.
@note: En contrebas, près du &clubhouse en flammes, de petites silhouettes sont engagées dans une mêlée désespérée. &p3 utilise les &binoculars pour mieux voir. &p3 repère &p6, reconnaissable à sa carrure imposante, repoussant un groupe de soldats japonais avec une intensité sauvage.
@p12: Est-ce Bone ? Il... il les repousse à mains nues !
@p12: Et qui est cette personne qui court vers la &chapel ?
@p3: Est-ce Mademoiselle &p8_lastname ?
@p12: C'est elle. Elle s'en est sortie.
@p3: Nous devons continuer à bouger. L'échelle vers le &balcony est par ici.`},boathouse_15:{personIds:["p4","p2"],links:["balcony_15","boathouse_16"],clue:`@note: &p2 et &p4 trébuchent jusqu'au &boathouse, claquant la porte sur le chaos dehors.
@note: &p2 se précipite vers le radeau, ses doigts s'acharnant sur le nœud d'amarrage.
@p2: Allez ! Allez, bon sang !
@note: Elle se retourne vers sa mère.
@p2: Mère ! Aidez-moi ! Il est coincé !
@note: &p4 s'appuie lourdement contre une pile de caisses, le visage blême.
@p2: Mère ?
@note: &p2 se précipite à ses côtés. Les mains de &p4 sont pressées contre son flanc, le sang suintant entre ses doigts, tachant sa robe d'un cramoisi sombre.
@p2: Vous êtes blessée ! Pourquoi n'avez-vous rien dit ?
@p4: <i>(Souriant faiblement)</i> Il fallait continuer à avancer, petite lune. Il n'y avait pas le temps de s'arrêter.
@note: Soudain, la porte du boathouse vole en éclats sous les coups de crosse.
@note: &p2 crie, reculant. Elle lève son fusil, les mains tremblantes mais résolues.
@p2: Reculez ! Je tire !
@note: La porte cède. Des soldats japonais envahissent l'entrée, baïonnettes au canon.
@note: &p2 ferme les yeux, pressant la gâchette.
@note: Mais avant qu'elle ne puisse tirer, des coups de feu éclatent depuis les hauteurs.
@note: Les soldats de tête tombent et les autres battent en retraite, confus, regardant en direction de la falaise.
@note: &p2 suit leur regard. Là-haut sur le &balcony, deux silhouettes se découpent contre le ciel de l'aube, les fusils crachant des éclairs.
@p2: <i>(Les larmes ruisselant sur son visage)</i> &p3_firstname ! Je le savais ! Je savais que tu ne nous abandonnerais pas !`},balcony_15:{personIds:["p3","p12"],objects:[{id:"binoculars",heldBy:"p3"},{id:"sample",heldBy:"p3"}],links:["roof_14","boathouse_15","boathouse_16"],clue:`@note: L'aube se lève, peignant le ciel de teintes rouge sang. La [suie noire](BLACK_SMOKE) commence à se disperser.
@note: &p3 et &p12 se tiennent au bord du &balcony, contemplant le désastre en contrebas.
@note: L'incendie du &clubhouse s'est propagé, consumant les jardins alentour. Au sud, le feu de la &railway a atteint les champs de tabac à sec, transformant l'horizon en un mur de flammes.
@note: Dans la jungle, les pirates battent en retraite, leurs ombres s'esquivant à l'approche des lignes japonaises.
@note: Les soldats ont sécurisé la plage et envahissent la plantation.
@p3: Regardez ! Là-bas !
@note: Au &boathouse, &p2 et &p4 luttent avec le cordage d'amarrage du radeau. Un groupe de soldats japonais se referme sur elles.
@p3: Elles sont prises au piège ! Elles n'arrivent pas à défaire le nœud !
@note: &p3 lève son fusil et tire. &p12 l'imite. Ils abattent les soldats de tête, mais la distance est trop grande et leurs munitions s'épuisent.
@p3: Zut ! Je suis à sec !
@p12: Moi aussi ! Ils continuent d'avancer !
@p3: Je dois descendre là-bas.
@note: &p3 grimpe sur la rambarde.
@p12: Lucas ! Non ! Vous serez abattu dès que vous émergez !
@p3: Il faut que j'essaie !
@note: Il plonge dans la mer agitée en contrebas.
@p12: <i>(Le regardant disparaître dans l'eau)</i> Au diable tout ça.
@note: &p12 retrousse sa robe et grimpe sur la rambarde.
@p12: Geronimo !
@note: Elle saute après lui, plongeant dans les vagues.`},chapel_14:{personIds:["p8"],links:["chapel_15","companionway_1","roof_14"],clue:`@note: &p8 fait les cent pas nerveusement à l'intérieur de la petite &chapel de pierre.
@p8: Où sont-ils ? Le &boathouse est encore vide.
@note: Elle scrute par l'étroite fenêtre, observant le chaos qui se déroule en bas.
@note: Ses yeux se plissent en apercevant deux silhouettes sur le &roof de la maison principale.
@p8: Mais au nom du ciel, que font-ils ?
@note: Elle regarde &p3 et &p12 se hisser jusqu'au &balcony.
@p8: Fous. Complètement fous.
@note: Elle se retourne vers l'intérieur de la chapelle, les yeux parcourant le sol et les murs de pierre.
@p8: Attendez. Le « passage secret »...
@p8: Ce n'est pas qu'une chapelle. Elle repose sur une structure renforcée. Un bunker de guerre.
@note: Elle écarte la lourde nappe d'autel et découvre une trappe verrouillée par un cadenas rouillé.
@p8: Voilà.
@note: Elle attrape une grosse pierre mais avant de frapper, elle remarque quelque chose.
@p8: Le cadenas est déjà ouvert.
@note: &p8 examine la trappe.
@p8: La poussière est dérangée. Quelqu'un est passé par là récemment.
@note: Elle soulève la trappe avec effort, découvrant une échelle qui descend dans l'obscurité.
@p8: Tiens donc. Voilà qui change les choses.
@note: Elle descend dans les ténèbres.`},chapel_15:{personIds:["p8"],links:["chapel_14","boathouse_16"],clue:`@note: &p8 remonte par la trappe, tirant une lourde caisse en bois.
@note: Elle la force. À l'intérieur, recouvertes de poussière, se trouvent des [fusées Hale](HALE_ROCKETS).
@p8: Dieu bénisse la paranoïa britannique.
@note: Elle se précipite à la fenêtre. En bas, &p3 et &p12 ont refait surface et nagent vers le boathouse. Les soldats japonais s'alignent sur le rivage, visant les nageurs sans défense.
@p8: Ils sont comme des canards dans un stand de tir. Pas question.
@note: Elle hisse l'une des fusées sur le rebord de la fenêtre. C'est un vieux projectile rudimentaire, lourd et rouillé.
@note: Elle craque une allumette contre le mur de pierre et allume la mèche.
@p8: Feu !
@note: La fusée siffle, des étincelles jaillissent, puis elle s'élance par la fenêtre dans un puissant souffle.
@note: Elle file vers la plage et s'écrase dans le sable juste devant le groupe de soldats japonais.
@note: Sable et éclats d'obus se dispersent partout. Les soldats se débandent, plongeant à couvert, visiblement ébranlés par cette artillerie inattendue.
@p8: <i>(Souriant largement)</i> Ha !
@note: Elle tend la main vers la caisse mais celle-ci est vide.
@p8: Diable. Il n'y en avait vraiment qu'une ?
@note: Des balles commencent à éclater la pierre autour de la fenêtre.
@p8: Parfait, me voilà à mon tour comme un canard dans un stand de tir.
@note: Elle se glisse à l'intérieur de la &chapel tandis qu'une grêle de plomb martèle l'extérieur.`},boathouse_16:{personIds:["p3","p12","p4","p2"],objects:[{id:"binoculars",heldBy:"p3"},{id:"sample",heldBy:"p3"}],deaths:["p4"],links:["boathouse_15","balcony_15","chapel_15","boat_17"],clue:`@note: &p3 et &p12 se hissent sur le ponton, à bout de souffle.
@note: Une explosion assourdissante déchire la plage derrière eux lorsqu'une fusée s'écrase.
@p3: Qu'est-ce que c'était, diable m'emporte ?
@p12: Une intervention divine ?
@p3: Allons-y !
@note: Ils nagent jusqu'au &boathouse.
@note: À l'intérieur, &p4 est affaissée contre une caisse, sa robe trempée de sang. &p2 lui tire la main, en pleurs.
@p2: Mère ! Je vous en supplie, levez-vous !
@p4: <i>(Faiblement)</i> Pas cette fois-ci, petite lune. Pas cette fois.
@note: &p3 s'essuie rapidement les mains sur son pantalon et examine la blessure.
@p3: C'est grave. Elle a perdu trop de sang.
@p3: Allons, &p2_firstname. Le radeau est prêt.
@p2: Non ! Je ne la laisserai pas !
@p4: Pars, ma chérie. Vis. Vis pour nous deux.
@p4: Cet endroit... c'est tout ce que je connais. Il est juste que j'y reste.
@note: &p4 prend &p12 par la main.
@p4: Emmenez-la. Promettez-moi de veiller sur elle. Je sais que nous n'avons pas toujours été d'accord, mais vous êtes quelqu'un de bien et Lune vous aime.
@p12: Je le promets.
@note: &p3 attrape &p2, qui crie et se débat.
@p3: Pardonnez-moi.
@note: Il la jette sur son épaule.
@p3: &p12_firstname, détachez l'amarre !
@note: &p12 serre la main de &p4 une dernière fois. &p4 acquiesce d'un signe de tête.
@p12: À vos ordres !
@note: Ils poussent le radeau dans l'eau.
@p12: Je vois des lumières dans l'obscurité. Est-ce votre embarcation ? Là-bas !
@p3: Dépêchons-nous !
@note: &p4 les regarde s'éloigner tandis que la vie s'éteint dans ses yeux.`},boat_17:{personIds:["p3","p12","p2"],objects:[{id:"binoculars",heldBy:"p3"},{id:"sample",heldBy:"p3"}],leaves:["p3","p12","p2"],links:["boathouse_16"],clue:`@note: Ils rament frénétiquement vers le grand bateau ancré au large.
@note: Des balles sifflent autour d'eux, s'écrasant dans l'eau.
@p12: Ramez ! Ramez plus fort !
@note: Les tirs s'arrêtent soudainement mais ils sont trop concentrés pour le remarquer.
@note: Ils atteignent l'embarcation et montent à bord.
@note: Le pont offre un spectacle sinistre. Des corps de marins britanniques et japonais pourrissent au soleil.
@note: &p3 va vérifier les moteurs.
@p3: Elle tournera !
@note: Ils regardent en direction du rivage.
@note: Une ligne de navires de guerre gris est apparue à l'horizon. L'Union Jack flotte à leurs mâts.
@p12: Je n'arrive pas à y croire ! La Marine ! Ils sont là !
@p3: Trop tard pour la plantation. Mais juste à temps pour donner une bonne leçon aux <c>Nips</c>.
@note: &p2 se tient à la poupe, regardant la fumée s'élever de sa demeure.
@p3: Voulez-vous y retourner ?
@note: &p2 regarde la terre en flammes, puis ses compagnons.
@p2: Il ne reste plus rien pour moi là-bas.
@p12: Ni pour moi. Jerry est parti. Vita... tout le monde.
@p3: Alors nous partons.
@p3: J'ai des contacts à Londres. Nous pouvons repartir de zéro. De nouveaux noms. De nouvelles vies.
@note: &p3 pousse les moteurs à fond et le bateau vire vers le large, laissant derrière lui le cauchemar de la Plantation Goodwill.
@note: Ainsi Lune est bien sortie vivante de la plantation ? Je dois [en informer M. Goodwill au plus vite](doc_investigation).
@note: Bien que je pense qu'il y a encore beaucoup à découvrir sur ce qui s'est passé à la plantation et pourquoi.
@note: Peut-être que je peux trouver des indices sur l'endroit où ils sont allés à partir d'ici.`},chapel_16:{personIds:["p8"],links:["chapel_15","boathouse_16","chapel_17"],clue:`@note: &p8 est clouée au sol dans la &chapel, les éclats de pierre volant sous les balles qui mitraillent l'intérieur.
@note: Elle risque un coup d'œil par la fenêtre et voit le radeau s'éloigner du &boathouse.
@p8: Allez. Filez d'ici.
@note: Elle vérifie son revolver. Deux cartouches restantes.
@p8: Je pourrais tenter une sortie. Essayer de nager.
@note: Elle regarde la plage, grouillante de soldats.
@p8: A qui est-ce que je veux faire croire ça ? Je serais taillée en pièces avant d'atteindre l'eau.
@note: Elle soupire et s'affaisse contre le mur.
@p8: Bien, &p8_firstname. Tu voulais une vie plus palpitante que de rédiger des testaments. Méfie-toi de tes vœux.
@note: Elle serre le revolver fort.
@p8: Bien. Rendons le Roi fier.
@note: Elle se lève, se préparant à une charge finale.
@note: Mais son élan héroïque est brisé net par un son différent qui perce à travers les coups de feu. Des sirènes. Des sirènes de navires.
@note: Elle regarde par la fenêtre.
@note: Doublant le promontoire, les blanches vedettes agiles de la Police Armée font leur apparition.
@note: Et derrière elles, une ligne de navires de guerre gris.
@p8: <i>(Riant, incrédule)</i> La cavalerie.
@p8: La foutue Marine est là !
@note: Elle s'affaisse sur le sol, riant de soulagement les larmes aux yeux tandis que les gros canons des destroyers commencent à tonner.`},chapel_17:{personIds:["p8"],objects:[{id:"pearl2",heldBy:"p8"},{id:"photo2",heldBy:"p8"}],links:["chapel_16","guesthouse_18","commandpost_19"],clue:`@note: Les coups de feu ont cessé, remplacés par les commandements ordonnés des officiers de marine débarquant des embarcations.
@note: &p8 sort de la &chapel dans la lumière du matin, rengainant son revolver.
@note: Elle contemple la propriété. Les incendies sont en cours de maîtrise mais les cicatrices dans la terre sont permanentes.
@note: Elle plonge la main dans sa poche pour son étui à cigarettes, ses doigts effleurant quelque chose de lisse et de rond.
@note: Elle le sort. C'est une unique et parfaite &pearl2. Le tourbillon rouge en son centre accroche la lumière, luisant comme une braise mourante.
@note: Elle la roule entre ses doigts, songeuse.
@p8: Un souvenir. Pour ne pas oublier.
@note: Elle remet la perle dans sa poche et allume une cigarette.
@note: Un officier de marine s'approche d'elle, la main sur son holster.
@p8: <i>(Exhalant un nuage de fumée)</i> Du calme, Lieutenant.
@p8: Je suis &p8, MI5.
@p8: J'ai toutes les informations sur ce qui s'est passé ici cette nuit.
@p8: Mais d'abord... j'ai besoin de me nettoyer. Ensuite je vous ferai mon compte rendu.
@note: Elle passe devant l'officier stupéfait en direction du pavillon de bain, la tête haute.
@note: Un Commandant près de la &veranda n'est pas aussi facilement décontenancé.
@unknown: Allez vous nettoyer et rejoignez-moi à 10h précises pour le débriefing !
@note: &p8 fait semblant de l'ignorer mais sourit tout en continuant de marcher vers le pavillon de bain.`},guesthouse_18:{personIds:["p8"],objects:[{id:"pearl2",heldBy:"p8"},{id:"photo2",heldBy:"p8"}],clue:`@note: &p8 observe la propriété, regardant les officiers de marine repousser les derniers soldats japonais vers la jungle. Le bruit des coups de feu s'amenuise et ralentit tandis qu'ils reprennent le contrôle de la plantation.
@note: De jeunes soldats courent dans tous les sens pour tenter de maîtriser l'incendie du clubhouse tandis que les hangars de séchage de tabac près de la voie ferrée ne sont plus qu'un amas de ruines fumantes.
@note: &p8 entre dans le pavillon de bain et s'assoit près de la jarre de Shanghai. Elle y plonge la tête, l'eau fraîche lavant l'épuisement de son visage. Elle pose délicatement la &pearl2 sur un comptoir en se déshabillant.
@note: Je la laisserai là, à la solitude du bain à la louche, à méditer sur son destin et celui de ses camarades, tandis qu'elle tente de laver la suie de Bornéo de sa peau.
        `},commandpost_19:{personIds:["p8"],objects:[{id:"photo2",heldBy:"p8"}],links:["guesthouse_18","commandpost_20","study_19"],clue:`@note: &p8 sort de la chambre d'amis, ayant récupéré des vêtements de rechange qu'elle avait laissés là à son arrivée à la plantation.
@note: Elle se sent aussi reposée que les circonstances le permettent après son bain.
@note: Elle peut voir que la Marine s'est mise au travail, établissant [les lignes](LINES). Un &messhall a déjà été installé et une soupe de fortune chauffe déjà sur le feu.
@note: &p8 entre dans le &commandpost, la faible lumière de la lampe à huile projetant de longues ombres dans la pièce.
@note: Elle examine la pièce, prenant la mesure du centre de commandement improvisé.
@p8: Ces marins travaillent décidément très vite, il faut le reconnaître.
@note: Il y a un bureau avec une carte de la propriété étalée devant elle, une radio sur l'étagère, un briquet en or distinctif et une pile de papiers épars. Elle remarque un [manifeste](MANIFEST|keydialogue) et le feuillette.
@p8: Où est &p16_lastname ? Il m'avait dit 10h précises.
@note: &p16 entre.
`},shore_17:{personIds:["p16","p17","p18","p19"],objects:[{id:"knife",heldBy:"p18"}],links:["shore_18","veranda_18","commandpost_20"],clue:`@note: L'armée japonaise est en train de réduire en bouillie ce qu'il reste des hommes de &p13_lastname lorsque les silhouettes massives des navires de guerre et des chalands blindés touchent le rivage. La Marine britannique est arrivée.
@p17: <i>(Criant par-dessus les coups de feu et le rugissement des moteurs)</i> Allez les hommes, vous connaissez la procédure ! Faites-leur savoir que les hommes du Roi les ont trouvés !
@note: Les officiers japonais réalisent qu'ils font face à un bataillon frais et se retrouvent pris de court, à court de munitions. Craignant d'être coupés de leurs transports, les Japonais signalent une retraite précipitée, disparaissant dans les épais buissons pour foncer vers la &beach. Ceux qui sont coupés du reste se lancent plutôt vers la jungle de l'Ulu, espérant se cacher profondément dans les arbres.
@note: Certains soldats japonais, se sentant acculés, se terrent derrière de bas murets et ouvrent le feu.
@note: Au moment où les chalands s'échouent, certains hommes sont touchés par des balles perdues.
@p16: En joue ! Fauchez ces canailles !
@note: Les derniers soldats encore au combat sont pris dans une grêle meurtrière de tirs de mitrailleuse.
@note: &p16 crie tandis que les derniers soldats japonais sont réduits au silence.
@p16: Cessez le feu !
@note: &p19 et ses compagnons fantassins plongent dans l'eau à mi-cuisse, luttant avec de lourds cordages pour amarrer les chalands contre la marée. Les rampes d'abordage tombent avec un claquement métallique et le reste du débarquement s'effectue sur le sable.
@note: &p18 attrape &p19 par le col.
@p18: Allez Tweety, allons explorer. Où tu veux aller ?
@p19: Je n'ai jamais vu une &veranda aussi belle, &p18_title. Regardez tout ce verre. Enfin, ce qu'il en reste.
@p18: Allez, vieux, on peut se trouver un petit verre si il en reste quelque chose.
@note: Un silence macabre retombe sur la plage, rompu seulement par le crépitement du &clubhouse en feu, tandis que les patrouilles de reconnaissance investissent les bâtiments à la recherche de survivants ou d'ennemis tapis dans l'ombre.
@note: Les mousses commencent une chaîne de déchargement des caisses de l'Amirauté depuis les chalands dans la vase. &p16 contemple le désordre sanglant et voit &p8 sortir de la &chapel.
@p16: Nom d'un chien. &p8_firstname, aussi vrai que je suis en vie.
@note: Il la regarde avec un sourire tandis qu'elle passe devant un lieutenant stupéfait et se dirige vers le &guesthouse.
@p16: <i>(Criant à travers la plage)</i> Allez vous nettoyer et rejoignez-moi à 10h précises pour le débriefing !
        `},shore_18:{personIds:["p16","p17"],links:["veranda_19","study_19"],clue:`@note: La plage est un capharnaüm de fumée et de douilles vides. &p17 et &p16 sont appuyés contre un palmier, regardant le clubhouse flamber. &p17 sort un paquet de Lucky Strike et en propose un à &p16 qui refuse.
@p17: <i>(Exhalant une longue volute de fumée)</i> C'est une sacrée tragédie, n'est-ce pas ? Ils ne vont pas lâcher.
@p16: Ils ont commencé comme ils comptent continuer. [Kota Bharu](KOTA_BHARU) a été un bain de sang. Nos hommes et les troupes indiennes se sont battus vaillamment d'après ce que j'entends, mais les <c>Nips</c> ont tout envahi avec une rapidité incroyable.
@p17: Et c'était en même temps que Pearl Harbour ! Ils sont vraiment rusés et organisés. Il faut bien leur reconnaître ça.
@p16: Pas seulement Hawaï. Ils ont frappé Hawaï, les Philippines et la Malaisie simultanément.
@p17: Terrifiant.
@p16: Et mon frère. Il est en poste à Sandakan. Il m'a dit qu'ils ont dévalé la péninsule malaise à bicyclette. Les hautes sphères disaient que la jungle était impénétrable et ils leur ont donné tort à vélo. Vous imaginez ?
@note: &p17 finit sa cigarette.
@p17: Bien. Je ferais mieux de m'assurer que mes hommes ne perdent pas leur temps.
@p16: Souvenez-vous seulement. Ils ont coulé nos 2 cuirassés soi-disant insubmersibles en moins de 3 heures. Notre temps ici est révolu. Nous devons simplement nous retirer avec dignité.
@p17: Ce discours catastrophiste, je ne le tiens pas à mes hommes. Je n'ai pas envie de me retrouver avec des déserteurs sur les bras, merci bien.
@note: &p17 se dirige vers la &veranda tandis que &p16 gravit lentement la pente vers la maison principale, les mains fermement croisées dans le dos.
        `},study_19:{personIds:["p16"],objects:[{id:"lighter",heldBy:"p2"}],clue:`@note: &p16 entre calmement dans le bureau, inspectant les lieux. Il regarde par la fenêtre pour voir les derniers soldats japonais fuir vers la jungle, poursuivis par ses hommes.
@note: Il se penche ensuite à la fenêtre pour regarder les chalands japonais tenter de s'enfuir tandis que les navires de la Royal Navy leur bloquent la route.
@p16: Nous avons eu de la chance cette fois. Vraiment de la chance.
@note: Il reste là un moment à admirer le feu d'artifice puis s'apprête à ressortir quand il remarque quelque chose briller dans la poche de poitrine du corps de &p1 sur le sol.
@note: Il s'accroupit pour examiner &p1 de plus près.
@p16: Curieux. Vous n'avez pas été abattu. Que s'est-il réellement passé ici ?
@trigger:switch_owner:lighter:p16
@note: &p16 soulève l'objet brillant de la poche. C'est le &lighter. Il siffle.
@p16: Ça, c'est un beau Dunhill. Plaqué or ?
@note: &p16 empoche le &lighter et quitte la pièce.
`},veranda_18:{personIds:["p18","p19"],objects:[{id:"knife",heldBy:"p18"}],links:["veranda_19"],clue:`@note: &p18 et &p19 entrent sur la véranda, avançant à pas furtifs en position basse, leurs baïonnettes fixées. Ils sécurisent le pont, à la poursuite des derniers soldats japonais qui s'étaient dispersés dans le jardin.
@note: Tout ce qu'ils trouvent sont les corps de &p5 et &p10.
@p18: Voie libre, fiston.
@p19: Vous croyez qu'ils vont revenir ?
@note: &p18 appuie son fusil contre une table en rotin. Il se sert un verre au bar.
@p18: Sans aucun doute. Ils reviendront en force avant même que tu t'en rendes compte. On les a simplement pris par surprise, c'est tout.
@p19: <i>(Regardant le corps de &p10)</i> Regardez ce Nippon dans sa salopette. Vous pensez qu'il faisait partie de la Cinquième Colonne et que c'est pour ça que ces deux-là se sont battus ? Avez-vous entendu parler du barbier japonais qui s'est avéré être un espion et a tranché la gorge de tous ses clients lorsqu'il a reçu le signal ?
@p18: <i>(Amusé)</i> Le signal ?
@p19: Oh oui, &p18_title. Ils ont des signaux très complexes et cachés qu'ils attendent, et ensuite, Bam ! Ils frappent. Ils passent du sympathique photographe au guerrier mortel.
@p18: L'appareil photo cache-t-il un pistolet ? Peut-être que le flash est de la poudre à canon !
@p19: Ne plaisantez pas. Ils ont des oreilles et des yeux partout. Ils vous servent le thé ou vous coupent les cheveux pendant dix ans, seulement pour se révéler être les maîtres de votre destruction.
@note: &p19 s'excite vraiment pendant que &p18 se sert un deuxième verre.
@p19: Et avez-vous entendu parler de la Société du Dragon Noir ? Ils financent toutes ces boutiques à dix sous japonaises comme des organisations de façade. Pourquoi croyez-vous que ces boutiques vendent des jouets et des soieries bon marché aux locaux ? Pour s'attirer la sympathie et retourner les habitants contre nous, en leur racontant des mensonges à notre sujet.
@note: &p17 entre.
@p17: Allez les garçons. La fête est finie. Nous devons remettre de l'ordre chez nous, et au pas de course.
    `},veranda_19:{personIds:["p17","p18","p19"],objects:[{id:"knife",heldBy:"p18"}],links:["veranda_18","shore_20","clubhouse_20"],clue:`
@p17: &p19_title &p19_lastname, allez sur le &shore et rassemblez une corvée.
@p17: <i>(Montrant les corps sur le sol)</i> Portez ces hommes et les autres civils du domaine dans la cour de la &chapel, à côté du &cemetery. Ils méritent d'être enterrés avec respect. Nous ferons ça correctement, dans les règles de l'art.
@note: &p19 sort.
@note: L'incendie du &clubhouse fait toujours rage.
@p17: Et &p18_lastname, quand vous aurez fini ce verre, faites-moi une fleur et allez aider à organiser l'extinction du feu là-bas, il s'approche dangereusement.
@note: &p18 avale son verre d'un trait.
@p18: J'y vais.
@note: De forts hurlements éclatent à l'extérieur.
@p19: Les Nippons sortent de l'eau. Au secours !
@note: &p17 se précipite dehors sur le &shore pour voir ce qu'il se passe.
    `},shore_20:{personIds:["p17","p19"],links:["veranda_19","workerquarters_21","commandpost_21"],clue:`@note: &p17 court sur la plage depuis la &veranda et découvre que des corps de soldats japonais et de la Royal Navy s'échouent sur le rivage.
@p17: Que diable se passe-t-il ici ?
@unknown: Nous n'en avons aucune idée, Monsieur. Ces corps ont commencé à s'échouer. Ce ne sont pas nos hommes. Je ne comprends pas.
@p19: Regardez ! On leur a enlevé leurs bottes et ceintures ! Personne n'a de respect pour les morts ?
@p17: C'est l'œuvre des pirates, j'en mettrais ma main à couper. Les sauvages.
@p17: Mettez nos compatriotes britanniques avec nos camarades tombés au combat, nous leur accorderons des funérailles maritimes dans les règles.
@p17: Mettez les Nippons dans la fosse.
@p19: À vos ordres, monsieur.
@p19: Vous deux, venez avec moi, nous allons fabriquer un grand brancard en utilisant des grandes feuilles et des cordes. Nous pourrons en tirer plusieurs d'un coup.
@note: Quelqu'un d'autre s'approche.
@unknown: &p17_title &p17_lastname, le &p16_title vous cherche. Il est au &commandpost.
        `},cemetery_22:{personIds:["p19"],links:["cemetery_23"],clue:`@note: L'atmosphère près de la &chapel est aux antipodes du reste du domaine. C'est le calme plat. &p19 a rassemblé une nouvelle corvée, choisissant des marins plus âgés pour porter les corps de &p1 et des autres victimes enveloppés dans de la toile à voile blanche et les drapeaux britanniques récupérés depuis les chaloupes.
@note: Ils les déposent doucement sur l'herbe côte à côte avec une révérence silencieuse, le pas lourd.
@note: &p19 reste là avec ses hommes pour la minute de silence en signe de respect avant de sortir leurs cigarettes et de prendre une pause bien méritée près du mur de pierre de la &chapel.
        `},clubhouse_20:{personIds:["p18"],objects:[{id:"knife",heldBy:"p18"}],links:["clubhouse_21"],clue:`@note: L'incendie fait furieusement rage. La chaleur du feu est si intense qu'il est difficile de s'en approcher. Des braises sont emportées par le vent et commencent à enflammer les fougères de la zone.
@p18: Merde. C'est très mauvais. Hé, vous là. Oui vous. Pourquoi restez-vous planté là à le regarder ? Vous voyez les lavabos par là ? Il y aura des seaux. Allez en chercher vite.
@unknown: Bien monsieur.
@p18: Et vous. Allez vider quelques-unes de nos caisses sur le sable et commencez à les remplir d'eau.
@unknown: Bien monsieur.
@p18: Ne me dites pas « oui, monsieur ». Je n'ai pas terminé. Ne vous avisez pas de porter l'eau tout seul jusqu'ici. Créez une chaîne, attrapez tous ceux que vous trouverez.
@note: Le soldat court en direction de la plage.
@p18: <i>(Criant par-dessus le rugissement des flammes)</i> Et trouvez-moi une pelle pour que je puisse commencer à étouffer la base !
        `},clubhouse_21:{personIds:["p18"],objects:[{id:"knife",heldBy:"p18"}],links:["clubhouse_20","clubhouse_22"],clue:`@note: &p18 jette du sable à coups de pelle sur la base grondante de l'incendie, sa silhouette clignotante à contre-jour de l'éclat orangé. Derrière lui, une chaîne humaine de jeunes soldats et de mousses travaille avec une détermination acharnée. Ils jettent seau après seau d'eau sur les flammes, le visage noirci par la suie et glissant d'un mélange d'embruns et de sueur. Ils ne faiblissent pas et continuent aussi vite qu'ils le peuvent.
@note: Bien qu'épuisés, ils ne chancellent pas. Ils maintiennent la ligne face à l'enfer d'une rare force de volonté obstinée.
@note: Leur ténacité finit par payer car le feu commence à ralentir puis se retrouve sous contrôle.

    `},commandpost_20:{personIds:["p8","p16"],objects:[{id:"lighter",heldBy:"p16"},{id:"photo2",heldBy:"p8"}],links:["workerquarters_21","commandpost_21"],clue:`@p16: Votre montre doit avancer. Il est exactement 11 heures.
@note: &p16 attrape le &lighter sur le bureau et allume un cigare.
@p8: &p16_firstname ! C'est bon de vous voir, malgré les circonstances... Et vous aviez dit 10 heures, mais peu importe.
@p16: &p16_firstname ? C'est &p16_title &p16_lastname pour vous quand vous êtes sur mon territoire, agent.
@p8: Je m'excuse. Flegme britannique et tout le reste, ce n'a jamais été mon fort.
@p16: C'est ça, oui.
@note: &p16 prend le manifeste des mains de &p8 et le repose sur le bureau.
@p16: Maintenant que nous en avons fini avec les civilités. Soyez sympa et dites-moi ce que diable vient faire quelqu'un comme vous dans cette plantation isolée la veille d'une guerre, qui plus est.
@p8: J'avais des pistes indiquant que le Rajah et la triade mettaient tous deux la pression sur les gérants de la plantation. Pouvoir les coincer tous les deux d'un seul coup de filet était une occasion trop belle pour la laisser passer.
@p8: Les Nippons en ont décidé autrement.
@p16: Qui d'autre sait que vous êtes ici ?
@p8: Ma chère mère et mon fiancé, bien sûr.
@p16: <i>(Levant un sourcil)</i> Parfait.
@p8: Je... J'ai un service à vous demander.
@note: &p16 fixe simplement &p8 du regard.
@p8: Puis-je réquisitionner quelques-uns de vos hommes pour m'aider à enterrer ces pauvres âmes dignement dans le &cemetery près de la chapelle ? Ce massacre était terriblement de trop. C'étaient des gens bien et ils se sont battus avec ardeur jusqu'à la fin. Chacun d'entre eux. Je m'étais prise d'affection pour cette famille pendant les quelques heures que j'ai pu passer avec eux.
@p16: Ils sont à vous. Je vais demander au &p17_title &p17_lastname de vous aider à choisir quelques hommes pour vous aider à creuser.
@p16: Une fosse commune était en train d'être creusée derrière les quartiers des travailleurs pour les soldats japonais et les pirates. Je vous suggère d'aller les prévenir rapidement avant qu'ils ne commencent à y jeter tous les corps ensemble.
@note: &p8 court jusqu'aux &workerquarters tandis que &p19 s'approche du soldat en faction à l'entrée.
@p16: &p19_title, amenez-moi le &p17_title &p17_lastname, j'ai un travail pour lui.
`},commandpost_21:{personIds:["p17","p16"],objects:[{id:"lighter",heldBy:"p16"}],links:["commandpost_20","shore_20","jungle_22"],clue:`@p17: Au rapport, comme ordonné. Vous vouliez me voir monsieur ?
@p16: Ah &p17_firstname ! Quelle était cette agitation dehors à l'instant ?
@p17: Près du &shore ? Je... Je ne sais pas vraiment comment l'expliquer honnêtement, monsieur, mais nous avons la situation en main.
@p16: Bien, je m'en remets à vos mains expertes. En attendant, j'ai une petite corvée fastidieuse pour vous. Rassemblez quelques-uns de vos hommes et aidez cette petite pimbêche à enterrer ses gens. Peut-être que ça la fera taire et qu'elle me lâchera les baskets.
@p17: Si je puis me permettre, la connaissez-vous, monsieur ? Vous semblez plutôt agacé par cette femme. Elle me paraît pourtant inoffensive.
@p16: Ça ne vous regarde pas &p17_title. Restez à votre place.
@p17: Tout à fait. J'ai parlé à tort. Je vous prie de m'en excuser &p16_title.
@p17: &p18_title &p18_lastname aidait avec l'incendie du &clubhouse. Je vais lui parler et il pourra prendre Titi avec lui, il aidait déjà à transporter les corps des civils à la chapelle.
@p16: Continuez comme ça.
@note: Alors que &p17 quitte le &commandpost, on peut voir &p8 courir à travers le &garden en direction de la &jungle.
`},workerquarters_21:{personIds:["p8","p19"],objects:[{id:"photo2",heldBy:"p8"}],links:["cemetery_22","jungle_22"],clue:`@note: L'ascension vers les baraquements des travailleurs est une lutte épuisante et silencieuse. &p19 dirige la corvée, son visage est un masque de sueur et de suie grasse, tandis que les Mousses s'accrochent aux cordages du brancard de fortune pour le hisser en haut de la colline.
@note: L'un des garçons laisse la corde glisser et &p19 serre les dents.
@p19: Doucement, les garçons. Ne la laissez pas glisser. Si nous les laissons glisser en bas de la colline, nous passerons la journée entière à récupérer les corps dans les buissons.
@unknown: Ils sont si lourds. Et monsieur, ils... Ils commencent à sentir sous ce soleil de plomb. C'est insupportable.
@p19: Allez, allez. Nous y sommes presque.
@note: Ils atteignent la crête de la colline et &p19 ordonne une halte.
@p19: Sortez les pelles. Je veux une tranchée de six pieds de profondeur et dix de largeur. Et au pas de course, vous m'entendez ?
@p19: Je dois y aller et rassembler les corps des civils près de la &chapel maintenant. Je vous fais confiance, ne me décevez pas.
@note: Les jeunes hommes commencent à déchirer certains des uniformes des soldats japonais pour les utiliser comme masques de fortune afin d'arrêter l'odeur nauséabonde des cadavres en décomposition.
@note: &p8 gravit la pente vers les quartiers des travailleurs et l'odeur la frappe comme une brique. Cela ne fait que quelques heures, mais la chaleur affecte déjà la décomposition des corps.
@note: Lorsqu'elle atteint le sommet de la colline, son esprit n'arrive pas à comprendre le tas de corps qui gît devant elle.
@note: Une corvée de Mousses a la tâche macabre de creuser une fosse commune.
@p8: Attendez ! Dites-moi. Vous ne jetez bien dans cette fosse que des soldats japonais et des pirates, n'est-ce pas ? Vous n'allez pas enterrer un seul des civils assassinés dans ce... ce trou à rats ?
@note: L'un des Mousses fait une pause, s'appuyant lourdement sur une pelle crasseuse. Il abaisse son masque de fortune, le visage strié de boue.
@unknown: Non, madame. Aucun civil ici.
@unknown: Les corps des civils sont rassemblés près du &cemetery à côté de la chapelle. Nous séparons l'infanterie impériale, conformément aux ordres.
@unknown: Remarquez, j'ai trouvé une jeune domestique près de la &jungle, mais nous l'avons laissée là sous l'épaisse canopée pour le moment. Elle ne va pas... Eh bien, elle se conservera mieux là-bas jusqu'à ce que la corvée remonte.
@p8: Une jeune servante ? Se pourrait-il que ce soit &p11 ? Je ne l'ai pas vue lors de toute cette agitation.
@note: &p8 salue le jeune homme.
@p8: Rompez.
@note: Le garçon remet son masque et retourne à sa terrible tâche.
        `},jungle_22:{personIds:["p8"],objects:[{id:"photo2",heldBy:"p8"}],links:["jungle_23","cemetery_23"],clue:`@note: &p8 se fraye un chemin à travers les buissons et découvre le corps de &p11, allongé là. Elle s'accroupit à côté de la fille. Elle tend la main et ferme les yeux de &p11.
@p8: Pauvre fille. Tu es bien loin de la cuisine. Je me demande ce que tu faisais jusqu'ici ma chérie.
@note: En se relevant, &p8 aperçoit une couleur inhabituelle un peu plus loin dans les broussailles.
@p8: Qu'est-ce que c'est que ça ?
@note: &p8 écarte quelques branches et découvre le corps de &p14 adossé au tronc d'un arbre, criblé de balles. Elle fouille le corps et trouve le &report glissé dans son pantalon. Elle y jette un coup d'œil rapide.
@p8: Eh bien, c'est un coup de chance. Peut-être que tout n'était pas un échec total après tout.
@note: Elle glisse le rapport sous sa chemise et prend doucement le corps sans vie de &p11 dans ses bras.
@p8: Il est temps de faire nos derniers adieux.
@note: Alors que &p8 redescend la colline, un groupe d'hommes dirigé par une silhouette imposante est aperçu au loin, arrivant à bord d'une locomotive à vapeur.
        `},clubhouse_22:{personIds:["p17","p18"],objects:[{id:"knife",heldBy:"p18"}],links:["messhall_23","cemetery_23","clubhouse_21"],clue:`
@note: Les soldats forment une chaîne depuis l'eau jusqu'au clubhouse, hissant des seaux et des barils de fortune pour asperger le feu avant qu'il ne se propage. &p18 gronde des ordres en supervisant le travail lorsque &p17 s'approche.
@p17: &p18_title &p18_lastname, avez-vous une minute ?
@p18: Oui monsieur.
@p17: J'ai besoin de vous près de la chapelle. La femme survivante, une avocate, a besoin d'aide pour enterrer les civils de manière appropriée. Le Commandant m'a demandé de rassembler quelques personnes et, à mon tour, je vous en confie la responsabilité. Prenez &p19_lastname en passant.
@p18: Titi ? Vraiment ? Ce garçon ne se taira jamais.
@p17: Oui, mais c'est un travailleur acharné et il est toujours heureux d'aider.
@p18: Avec tout le respect que je vous dois, je préférerais qu'il soit paresseux, maussade et silencieux.
@p17: Faites simplement ce qu'on vous dit, &p18_title.
@p18: À vos ordres, monsieur.
@p17: Je vais aller casser la croûte si vous avez besoin de moi.
`},commandpost_22:{personIds:["p16"],objects:[{id:"lighter",heldBy:"p16"}],links:["commandpost_21","jungle_23"],clue:`@note: &p16 examine la carte et met au point leur prochain mouvement. Il essaie d'obtenir un signal sur la radio. Un Lieutenant entre.
@unknown: Monsieur. Un certain &p21_firstname &p21_lastname vient d'arriver par une locomotive à vapeur. Il a demandé à vous voir, il est près de la &jungle.
@p16: C'est la dernière chose dont j'ai besoin. Je vais aller voir ce qu'il veut. Merci Lieutenant.
        `},jungle_23:{personIds:["p16","p21"],objects:[{id:"lighter",heldBy:"p16"}],links:["railway_24","commandpost_24"],clue:`@note: &p16 et son lieutenant arrivent près de la clôture du périmètre. Ils sont accueillis par &p21 et son escorte de [Guerriers Iban](IBAN) tout de pagnes traditionnels vêtus, recouverts de tatouages et armés de fusils modernes ainsi que d'épées courbées anciennes.
@p16: Cher Rajah, Nous ne nous attendions pas à voir le drapeau du Sarawak si au nord. Ce sont les terres de la Chartered Company. Qu'est-ce qui vous amène par-delà la frontière ?
@note: &p21 tape avec sa canne sur la clôture détruite.
@p21: Les frontières, &p16_title ? Les Nippons se moquent de vos frontières. Je ne vois plus de plantation de la Compagnie ici, n'est-ce pas ?
@p16: Nous avons repoussé la première vague, monsieur. La Marine surveille la côte d'un œil vigilant et la brume se dissipe. C'est un peu tendu, mais nous tenons la ligne.
@p21: Vous ne tenez rien du tout. J'entends ce qui se dit à la radio. L'armée du Roi est trop dispersée et si la Chartered Company ne peut plus protéger ses actifs, il est peut-être temps pour une main plus ferme de superviser ces domaines.
@p16: Vous n'êtes pas sérieux. Essayez-vous simplement d'entrer ici et de vous emparer des biens de la Compagnie ? En pleine guerre, monsieur ?
@p21: Le ministère des Colonies est à cinq mille milles d'ici, plongé dans le noir par les Boches. Je suis juste ici. Si cette plantation est une perte totale, elle devient un protectorat du Rajah. Je n'aurai pas de base japonaise sur mon palier. Je me chargerai de protéger ces terres.
@p16: Vous n'êtes pas ici pour protéger quoi que ce soit. Vous êtes ici pour vos propres intérêts.
@note: &p21 frappe violemment le sol de sa canne, en colère.
@p21: Je suis ici pour Bornéo, &p16_title. L'île est ancienne et elle a la mémoire longue. Elle se souvient des Républiques Pirates et elle ne verra les Nippons que comme de la fumée dans l'histoire. La question est... Se souviendra-t-elle des Britanniques ?
@p21: Ce n'était qu'un avertissement de courtoisie. Je vous attendrai dans ma voiture jusqu'à votre départ.
@note: &p16 et son lieutenant retournent vers le domaine.
@p16: Cet homme est un fantôme du 19ème siècle, et il essaie toujours de déjouer l'Amirauté.
@p16: Nous n'avons pas besoin de plus d'effusion de sang et nous savons que l'île est perdue. Il ne rime à rien de se disputer sur des cendres. Laissez-le prendre le contrôle de la plantation et de ses fantômes, ce sera une victoire de courte durée lorsque les Nippons auront repris leur souffle et reviendront en force.
`},commandpost_24:{personIds:["p16"],objects:[{id:"lighter",heldBy:"p16"}],clue:`@note: &p16 sort une bouteille de whisky et un verre d'une boîte sur le sol.
@p16: Il me faut un verre, et ensuite nous pourrons nous préparer au départ.
@note: &p16 s'assoit en silence et contemple ce que les prochains jours lui réservent.
        `},railway_24:{personIds:["p21"],clue:`@note: &p21 est confortablement installé à l'intérieur de son wagon privé garni de velours, observant à travers les rideaux de soie la marine britannique qui commence à se retirer vers ses chaloupes.
@note: Sur une petite table en bois, un plateau en argent déborde de diverses viandes et fruits frais, une bouteille de vin pétillant est gardée au frais dans un seau à glace.
@note: L'homme est comme un bloc de bois. Solide, silencieux et ancien, attendant patiemment que le domaine se vide pour pouvoir enfin réclamer pour lui-même les restes de ces terres. Il s'imagine, peut-être, que cette dernière acquisition lui apportera un contentement éphémère. Ou peut-être ne sait-il plus ce qu'il veut après plus d'un demi-siècle passé à agrandir son royaume, que signifie vraiment un acre de terre de plus ?
@note: Et croit-il vraiment, au fond de lui-même, qu'il peut repousser la machine de guerre japonaise avec quelques lames Iban ? Ou fait-il volontairement l'autruche parce qu'admettre la vérité, à savoir que son royaume a été bâti sur un château de cartes, serait tout simplement trop difficile.
        `},cemetery_23:{personIds:["p8","p18","p19"],objects:[{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"},{id:"photo2",heldBy:"p8"}],links:["cemetery_22","messhall_24"],clue:`@note: &p8 arrive près de la chapelle pour y voir quelques soldats fumer une cigarette.
@p8: Excusez-moi &p18_title. Pourriez-vous m'indiquer où est le &p17_title &p17_lastname ?
@p18: La dernière fois que j'ai vu le &p17_title, il se dirigeait vers le &messhall.
@p19: Vous êtes la dame qui a tiré cette fusée ?
@p8: Je vous demande pardon ?
@p19: Nous vous avons vue donner une bonne leçon aux Nippons depuis la poupe, alors que nous approchions. Sacré beau spectacle, si je puis dire !
@p18: Vous devez excuser le jeune Titi, ici. Il n'a aucune manière. Je m'appelle &p18_firstname. Enchanté.
@p8: Aussi bien que possible dans ces circonstances, &p18_firstname.
@p18: J'ai entendu dire que vous aviez un travail pour nous ? Titi et moi sommes ici pour être vos muscles, pour ainsi dire. Combien de tombes allons-nous creuser ?
@note: &p8 inspecte le cimetière.
@p8: Je ne vois pas Bone et Vita, 2 de mes camarades tombés, parmi ce groupe. Sont-ce tous les corps ?
@p18: Il y a aussi deux corps carbonisés près du &clubhouse. J'y étais à l'instant pour éteindre le reste de l'incendie. Il n'en reste que des cendres, mais les morceaux de lin brûlé suggèrent des civils. À mon avis, il vaudrait mieux leur accorder des funérailles maritimes avec le reste de nos garçons.
@note: &p8 regarde vers le clubhouse et entrevoit ce qui reste de la robe de &p7 dans un tas d'os et de cendres.
@p8: Vous y étiez à l'instant, dites-vous ?... Au moins, ils sont morts ensemble. Ils s'aimaient vraiment.
@p19: <i>(Interrompant les pensées de &p8)</i> Alors, où voulez-vous qu'on commence à creuser ?
@note: &p18 donne une tape derrière la tête de &p19.
@p18: Laissez une minute à cette femme, &p19_firstname. Ne voyez-vous pas qu'elle se recueille ?
@p8: Ce n'est rien. Avez-vous une pelle de rechange pour moi ?
@note: &p8 les emmène dans une partie isolée du cimetière et ils commencent à creuser.
@p19: C'est un travail qui creuse, ça. J'espère qu'il restera de la tambouille pour nous quand nous aurons fini.
@p18: Taisez-vous et creusez, l'ami.
@p8: Ne soyez pas trop dur avec le garçon. Ne vous inquiétez pas &p19_title, nous prendrons de la soupe après.
        `},messhall_23:{personIds:["p17"],links:["shore_20","messhall_24"],clue:`
@note: &p17 déguste sa soupe au calme, en lisant un journal vieux d'un mois qu'il a pris dans la bibliothèque lorsqu'ils ont chassé les Nippons de la maison.
@note: Quand soudain, un simple soldat vient s'asseoir à côté de lui.
@unknown: Sergent. Je voulais m'excuser pour la fausse alerte sur le &shore un peu plus tôt. Je n'avais juste jamais rien vu de tel.
@p17: Ce n'est rien, Soldat. Ça a été une sacrée matinée. Nous sommes tous à cran.
@unknown: Tout de même. À votre avis, que leur est-il arrivé ? C'était si aléatoire et... sauvage.
@p17: Je ne pense pas que nous le découvrirons un jour, alors je vous conseillerais de ne plus y penser. Sortez-les simplement de l'eau et mettez-les avec le reste des victimes.
@p17: Maintenant, si vous n'y voyez pas d'inconvénient, j'aimerais retourner à ma lecture.
@unknown: Monsieur ? Avec tout le respect que je vous dois, ce sont de vieilles nouvelles. Vous le savez bien, n'est-ce pas ?
@p17: Ça me détend juste de lire sur des choses simples, des plaisirs simples et des querelles insignifiantes. Ça me sort de cette vie macabre que nous menons en ce moment et ça me donne l'espoir que nous pourrons un jour retourner à la normale.
@unknown: Vous avez raison, monsieur. Je vous y laisse.
`},messhall_24:{personIds:["p8","p17","p18","p19"],objects:[{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"},{id:"photo2",heldBy:"p8"}],links:["cemetery_23","messhall_23"],clue:`@note: &p8, &p18 et &p19 arrivent au mess couverts de boue et de sueur. Ils déposent leurs pelles près de l'entrée.
@p19: Chef, qu'y a-t-il de bon ?
@p8: &p18_title &p18_lastname, où est le &p17_title &p17_lastname ?
@p18: C'est celui qui est assis tout seul, avec l'air tout stoïque.
@note: &p17 lève les yeux de son journal tandis que &p8 et &p18 approchent.
@p18: Eh Sergent. C'est l'avocate.
@p8: Ravie de vous rencontrer &p17_title &p17_lastname.
@p17: De même. J'espère que &p18_title &p18_lastname et &p19_title &p19_lastname se sont montrés utiles ?
@p8: Tout à fait, et ça m'a fait réfléchir. Si je peux obtenir la bénédiction de &p16_title &p16_lastname, j'aurais besoin de votre aide encore davantage.
@p8: &p19_title &p19_lastname me dit que vous êtes en poste à [Sandakan](SANDAKAN) depuis quelques années. Est-ce vrai ?
@p17: C'est un fait, oui. Je suis un vieux briscard du coin depuis pas mal d'années. Pourquoi ça ?
@p8: Et il me dit aussi que le &p18_title est un survivaliste et a eu affaire à l'&ulu presque toute sa vie ?
@p17: Titi a une grande gueule, mais c'est également vrai. Où voulez-vous en venir, madame ?
@p8: J'aimerais vraiment que vous m'aidiez à rejoindre [Sandakan](SANDAKAN) à pied. Toutes les autres voies sont des pièges mortels à présent et je dois urgemment voir mon fiancé qui est encore en ville.
@p17: Avec tout le respect que je vous dois, nous sommes des soldats, madame. Pas des nounous.
@p8: Et ce sont de bons soldats qu'il me faut. Ne vous y trompez pas, ceci sera un ordre. Je suis juste civile en vous prévenant bien à l'avance, c'est tout.
@p17: Est-ce tout ? Je souhaite retourner à mon bouillon avant qu'il ne refroidisse.
@note: &p17 se détourne de &p8 et continue de manger. &p19 accourt et s'assoit à côté d'eux avec un grand bol de soupe et un petit pain, inconscient de la tension.
@p19: Seigneur, je suis affamé.
@note: &p19 sirote sa soupe très bruyamment. Il prend son pain et essaie d'en arracher un morceau.
@p19: Bon sang ! C'est dur comme de la pierre, comment on est censé couper ça !
@note: &p18 arrache sèchement le pain des mains de &p19, agacé.
@p18: Donne ça ici, espèce d'idiot !
@note: &p18 sort un solide couteau de poche.
@p18: Ne gardes-tu jamais ton &knife sur toi ? Parfois, je te jure.
@note: &p18 coupe le pain en deux d'un coup sec et le tend à &p19.
@p8: C'est tout un &knife, &p18_title.
@p18: Modèle réglementaire, madame.
@p19: Je vous suis bien obligé, &p18_title !
@note: &p19 reprend sa dégustation bruyante, trempant son pain au fur et à mesure. Il s'arrête brusquement et lève les yeux vers le visage de marbre du &p17_title et le regard d'acier de &p8_firstname.
@p19: Dites. Pourquoi tout le monde a l'air si sombre ?
`},library_2:{personIds:["p1","p6"],objects:[{id:"lighter",heldBy:"p1"},{id:"pearl",heldBy:"p6"}],links:["veranda_3","clubhouse_3"],clue:`@note: &p1 et &p6 entrent dans la bibliothèque, &p1 ouvre la boîte à cigares sur la table ornée en ivoire, tend un cigare à &p6 et l'allume avec son &lighter. On entend le clic caractéristique d'un briquet Dunhill à levier. &p1 le remet ensuite dans la poche de son gilet.
@note: Ils sont bientôt entourés de fumée.
@p1: Tout le lot de perles n'a aucun orient, Bone. C'est le verdict.
@p6: Mais elles ont beaucoup d'orient en elles. Elles ne sont pas vitreuses, je peux voir le lustre. Ils essaient de vous arnaquer.
@p1: Je comprends ce que vous dites, mais tous ceux que j'ai vus sont d'accord. Ce tourbillon rouge qui est apparu dans toutes nos perles signifie qu'elles pourraient tout aussi bien être un simple caillou. Elles sont sans valeur. Ils ne peuvent tout simplement pas les utiliser comme bijoux en nacre.
@p6: Et pour les coquilles ? Elles sont toujours bonnes. Il y a plus de valeur dans les coquilles avec le volume que nous avons.
@p1: Ils ne toucheront pas aux coquilles. Ils ont peur que nos perles soient contaminées par une malédiction. Et ceux qui ne croient pas à ça pensent que c'est une guerre chimique des <c>Japs</c> pour tous nous tuer.
@p6: Je vous le dis, Jerry, ils ont raison. C'est une malédiction. D'abord le commerce du tabac qui s'assèche, maintenant les huîtres qui prennent ce tourbillon rouge de mauvais augure.
@note: &p1 éteint son cigare et dévisage fixement &p6.
@p1: Ne soyez pas si ridicule, mon vieux.
@note: &p6 met la main dans sa poche et jette une poignée de &pearl sur &p1.
@p6: Regardez-les ! Regardez-les simplement ! On dirait l'œuvre du diable. Nous sommes finis !
@p6: C'est le [Bomoh](BOMOH) des [Rajahs Brooke](BROOKE_RAJAHS), je vous dis. Il essaie de nous chasser. Ils veulent ces terres depuis des années et la Chartered Company s'en moque maintenant qu'elle a ses mines d'or de caoutchouc et d'huile de palme.
@note: &p1 regarde les perles rouler sur le sol, puis &p6.
@p1: La Compagnie s'en soucie, Bone. Mais ils sont préoccupés. Nous devrions tous l'être.
@p1: Ce n'est pas une malédiction. C'est de l'instabilité géopolitique. La menace japonaise est réelle. L'Europe est dans la tourmente économique avec la montée du nazisme. C'est pour ça que les marchés sont effrayés, pas à cause d'un sorcier.
@p6: Vous êtes aveugle, Jerry. Vous êtes trop éloigné de tout ça, assis ici dans votre tour d'ivoire. Avez-vous vu la brume verte à l'horizon ? Comment diable expliquez-vous cela ? Elle se rapproche depuis des semaines.
@p1: Ou peut-être que c'est vous qui êtes aveugle. Vous ne voyez pas ce qui se passe là-bas, à passer toute la journée au &clubhouse, défoncé à l'opium.
@p6: Si ce n'est pas une malédiction, alors c'est la [Triade](TRIAD). Ils ont fait quelque chose à notre cache. Ils conspirent avec les marchands pour dévaluer les perles afin de nous racheter à bas prix.
@p1: Assez ! Vous devenez paranoïaque. Arrêtez ces absurdités.
@p1: Nous avons besoin d'un plan pour sauver la plantation, pas d'histoires de fantômes ni de théories du complot paranoïaques.
@p1: Nous rencontrerons &p8_firstname après le dîner. Nous devons examiner les finances et voir quelles sont nos options. C'est pour ça que je l'ai ramenée avec moi aujourd'hui.
@p6: <i>(marmonnant)</i> Bien sûr que oui.
@p1: Bref, il est 18 heures, l'heure d'un Sundowner, vous venez ?
@p6: Ils m'attendent au &clubhouse. Je vous rejoindrai après.`},library_3:{personIds:["p8"],objects:[{id:"pearl",heldBy:"p8"}],links:["library_2","guesthouse_4"],clue:`@note: &p8 entre dans la bibliothèque. Elle voit des &pearl éparpillées sur le sol.
@note: &p8 s'agenouille et les ramasse avec soin, inspectant le tourbillon rougeâtre de leur lustre. Elle secoue la tête et les place dans la poche de son chemisier.
@note: Elle se dirige vers l'étagère et choisit plusieurs gros volumes.
@note: Elle s'assoit au bureau, ouvre la mallette qu'elle a apportée et étale une série de registres.
@note: &p8 allume une cigarette et se met au travail, les sourcils froncés de concentration.
@note: Elle passe un doigt sur la colonne des dépenses. Ils perdent de l'argent de tous les côtés... Autant pour les boissons et l'opium ?!
@note: Elle referme violemment le [registre](doc_ledgers) et se frotte les tempes.
@p8: Je dois vraiment aller me faire belle pour le dîner. Il fait une chaleur épouvantable, et je ne pourrais décemment pas apparaître dans ces vêtements humides.`},study_11:{personIds:["p10","p9"],objects:[{id:"telephone",heldBy:"p9",dialogue_trigger:"STUDY_11"},{id:"opium",heldBy:"p10"}],links:["study_10","study_12","veranda_12","theresaroom_10"],clue:`@note: &p9 entre.
@note: &p10 jette un coup d'œil à l'intérieur, n'en croyant pas ses yeux.
@p9: Vous voyez ? Je ne savais pas vers qui me tourner. Je ne sais pas à qui faire confiance.
@note: &p10 cherche un pouls. Aucun.
@note: Il voit la &vial et l'empoche, terrifié.
@note: Il place sa propre dose d'&opium sur le sol à côté de la main de la victime.
@p10: Un accident. Ça doit ressembler à un accident, c'est mieux ainsi. Nous pouvons dire que c'était une overdose. Sinon &p6_lastname me fera pendre.
@p9: Arrêtez de vous inquiéter, &p10_firstname. Je m'en occupe.
@note: &p9 décroche le &telephone.
@p9: <i>parle dans une langue que je ne comprends pas</i>
@note: Bon sang. Je ne parle pas malais, ni dayak, ni peu importe la langue qu'il utilise. Il va falloir que je retranscrive phonétiquement ce qui se dit et que je contacte Armand à Oxford. Il devrait être capable de me traduire ça.
@note: Maintenant il faut juste que je me concentre et que j'écoute attentivement.
@p9: <i>continue de parler</i>
@note: &p9 pose le téléphone.
@p9: Ils sont en route. Vous devriez y aller.
@p10: Qu'allons-nous dire aux autres ? Et &p2_firstname ? Elle sera dévastée.
@p9: La [petite Mem](MEM) est plus forte que vous ne le pensez. Et elle nous a, nous.
@p10: Je vais aller voir &p4_firstname. C'est là que je serai si vous avez besoin de me trouver.
@p9: De quoi parlez-vous ? Vous ne pouvez pas faire ça. Oubliez-la. Il est 2 heures du matin. Allez simplement vous coucher et qu'on ne vous voie pas.
@note: &p10 retire sa casquette et essuie la sueur et les larmes de son visage.
@p10: Très bien, oui, vous avez raison.
@p9: Je vais attendre les renforts ici. Allez-y.
@note: &p10 sort, son chemin vers ses quartiers le faisant passer devant la &veranda.
`},study:{clue:"De lourds meubles en teck et une odeur de fumée rance emplissent l'air. Un téléphone se trouve sur le bureau."},kitchen:{clue:"Située à l'arrière du bâtiment pour garder la chaleur infernale de la cuisinière à bois à l'écart des pièces principales."},dining:{clue:"Un grand hall où un large ventilateur brasse l'air stagnant au-dessus des convives."},clubhouse:{clue:`Une version rustique d'un club de gentlemen londonien ; avec une table de billard, d'anciens numéros de Punch et du Illustrated London News.
Il y a un bar qui sert des [Gin Pahits](GIN_PAHITS).`},workerquarters:{clue:"Une rangée de casernes en bois où les domestiques logent."},balcony:{clue:"Un point d'observation idéal surplombant la mer de Chine méridionale."},beach:{clue:"Une plage cachée, entourée de grandes falaises calcaires."},boathouse:{clue:"Une structure affaissée en bois blanchi par le sel. À l'intérieur, des filets de pêche en lambeaux pendent des chevrons."},garden:{clue:"Une pelouse impeccablement tondue avec un jeu de croquet."},library:{clue:"Des piles de journaux Straits Times jaunis s'entassent à côté des étagères de la bibliothèque, remplies de gros livres reliés."},bonfireroom:{clue:"La chambre où dorment &p6 et &p7."},masterbedroom:{clue:"À l'écart de la maison principale, ce bungalow séparé est la chambre du maître et de sa femme."},Luneroom:{clue:"L'espace est rempli du désordre habituel d'une jeune femme."},guestroom:{clue:"Spartiate et fonctionnelle, près du lavoir et des latrines."},sule_0:{personIds:["p2","p3","p12"],objects:[],clue:`@note: La mer est calme, mais le pont de la chaloupe est glissant de sang.
@note: &p12 est dans une cabine, avec un seau d'eau et un chiffon à peu près propre, en train de nettoyer &p2 qui a enfin cessé de pleurer.
@p12: Ça va aller, &p2_firstname. Vous avez de nouveau l'air de vous-même. Quoique, je ne sais vraiment pas quoi faire de vos cheveux. Ils sont tout à fait indisciplinés.
@p2: Peu importe. Laissez-les. Je veux juste m'enrouler en boule et dormir pour toujours.
@p2: Même si... j'ai une faim de loup. Les kachang d'Aisyah me manquent terriblement. Et les keropok... Je donnerais n'importe quoi pour un en-cas salé en ce moment.
@note: &p12 sourit d'un air las.
@p12: Moi aussi, ma chérie. Moi aussi.
@note: On frappe à la porte de la cabine.
@p3: Mesdames, j'aurai bientôt besoin de votre aide sur le pont. Oh, et &p12_firstname, j'ai trouvé les ciseaux que vous aviez demandés.
@p3: Et pour vous &p2_firstname, j'ai réussi à trouver du bœuf salé et quelques biscuits de mer.
@note: &p2 fait la grimace.
@p12: Allons, allons, jeune fille. Nous ne pouvons pas faire les difficiles.
@note: &p2 accepte la ration à contrecœur et commence à mâcher le bœuf coriace avec un regard de résignation sombre.
@note: &p12 utilise les ciseaux et commence à couper l'ourlet de sa robe de soie, raccourcissant sa tenue parisienne pour en faire quelque chose de plus pratique pour la vie en mer.
@note: Ils sortent sur le pont pour faire face aux corps en décomposition.
@note: &p3 traîne le corps d'un marin britannique vers le bastingage. &p2 et &p12 luttent avec le poids mort d'un soldat impérial japonais.
@p3: Oh, attendez. Ne les balancez pas simplement par-dessus bord ! Prenez leurs ceintures, bottes, montres et tout ce qui a de la valeur sur eux.
@p2: Lucas, c'est tout simplement macabre !
@p3: C'est de la survie, Lune. Nous n'avons rien. Ni pièces, ni papiers, et le monde est à feu et à sang.
@p12: Je dois dire que c'est une drôle de façon de passer la semaine avant Noël.
@p3: Les Nippons auront des yens, peut-être même un peu d'or. Les marins peuvent avoir quelques souverains ou dollars des Détroits dans leurs poches.
@p3: Et des armes de poing aussi. Nous échangerons tout cela contre des vêtements, de la nourriture et un billet pour l'Europe lorsque nous atteindrons &singapore dans quelques jours.
@note: Écœurées mais résignées, elles dépouillent les morts de leurs objets de valeur avant de les confier à l'océan.`},singapore_1:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: Ils arrivent à Singapour et l'endroit est un véritable chaos. Les sirènes des raids aériens hurlent. On entend les gens parler du HMS Prince of Wales et du Repulse qui ont été coulés par un raid aérien japonais il y a quelques jours. Tout le monde panique.
@note: &p2 et &p12 sont serrées l'une contre l'autre sur [Collyer Quay](COLLYER_QUAY), regardant les derniers grands navires quitter le port.
@note: Elles portent toujours leurs vêtements d'il y a plusieurs jours. Elles ont essayé de les nettoyer et de les restaurer du mieux qu'elles pouvaient, mais elles ont l'air d'avoir traversé l'enfer.
@note: &p3 fend la foule, avec des vêtements d'occasion propres à la main.
@p12: Vous voilà. Il y a tellement de monde ici, tout le monde se bouscule. C'était le dernier navire. J'ai entendu dire qu'il n'y en aurait plus maintenant que les Japonais sont là. Qu'allons-nous faire ?
@p2: &p3_firstname, j'ai peur. La foule nous écrase !
@p3: Ne vous inquiétez pas, j'ai un plan. J'ai toujours l'&sample. Je devrais pouvoir obtenir une audience avec le [Secrétariat Colonial](SECRETARIAT).
@p3: Ils nous fourniront des papiers et un passage sur un [Cargo Mixte](TRAMP_STEAMER).
@p3: Pour l'instant, je vous ai trouvé une chambre dans la [Shophouse](SHOPHOUSE) pour quelques dollars des Détroits.
@p3: Ce n'est pas grand-chose, mais cela vous donnera l'occasion de vous reposer et de vous laver.
@p12: Et vous ?
@p3: Je resterai en bas, je ne serai pas loin si vous avez besoin de moi.
@note: &p3 tend les vêtements à &p12.
@p3: Je suis désolé, c'est tout ce que j'ai pu trouver. J'espère qu'ils vous iront.
@p12: Ne vous excusez pas. Vous avez déjà tellement fait.
@p2: (Hoche la tête)
@p3: Allez vous reposer, nous avons une longue journée qui nous attend demain matin.`},singapore_2:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: &p3 est parti pour Empress Place afin de garantir leurs papiers au Secrétariat.
@note: Dans la petite chambre de la shophouse, &p12 frotte enfin la crasse de sa peau et revêt la robe en coton que &p3 a achetée pour elle. Elle a de nouveau l'air presque humaine.
@note: &p2, affamée, dévore la nourriture de rue que &p3 a apportée : satay, gâteaux de riz et diverses confiseries sucrées achetées aux marchands ambulants, jusqu'à virer au vert pâle et se recroqueviller sur le lit en gémissant.
@note: &p3 revient à la tombée de la nuit, l'air satisfait de lui-même.
@p3: C'est fait. J'ai parlé au capitaine du port. Nous ne sommes plus apatrides. Nous avons des papiers.
@p12: Dieu merci.
@p3: Cependant, cela signifie que je dois accomplir une mission pour eux. Nous devons emmener l'échantillon à Whitehall nous-mêmes. Ils pensent qu'il est plus en sécurité avec nous puisque nous voyageons incognito.
@p12: <i>(Sarcastique)</i> Bien sûr qu'ils le pensent.
@p3: De plus, par souci de convenance, et pour éviter tout interrogatoire inconfortable par les autorités portuaires, j'ai dû arranger nos papiers d'une manière particulière. &p2_firstname, vous êtes maintenant &p2_firstname &p3_lastname, et vous êtes ma sœur.
@note: &p2 se redresse instantanément, sa nausée oubliée. Elle rayonne.
@p2: Votre sœur ! Oh, &p3_firstname, c'est absolument merveilleux !
@p3: Et &p12_firstname... Je vous en prie, écoutez simplement la logique de la chose.
@note: &p3 commence à se tortiller, virant au rouge cramoisi.
@p3: Les papiers vous définissent comme étant mon épouse. C'était le choix le plus opportun. Un homme voyageant avec son épouse et sa sœur éveille moins de soupçons que... quelle que soit cette équipe hétéroclite.
@p12: <i>(Fronçant les sourcils)</i> Votre épouse ? Vraiment, &p3_firstname ? N'y avait-il pas de place pour une cousine éloignée ? Ou peut-être une tante célibataire ? Ou même juste une autre sœur. Pensez-vous que je sois trop vieille pour jouer la grande sœur, c'est cela ? Il n'était pas nécessaire de monter cette farce matrimoniale.
@note: &p3 sort piteusement deux simples alliances en or de sa poche.
@p3: Nous allons devoir les porter. Si nous voulons passer inaperçus, nous devons jouer le rôle.
@note: &p12 fixe les bagues, puis éclate de rire. L'absurdité de la situation est trop grande.
@note: Le sourire de &p2 s'efface. Elle lance un regard noir aux bagues, visiblement jalouse.
@note: &p3 s'en aperçoit. Il s'agenouille près du lit et tire une petite pochette en velours de sa poche.
@p3: Je ne vous ai pas oubliée, &p2_firstname.
@note: Il attache un collier de perles autour de son cou. &p2 halète en touchant les pierres fraîches.
@p12: <i>(Livide)</i> &p3_firstname ! Nous avions besoin de cet argent pour la nourriture ! Et pour le long voyage de retour ! Vous l'avez dépensé pour des babioles ?
@p3: Du calme, ma chère épouse. Nous avons plus qu'assez pour nous en sortir.
@p12: Vous vous habituez à ces absurdités de mariage avec un peu trop de facilité, M. &p3_lastname.
@note: Il agite un jeu de billets sous son nez.
@p3: Le passage pour l'Europe est assuré. Nous partons à la marée du matin. C'est un navire marchand de la Blue Funnel, pas un paquebot de luxe, mais il n'y a pas d'autre échappatoire hors de cette ville. J'ai eu une chance incroyable de pouvoir obtenir ces billets.
@p3: Je dois vous avertir que nous ne nous dirigeons pas vers les eaux libres. Nous devons franchir le détroit de &malacca. Cinq cents miles des eaux les plus étroites et les moins profondes sur terre, et les Nippons tiennent chaque pouce de la côte nord.
@p3: Ils ont capturé les aérodromes du Kedah, Alor Star et Sungei Patani. Cela signifie que leurs bombardiers ne seront qu'à vingt minutes de notre pont à tout moment. Ils chercheront notre sillage depuis les nuages, et nous naviguerons dans un black-out maritime total. Pas de phares, pas de balises. Si le capitaine se trompe de calcul, nous serons des cibles faciles pour un mitraillage.
@p3: Et puis il y a les I-Boats, les sous-marins japonais. Ils bouchent la sortie au nord de [Sumatra](SUMATRA), attendant le peu d'entre nous qui ne se font pas attraper par les avions.
@p3: Donc, je vous en prie, reposez-vous maintenant.
@p12: Une charmante histoire pour s'endormir, &p3_firstname. Bien joué.
@p3: Je vais prendre congé, alors. Je vais sortir. Dormez bien mesdames.
@note: &p12 attrape la main de &p3.
@p12: Vous ne ferez rien de tel. Restez dans la chambre avec nous. Après tout, cela éveillerait les soupçons si un mari et une femme faisaient chambre à part. Il y a de la place par terre, je vais vous chercher une couverture supplémentaire et un [traversin](BOLSTER).`},singapore_3:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: Le groupe est réveillé dans la nuit. Un hurlement mécanique et lancinant commence à s'élever et à retomber sur la ville.
@note: Ils s'habillent et descendent pour voir ce qui se passe.
@note: &p3 remarque un soldat britannique débraillé, un vétéran à en juger par son allure, recroquevillé dans l'arche de la shophouse.
@p3: Dites donc, soldat ! Que se passe-t-il ?
@unknown: Les <c>Nips</c>. Ils ont pris l'habitude de mitrailler la ville de façon régulière maintenant. Une sortie nocturne, en quelque sorte.
@note: Le soldat fait un vague geste vers les devantures fracassées de l'autre côté de la rue.
@unknown: N'avez-vous pas remarqué les vitres soufflées ?
@unknown: Je chercherais un trou si j'étais vous. Et je le ferais fissa.
@note: Les lampadaires s'éteignent soudainement. Le soldat rit.
@unknown: Au moins, ils ont retenu la leçon de la dernière fois. Sacrée incompétence ! La première nuit, le Gouverneur a laissé les lampes allumées comme un phare. Les <c>Nips</c> n'ont même pas eu besoin de boussole, les bombardiers ont simplement suivi les lumières droit sur leurs cibles.
@p3: C'est vraiment arrivé ?
@note: Le soldat opine du chef, écrasant sa cigarette sous une botte usée.
@unknown: Maintenant, mettez-vous à l'abri. Ils sont presque sur nous.
@note: Les sirènes d'alerte aérienne commencent à hurler.
@note: Le vrombissement commence. Une vibration basse qui fait claquer les dents dans les gencives. Le sol sous la shophouse commence à trembler.
@p3: La sirène ! Abritez-vous sous cette table ! C'est une lourde table en teck, elle tiendra.
@note: &p2 et &p12 se précipitent sous la table, &p3 s'agrippe fermement à elles.
@note: Le bruit des bombes qui explosent se rapproche de plus en plus.
@note: L'onde de choc fracasse toutes les vitres restantes dans la zone. Des éclats de verre jaillissent tout autour d'eux. Le souffle crée un vide qui aspire l'air de la pièce, leur faisant siffler les oreilles, remplacé par un mur brûlant de chaleur et de poussière.
@p12: &p2_firstname ! Êtes-vous entière ?
@note: &p2 hoche la tête, un regard terrifié sur le visage.
@p12: Nous ne pouvons pas rester ici à être enterrés vivants. Nous devons foncer vers le quai !
@p3: Allons au bateau. Vite.
@note: Ils trébuchent dans la rue. C'est le chaos absolu. Le ciel est d'un orange maladif, et l'air les étouffe avec l'odeur de caoutchouc brûlé et d'épices torréfiées provenant des entrepôts touchés.
@note: Le raid japonais a utilisé des bombes incendiaires. Les toits en bois des shophouses sont en feu. Les services d'incendie auxiliaires sont déjà sur place, luttant avec des pompes à bras.
@note: Dans la bousculade de la foule paniquée, &p2 est arrachée de la poigne de &p3 par une vague de fuyards.
@p3: Dites donc ! Pardonnez-moi ! Madame, écartez-vous ! Ma sœur... Faites attention, espèce de brute !
@note: &p3 essaie de naviguer dans la foule avec la frustration polie d'un gentleman dans une gare bondée, mais il est terriblement inefficace. &p2 est emportée de plus en plus loin dans l'obscurité.
@p12: Oh, pour l'amour du ciel !
@note: &p12 pousse &p3 de côté et plonge tête la première dans la foule. Elle assène un coup violent à un homme qui lui bloque le passage et en frappe un autre carrément dans le tibia.
@p12: Bougez-vous ! Dégagez de mon chemin ! &p2_firstname !
@note: Elle attrape &p2 par le col de sa robe et la ramène en arrière.
@p12: Venez ! Nous partons sur-le-champ !
@note: Ils courent à perdre haleine vers les quais de Keppel, grimpant sur la passerelle du navire marchand de la Blue Funnel juste au moment où les amarres sont larguées.
@note: Alors que le navire s'éloigne, la suie noire du Nord commence à retomber, recouvrant les survivants tremblants tandis que Singapour brûle derrière eux.`},malacca_4:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: Le navire marchand de la Blue Funnel était un labyrinthe. Le moindre centimètre carré d'espace sur le pont était occupé par des [Sujets Britanniques en Détresse](DBS) blottis sur des caisses ou dormant sur des couvertures sales. Le navire avançait au rythme lourd et lancinant des moteurs. C'était un rappel constant qu'ils étaient assis sur des milliers de tonnes de fret et de carburant, une cible de choix pour une torpille japonaise.
@note: &p3 a passé la première matinée sur le pont des embarcations, scrutant l'horizon à la recherche du reflet argenté des périscopes.
@unknown: Bonjour, monsieur. Toute une aventure, je dois dire. Quelle est votre histoire ?
@p3: Ma femme et moi étions à Bornéo. Nous avons réussi à rejoindre Singapour, mais de justesse. Et vous ?
@unknown: Bornéo, hein ? Vous avez été particulièrement rapides. J'ai passé trois semaines à me cacher avant de me ruer vers la [Jetée](CAUSEWAY). Les huiles à Singapour nous avaient dit que la jungle était infranchissable. Infranchissable ! Les Nippons la traversaient à vélo comme s'ils faisaient une promenade dominicale à Hyde Park.
@p3: C'est la même histoire partout, j'en ai bien peur. La Royal Navy est débordée.
@unknown: Ils ont été pris les culottes baissées. J'ai vu la fumée au-dessus du détroit quand je suis parti. Avez-vous réussi à sauver grand-chose ? Ou voyagez-vous avec un bon du Secrétariat comme le reste d'entre nous, pauvres hères ?
@p3: <i>(D'un geste vague vers la cabine)</i> J'ai ma femme et ma sœur avec moi. Nous avons sauvé quelques babioles et les vêtements que nous portons. Au-delà de ça... eh bien, je suppose que je repartirai de zéro une fois arrivés en Angleterre.
@unknown: Au moins, vous avez vos femmes saines et sauves. Mon épouse était sur le dernier bateau P&O parti en novembre. Prions le ciel qu'elle ait atteint le [Galle Face](GALLEFACE). Je n'ai eu aucune nouvelle depuis que la radio a été coupée à [Ipoh](IPOH).
@note: L'homme plonge la main dans sa poche et sort une flasque en argent cabossée.
@unknown: Un petit coup ? C'est un brandy d'origine assez douteuse que j'ai réussi à récupérer à Singapour avant que les sirènes ne commencent. Ça arrache comme un coup de pied de mule.
@p3: <i>(Prenant la flasque)</i> Vous êtes un prince. Aux amis absents, hein ?
@unknown: Aux amis absents. Et à une guerre courte.
@note: La nuit tombée, le navire est entièrement plongé dans le noir ; aucune lumière n'est autorisée sur le pont. Cela en ferait une cible trop facile sinon.
@note: &p3 entre dans la cabine.
@p3: Avez-vous toutes les deux bien pu vous reposer aujourd'hui ? Vous en aviez besoin.
@p2: <i>(Hoche la tête)</i> Oui, oui. Je me sens beaucoup plus fraîche. J'ai aussi fini nos rations terrestres. Je crains que mon plus grand défi soit encore à venir demain : réussir à garder l'ordinaire du bord dans mon estomac. Du mouton gras et du chou bouilli.
@note: &p12 pointe du doigt la rambarde à l'extérieur de leur cabine. &p3 et &p12 sortent.
@p3: <i>(S'appuyant contre la rambarde à côté de &p12)</i> Je crois que nous avons passé le [détroit de Malacca](MALACCA) sans être suivis. Nous mettons le cap sur le grand large ce soir.
@p12: Remercions les étoiles pour ces petites grâces.
@note: &p12 sort 2 cigarettes, en offrant une à &p3 qui refuse. Elle tire une longue bouffée.
@p12: &p2_firstname pleurait dans son sommeil. Pauvre fille. Elle a traversé tellement d'épreuves, mais elle fait preuve de tant de courage.
@p3: Nous la protégerons. Elle a une forte volonté, ça ira.
@note: Ils interrompent leur conversation lorsqu'ils entendent &p2 les rejoindre.
@p2: Singapour n'est plus, n'est-ce pas ? J'ai regardé en arrière à midi... il n'y avait plus que de la fumée.
@p12: <i>(Passant un bras autour des épaules de &p2 et la serrant contre elle)</i> Ne regarde pas en arrière, petite lune. Il ne nous reste plus rien en Orient. À partir d'ici, nous regardons vers la mère patrie.
@p2: <i>(Touchant les perles à son cou)</i> &p3_firstname ?
@p3: Oui, &p2_firstname ?
@p2: Vous portez toujours la bague. Vous ne l'avez pas enlevée depuis que nous avons quitté le quai, même dans la sécurité de la cabine.
@note: &p3 regarde l'alliance en or à son doigt, puis &p12 dans la pénombre.
    `},malacca_5:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: La cabine est une boîte en fer étouffante. &p12 frotte vigoureusement le hublot crasseux avec un chiffon humide, tandis que &p2 est allongée immobile sur la couchette inférieure, le visage de la couleur du lait tourné. &p12 jette le chiffon dans un seau.
@p12: Voilà. Au moins maintenant, nous pourrons peut-être voir la torpille avant qu'elle ne nous frappe. &p2_firstname, asseyez-vous. Vous avez passé la matinée à ressembler à une figure de proue sur une épave.
@p2: L'odeur qui vient de la cuisine. C'est tout bonnement moyenâgeux, &p12_firstname. Comment peuvent-ils s'attendre à ce que nous mangions du chou bouilli par cette chaleur ?
@p12: <i>(remettant l'alliance en or à son doigt)</i> On mange ce qu'on nous sert quand on est un Sujet Britannique en Détresse, ma chérie. Maintenant, levez-vous et mettez votre robe. Nous allons sur le pont prendre le thé.
@p2: Le thé ? Nous sommes sur un rafiot rouillé dans une zone de guerre, et vous parlez de mondanités ?
@p12: <i>(remettant l'alliance en or à son doigt)</i> Précisément. Si nous avons l'air de la plèbe, les autorités nous traiteront comme la plèbe. Dans cette partie du monde, le lin empesé est la seule chose qui nous sépare de l'abîme. Nous sommes la famille &p3_lastname maintenant, et nous jouerons ce rôle.
@note: &p3 entre dans la cabine, sa veste en lin blanc tachée de poussière de charbon.
@p3: Le pont grouille de monde. C'est tellement difficile de se déplacer sans renverser quelqu'un. Miller de Johore, le vieux bonhomme à qui je parlais hier, harcèle tout le monde pour avoir des nouvelles, et le personnel est débordé.
@p12: <i>(S'approchant et lissant le revers de veste de &p3)</i> Vous avez l'air d'avoir alimenté les chaudières vous-même.
@p12: Allons, &p2_firstname, le thé n'attendra pas. Venez.
@note: Plus tard, sur le pont des embarcations. &p12 est assise majestueusement dans un fauteuil en rotin, un exemplaire vieux de plusieurs mois du Tatler ouvert sur ses genoux. &p3 se tient derrière elle, la main posée passivement sur le dossier de sa chaise, le regard balayant l'horizon. &p2 est appuyée contre la rambarde, regardant le sillage blanc se dérouler derrière eux.
@p2: On dirait un linceul, n'est-ce pas ? Se déroulant jusqu'à Sandakan.
@p3: Si c'est un linceul, alors c'est un linceul funèbre, &p2_firstname. Les Nippons ont maintenant des aérodromes à [Kedah](KEDAH). L'état tout entier est désormais sous contrôle japonais et nous sommes sur le point de passer au large de cette côte. Si un [Nell ou un Betty](BETTY) repère notre sillage, nous sommes dans le pétrin.
@p12: <i>(Tournant une page de son magazine)</i> Parlez de quelque chose de plus agréable, chéri. Le groupe de vieilles femmes près du canot de sauvetage nous observe. Elles m'ont déjà demandé où nous nous étions mariés. Je leur ai dit à Singapour, il y a trois ans. Cathédrale Saint-Andrew.
@p3: Saint-Andrew, vraiment ? Vous avez une imagination débordante, &p12_firstname.
@p12: Soyez gentil et allez me chercher un peu de cette eau tiède affreuse qu'ils appellent du thé. J'ai soif.
@note: &p2 suit &p3 jusqu'au buffet de thé.
@p2: Trois ans. Vous avez effacé mon père le temps d'une conversation.
@note: &p3 se retourne, touchant le bras de &p2 avec affection.
@p3: Nous ne l'avons pas effacé, &p2_firstname. Jusqu'à ce que nous atteignions le [Galle Face](GALLEFACE), nous devons ne pas attirer l'attention. Tenez bon, petite lune. S'il vous plaît.
@note: &p2 fixe la mer avec mélancolie, retenant ses larmes.
@p2: Je tiens le coup, &p3_firstname. C'est le monde entier qui perd le nord. C'est ma mère qui me manque le plus. Mais j'aimais mon père aussi, vous savez. Et lui il aimait &p12_firstname. Souvenez-vous-en. Ne salissez pas sa mémoire.
@note: &p3 récupère trois tasses de thé tiède et commence à revenir.
@p3: Allons, &p2_firstname. Séchez ces larmes et venez prendre le thé avec nous.
@p2: &p3_firstname ?
@p3: Oui petite lune ?
@p2: Promettez-vous que nous chercherons mon frère ? Dès l'instant où nous poserons le pied sur le quai ?
@p3: Je vous en donne ma parole d'honneur.
@note: Je me demande pourquoi &p3 n'a pas tenu cette promesse ? Leur est-il arrivé quelque chose pendant le voyage ?

        `},malacca_6:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: Le navire marchand de la Blue Funnel a enfin émergé de l'étreinte claustrophobique du détroit de Malacca. La mer s'est ouverte sur la vaste mer d'Andaman. Pour la première fois depuis une semaine, l'horizon à l'est est dépourvu de la fumée de la Malaisie en flammes.
@note: &p3 est sur le pont. Il aperçoit les îles Nicobar. Ces îles étaient en train d'être renforcées par les Britanniques dans une tentative désespérée de créer une ligne de défense. &p3 est soulagé. Cette zone est toujours sous contrôle britannique, et apercevoir ce point de repère lui donne l'espoir qu'ils ont une chance de s'en sortir.
@note: C'est le jour de Noël 1941. Dans leur cabine exiguë à quatre couchettes, &p12 a accompli un petit miracle avec quelques morceaux de papier d'aluminium pour cigarettes, créant de joyeuses guirlandes festives et brillantes.
@note: &p3 retourne dans la cabine.
@p3: Le capitaine me dit que nous avons laissé Sumatra derrière nous. Nous sommes dans la mer d'Andaman maintenant, cap à l'ouest vers le [Galle Face](GALLEFACE).
@p12: Remercions le ciel. Un peu de chance, enfin.
@note: &p2 est assise au bord de la couchette, l'air plus vivante qu'elle ne l'a été depuis Singapour.
@p2: Est-ce vrai, &p3_firstname ? Sommes-nous vraiment loin des Nippons et de leurs aérodromes ?
@p3: Nous sommes de toute façon hors de portée des bombardiers pour l'instant. Il nous reste encore les sous-marins à redouter, mais le grand bleu est bien plus rassurant que ce détroit mortel.
@note: &p12 sort de sous la couchette une boîte cabossée qui était cachée là.
@p12: Alors je déclare une double célébration. L'une pour le capitaine et l'équipage de ce beau navire, et l'autre pour le Père Noël.
@p2: <i>(Haletante)</i> &p12_firstname ! Est-ce un plum pudding ?
@p12: Ne me demandez pas ce que j'ai dû échanger contre ça, et il a un peu souffert, et Dieu seul sait qu'il ne sera pas chaud, mais c'est Noël en boîte.
@note: &p3 sourit de toutes ses dents en révélant une bouteille avec une étiquette manuscrite tirée de la poche de sa veste.
@p3: Et j'ai réquisitionné quelques spiritueux de fête de notre ami Miller. C'est assez fort pour décaper la coque du navire, mais ça fera l'affaire pour un toast de Noël.
@note: &p3 verse le rhum piquant dans trois tasses. Le navire marchand de la Blue Funnel se balance doucement, premier avant-goût de la houle de la &bengal.
@p3: <i>(Levant sa tasse)</i> Aux amis absents.
@note: &p2 touche les perles à sa gorge tandis que sa voix tremble.
@p2: À Papa et Maman.
@p12: Aux amis absents. Et à nous... la famille &p3_lastname. Puissions-nous atteindre Tilbury avant que le gin ne vienne à manquer.
@p2: <i>(Prenant une toute petite gorgée et toussant)</i> Doux Jésus ! C'est comme boire un éclair !
@p3: <i>(Riant)</i> Ça va vous faire pousser des poils sur la poitrine.
@p12: <i>(Coupant le gâteau froid avec un canif)</i> Pensez-vous qu'ils écoutent le discours du Roi à la maison ? Autour d'un feu de cheminée, avec du vrai houx et de la vraie neige ?
@p3: J'imagine que oui. Même si je pense que Sa Majesté aura beaucoup à dire sur les désagréments actuels en Orient.
@p12: Tidapa, &p3_firstname. Pour ce soir, nous allons faire comme si nous étions en paix. Pas de pluie de suie, pas de sirènes, et certainement pas de pirates. Juste un véritable Noël au milieu de l'océan.
@note: &p12 tend une tranche de gâteau à &p2. &p2 mâche le gâteau riche et fruité, une larme finissant par s'échapper et rouler sur sa joue.
@p2: C'est la meilleure chose que j'aie jamais goûtée.
@p3: C'est un début, n'est-ce pas ? Quelques jours en eau libre et un peu de [duff](DUFF). Nous pourrions bien nous en sortir, &p12_firstname.
@p12: Vous êtes incorrigible, M. &p3_firstname. Ne devenez pas sentimental, ça ne correspond pas à votre image de mari. Maintenant, soyez un amour et versez-moi une autre lichette de cette eau de feu infâme. J'ai un esprit de Noël à maintenir.
        `},bengal_7:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: Le navire se vautre dans la baie du Bengale, bien loin du rivage. Il est escorté, avec une douzaine d'autres navires, par un destroyer de la Royal Navy.
@note: La mousson du nord-est a transformé la mer en un paysage violent, de grosses vagues s'écrasant sans cérémonie sur le navire marchand de la Blue Funnel.
@note: Le bateau tangue violemment. Après une journée de vomissements constants, &p2 a finalement succombé à un lourd sommeil de mal de mer sur la couchette inférieure.
@note: &p3 et &p12 l'ont laissée se reposer et sont dans la cuisine à prendre du thé. &p12 s'arc-boute en essayant de verser une mesure d'eau.
@p12: J'en ai assez de ce stupide bateau qui tangue comme un ivrogne. Je jure que mes organes internes ont changé de place.
@note: &p3 essaie de stabiliser la petite table.
@p3: La mousson dans la baie du Bengale est traîtresse, mais nous devrions bientôt en sortir et arriver à &colombo. C'est à ce moment-là que nous pourrons enfin nous détendre. Laissant à la fois la tempête et les Nippons définitivement derrière nous.
@p12: Vous êtes resté d'un calme troublant tout au long de cette épreuve, &p3_firstname. Cela fait-il partie de l'entraînement du SIS ? Apprendre à rester stoïque alors que le monde part en vrille ?
@p3: Ce n'est pas de l'entraînement, c'est la vie. J'ai vécu des moments poignants. Une fois que vous avez vu tout votre équipage se faire assassiner sous vos yeux alors que vous étiez impuissant, vous réalisez que s'inquiéter est un gâchis pour les dernières heures d'un homme.
@note: Soudain, une explosion assourdissante fait trembler la coque. Ce n'est pas une explosion à bord, mais une grenade sous-marine larguée par leur destroyer d'escorte à un kilomètre de là. Le gong d'urgence commence à résonner avec fracas.
@p3: C'est l'alarme sous-marine ! &p12_firstname, prenez votre gilet de sauvetage ! Maintenant ! Je vais chercher &p2_firstname.
@note: La panique éclate dans le couloir à l'extérieur. Dans le chaos, &p12 trébuche alors que le navire fait une embardée massive. &p3 se retourne pour la rattraper, enroulant ses bras autour de sa taille, la plaquant contre sa poitrine pour l'empêcher de tomber.
@note: Le navire continue de tanguer, les plats et les bouteilles s'entrechoquent et se fracassent tout autour d'eux en tombant des tables et des étagères.
@p3: Accrochez-vous à moi. Ne lâchez pas. Si on finit à l'eau, restez avec moi. Vous m'entendez ?
@note: Pendant une longue minute, ils restent enlacés, les battements du cœur de &p3 résonnant contre les côtes de &p12. Le navire marchand de la Blue Funnel se redresse lentement. Les explosions étouffées des grenades sous-marines se poursuivent au loin, mais le signal de fin d'alerte finit par retentir.
@note: Leurs regards se croisent une fraction de seconde, puis &p12 reprend contenance.
@p12: Vous pouvez me lâcher maintenant. Je vais très bien.
@note: Ils retournent dans la cabine, l'adrénaline les laissant tremblants et épuisés. &p2 bouge dans son sommeil mais ne se réveille pas. &p3 s'affaisse sur une caisse, la tête entre les mains.
@note: &p12 s'assoit à côté de lui et passe son bras autour de ses épaules pour le réconforter.
@p12: C'était... absolument terrifiant. Où est passé votre calme troublant maintenant ?
@p3: J'ai menti. Je garde tout en moi sur le moment, mais ça ressort encore plus fort une fois que c'est fini. Regardez ma main. Regardez.
@note: &p3 lève son bras droit et sa main tremble de manière incontrôlable.
@p3: Et aujourd'hui. Aujourd'hui, c'était pire. Je n'arrêtais pas de penser à vous et à Lune. Je me fichais de ce qui m'arrivait, mais ça me faisait tellement mal au cœur de penser qu'il pourrait arriver quelque chose à l'une de vous.
@p3: Je suis désolé &p12_firstname. Vous devriez profiter de la vie, pas attendre de vous faire éventrer par une torpille au milieu de nulle part.
@p12: Je n'étais pas heureuse à la plantation &p3_firstname. Je mourais d'une autre manière à Bornéo.
@note: &p12 essaie de se reprendre avant de dire la suite. Sa voix tremble alors qu'elle tente de retenir ses larmes.
@p12: Je... J'avais envisagé d'en finir à de nombreuses reprises, vous savez. J'avais même rédigé une... lettre d'adieu, par désespoir, et un besoin de me sentir regardée, de me sentir aimée.
@p12: Au moins ici... je me sens vivante. Même si je suis morte de peur.
@p3: Vous avez plus de cran que n'importe quel agent avec qui j'ai travaillé en Orient.
@note: &p12 appuie sa tête contre l'épaule de &p3.
@p12: Quel est le plan quand nous arriverons à Londres ? Vraiment ? Qu'y a-t-il dans votre cœur ?
@p3: Il n'y avait pas de plan véritable. Seulement vous garder toutes les deux en sécurité aussi longtemps que possible.
@p3: Mais maintenant. Après ces deux dernières semaines...
@note: &p3 reste silencieux un moment, caressant sa bague.
@p3: J'ai passé dix ans à jouer les fantômes, &p12_firstname. Pas d'attaches, pas de cœur. Mais vous voyant sur ce pont... j'ai réalisé que je ne veux pas franchir ce cap seul.
@p12: <i>(Fermant les yeux)</i> Vous n'êtes pas seul.
        `},colombo_8:{personIds:["p2","p3","p8","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: Le navire marchand accoste à Colombo la veille du Nouvel An.
@note: Les quais sont un véritable chaos. Des milliers de travailleurs ceylanais transportent des paniers de charbon tandis que des policiers militaires britanniques à casquettes rouges aboient des ordres à une file de réfugiés à l'air abattu.
@p3: Gardez la tête haute, toutes les deux. Nous nous sommes sortis de la mer d'Andaman, vient maintenant le défi de la paperasserie de l'Amirauté.
@p3: Si nous gardons notre sang-froid, nous devrions pouvoir passer les contrôles des papiers sans accroc.
@p12: J'ai l'air de quelque chose que le chat a rapporté, &p3_firstname. Si le [Galle Face](GALLEFACE) me voit comme ça, ils m'enverront directement aux cuisines.
@note: &p2 est émerveillée, agrippant ses perles, les yeux écarquillés par l'immensité de la ville.
@p2: Regardez les soldats, &p12_firstname. Il y en a tellement. Est-ce que ça va aller ?
@note: Alors qu'ils franchissent le hangar des douanes, une voix familière transperce le brouhaha des quais.
@p8: &p12_firstname ! M. SIS ! Petite &p2_firstname ! Doux Jésus, vous avez l'air d'avoir été traînés à l'envers dans une haie.
@note: Ils se retournent pour voir &p8. Elle contraste singulièrement avec leur état pitoyable : elle porte des vêtements tropicaux blancs impeccables, un brassard du Service sur la manche.
@p12: &p8_firstname ! Vous êtes... vous êtes entière ! Je suis si heureuse de vous voir !
@p8: Entière et en service, &p12_firstname. Quand la Marine nous a sortis de cet [enfer de Bornéo](CYNTHIA_JOURNEY), j'ai reçu l'ordre de rejoindre directement le centre de renseignement ici. Je scrute les manifestes depuis six jours en espérant y voir vos noms.
@p8: Imaginez ma surprise en voyant une Mme SIS sur le manifeste.
@p3: C'est... c'est une longue histoire.
@p12: Pas si longue que ça. Il s'est simplement découvert une vocation de mari.
@note: &p12 et &p8 rient de bon cœur tandis que &p3 rougit.
@p3: Bien, bien. On a assez ri, mais j'ai une question urgente à régler. Nous sommes DBS, &p8_firstname, à bord d'un cargo Blue Funnel plein de réfugiés, et nous transportons... une cargaison délicate.
@p8: Vous avez toujours l'échantillon. Je m'en doutais. J'ai une voiture de service qui attend sur le quai. Nous vous ferons passer les gardes portuaires directement jusqu'au Galle Face.
@p2: Mademoiselle &p8_firstname... les avez-vous enterrés ? Ma mère et mon père ? Sont-ils en paix ? Dites-moi que oui, je vous en supplie.
@note: &p8 regarde la jeune fille, son visage s'adoucissant l'espace d'une brève et douloureuse seconde.
@p8: J'ai vu beaucoup de bravoure cette nuit-là, &p2_firstname. Et vous étiez la plus courageuse de tous.
@p8: Nous avons maîtrisé les incendies et j'ai veillé à ce qu'ils soient tous enterrés dignement près de la chapelle. Seuls la pauvre &p7_firstname et M. &p6_lastname étaient trop calcinés pour être inhumés et nous leur avons offert une sépulture en mer.
@p8: Gardez courage ; vous êtes avec nous maintenant.
@note: &p2 enfouit son visage dans la poitrine de &p8.
@p2: Merci, Mademoiselle &p8_firstname.
@note: Plus tard, sur la pelouse du Galle Face. Le soleil se couche en ce réveillon du Nouvel An. La grande pelouse est couverte de tranchées anti-aériennes et de sacs de sable, mais le Galle Face Hotel trône toujours fièrement face à la mer.
@note: Après le luxe d'un bain digne de ce nom, &p2 et &p12 réapparaissent bien mieux dans leur peau. &p8_firstname les a habillées de vêtements magnifiques et de chapeaux de paille.
@p3: Mesdames, vous êtes absolument ravissantes.
@p2: Merci infiniment &p3_firstname. Et à vous aussi, Mademoiselle &p8_firstname.
@p8: Il n'y a pas de quoi, petite lune. C'est tout naturel.
@note: Ils sont assis sur la véranda, quatre survivants, verre de Stengah à la main. L'océan Indien se fracasse contre la digue.
@p8: Les nouvelles sont sombres, SIS. Hong Kong est tombée. Singapour est sous les bombes, comme vous le savez. On appelle cela le Nouvel An le plus noir de l'histoire de l'Empire.
@p3: Raison de plus pour acheminer cet échantillon à Whitehall. Si les Japonais utilisent la Brume Verte dans la mer de Sulu, le bureau de la Guerre doit le savoir avant qu'ils frappent les Indes.
@p12: Pour ce soir, ne peut-on pas oublier qu'on est des agents ? Ne peut-on pas oublier qu'on est des réfugiés ? C'est le réveillon du Nouvel An et nous sommes en sécurité, en bonne compagnie.
@p8: <i>(Levant son verre, un sourire en coin)</i> Bien dit, &p12_firstname. À la Plantation Goodwill. Qu'elle renaisse un jour de ses cendres. Et à la famille &p3_lastname. Vous formez un couple si charmant que vous avez même trompé le Maître Attendant.
@p2: À la nouvelle année. Puisse-t-elle se terminer mieux qu'elle n'a commencé.
@note: Alors que les coups de minuit commencent à résonner depuis les navires dans le port, le black-out reste total. Pas de feux d'artifice, seulement les faisceaux d'un projecteur balayant les eaux sombres, attendant l'inévitable.
`},colombo_9:{personIds:["p2","p3","p8","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: Le lendemain matin, &p8 les conduit dans une arrière-salle du Galle Face Hotel. La pièce est remplie de malles et de caisses, et &p8 déverrouille la première malle.
@p8:  J'ai fait razzier les réserves de l'Amirauté et les apothicaires locaux par mes hommes. Vous entrez dans l'étape la plus périlleuse du voyage et je ne vous laisserai pas arriver à Londres comme des spectres tremblants. Prenez autant que vous en avez besoin.
@p12: <i>(Passant la main sur un tissu épais, couleur fauve)</i> Est-ce... du Burberry ?
@p8: Des imperméables en gabardine pour vous tous. Ce sont des modèles civils, mais doublés de laine polaire. Vous avez vécu dans la chaleur de 90 degrés de Borneo pendant des années, l'Atlantique en février vous semblera comme une gifle en plein visage. Enfilez-les dès que vous passerez le &suez.
@p3: Et les vivres, &p8_firstname ? Le cambuse du cargo commence déjà à empester le lard rance.
@note: &p8 ouvre la caisse suivante, en sortant une boîte en métal argenté.
@p8: Des pastilles de lait malté Horlicks. Les garçons de la RAF les utilisent. J'ai également emballé plusieurs pots de Bovril. Une tasse de bouillon de bœuf chaud fera plus pour votre vigueur qu'une bouteille de gin.
@p2: <i>(Ramassant un petit flacon de verre brun)</i> Qu'est-ce que c'est que ça ? Ça sent... bizarre.
@p8: Des comprimés de hyoscine. La Baie du Bengale n'était qu'un échauffement. La &arabiansea peut être traîtresse à cette époque de l'année. Si l'horizon commence à tanguer, prenez-en un toutes les six heures. Ça vous donnera l'impression d'avoir la bouche remplie de sable du Sahara mais ça maintiendra votre estomac à sa place.
@p3: Et la Quinine ?
@p8: J'ai obtenu un stock frais de Tabloids. De quoi tenir jusqu'à Londres. L'humidité méditerranéenne ramène souvent les frissons du paludisme avec vigueur. Maintenez la dose régulière, &p3_firstname.
@p8: Pour finir, des couvertures en laine de l'armée britannique. Elles sont rêches comme le dos d'un blaireau mais elles sont en pure laine. Enveloppez-vous dedans dès que vous atteindrez les nuits du désert. L'air du désert est trompeusement froid.
@note: &p12 contemple la montagne de matériel.
@p12: Vous nous avez transformés en dépôt de ravitaillement ambulant, &p8_firstname.
@p8: Vous en aurez besoin, &p12_firstname. Les <c>Nips</c> frappent déjà en direction de la Birmanie et les sous-marins sont partout. Vous transportez un paquet important, le moins que le Service puisse faire est de s'assurer que vous ayez un manteau chaud et l'estomac solide quand vous le livrerez.
@p3: Ma seule préoccupation est que cette abondance attirera l'œil de chaque âme désespérée sur ce pont. Nous vous sommes immensément reconnaissants, &p8_firstname, ne vous méprenez pas, mais nous devons avancer avec prudence. Il faudra se faire discrets et essayer d'emballer tout ça dans la plus petite caisse possible.
@p12: Eh bien, je réclame ma part des gabardines et des couvertures. Je n'ai nullement l'intention d'arriver à Londres comme un glaçon humain.
@p2: Et moi, je veux le lait malté et le Bovril !
@p12: Ce qui signifie que tu devras juste te contenter de tout porter pour nous, mon cher mari.
@p3: Je les porterai avec fierté, ma chère. Bien que je suspecte qu'il me faudra plus que du lait malté pour survivre à une virée shopping avec vous deux.`},arabiansea_10:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: &p3 a improvisé une tente à l'aide de deux des couvertures de laine de l'armée britannique drapées sur une vergue de rechange pour faire de l'ombre. &p12 et &p2 sont assises sur les couvertures restantes.
@p12: Faites vite, Monsieur &p3_lastname. J'ai une forte envie d'une tasse de Bovril. Je n'aurais jamais cru voir le jour où un extrait de viande serait le comble du luxe, mais voilà.
@note: &p2 est occupée à glisser un comprimé de Horlicks dans sa bouche et à le croquer avec contentement.
@p2: C'est comme manger un nuage malté, &p12_firstname. J'avais oublié que les choses pouvaient avoir un goût de... enfin, de quelque chose d'autre que du mouton bouilli et du sel.
@p3: Voilà. Thé au Bovril à la &p8_firstname. Il est assez épais pour y faire flotter une pièce, mais il va vous remettre du fer dans le sang.
@note: Alors qu'ils sirotent le bouillon salé, une douzaine de poissons volants jaillissent de l'eau, planant à la surface. L'un d'eux atterrit avec un claquement mouillé sur le plancher de la cabine.
@note: &p2 pousse un cri de surprise, puis éclate d'un fou rire.
@p2: &p3_firstname ! Nous avons un invité surprise pour le thé !
@note: &p3 glousse à la vue du poisson qui se débat frénétiquement.
@p3: Tiens donc ! Avez-vous vos papiers sur vous, petit poisson ? Ou êtes-vous un clandestin sur notre beau navire ?
@note: &p12 se lève d'un bond avec théâtralité et attrape &p2 par les bras.
@p12: Vite, &p2_firstname ! C'est un éclaireur du Roi de la Mer. Nous devons le rendre à son royaume aquatique avant qu'il ne se dessèche !
@note: &p12 et &p2 tendent toutes deux la main vers le poisson glissant, il leur échappe et l'espace d'un moment chaotique, elles poussent toutes deux des cris de rire tandis que le poisson leur file entre les doigts, glissant sur le plancher. Finalement, elles le ramassent ensemble et le rejettent à la mer.
@note: &p2 essuie une larme de rire qui roule sur sa joue.
@p2: Oh, avez-vous vu ses yeux ? Il avait l'air positivement offensé !
@p12: C'est un présage de premier ordre, petite lune. Je ne savais pas qu'un poisson pouvait voler.
@p2: Je l'avais lu dans mes livres d'images. Je n'aurais jamais rêvé d'en avoir un sur les genoux !
@p12: Quand nous arriverons à Londres, je vais vous gâter. Je vous emmènerai chez Selfridges et nous achèterons les chapeaux les plus scandaleux de l'immeuble. Nous aurons l'air de vedettes de cinéma et nous ferons porter toutes les boîtes à la maison par mon cher mari.
@p3: Je les porterai avec fierté, ma chère. Bien que je soupçonne qu'il me faudra plus que du lait malté pour survivre à une virée au magasin avec vous deux.
@note: &p12 plonge la main dans la caisse et en sort l'un des imperméables en gabardine. Elle le drape sur les jambes de &p2 comme une lourde couverture.
@p12: Voilà. Un peu de Burberry pour tenir la fraîcheur du soir à distance. Nous rentrons à la maison avec classe, &p2_firstname. Gardez la tête haute.
@p2: <i>(Se blottissant contre la doublure en polaire)</i> Je la garde haute, &p12_firstname. Vraiment.
        `},arabiansea_11:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: &p3 et &p12 sont montés sur le pont supérieur rejoindre la queue pour l'eau, laissant &p2 seule dans la cabine. Elle est avachie sur la couchette du bas, s'éventant faiblement avec un mouchoir froissé.
@note: Le parfum du thé au Bovril que &p2 a bu plus tôt s'accroche encore à l'air ambiant.
@note: &p2 remarque une ombre sous la porte qui s'y attarde un moment, puis quelqu'un agite la poignée avec insistance.
@p2: &p12_firstname ? &p3_firstname ? C'est vous ?
@note: La porte est poussée d'un coup violent. Deux hommes se tiennent là, l'air menaçant.
@unknown: Là. Je vous le disais. Regardez tout ça ! Des vraies rations.
@note: &p2 pousse un cri, se retranchant contre le mur.
@note: L'un des hommes tente de la calmer.
@unknown: On crève de faim, m'dame. Ma femme n'a rien gardé dans l'estomac depuis trois jours. On veut juste un peu de votre nourriture. Partagez avec nous.
@note: L'autre aperçoit la boîte de Bovril et tend la main vers elle.
@note: &p2 se jette sur la petite caisse.
@p2: Non ! C'est tout ce qu'on a ! &p3_firstname ! &p12_firstname !
@note: L'homme brutal s'avance et arrache violemment les mains de &p2 de la caisse. Il la repousse sur le matelas.
@p2: <i>(Sanglotant)</i> Je vous en supplie... soyez généreux... nous avons tout perdu nous aussi...
@unknown: Vous avez tout perdu, vous dites ? Vous avez une cabine et un père en chemise blanche. On dort dans la crasse près des chaudières. On veut juste notre juste part. C'est notre tour.
@note: Les deux hommes s'enfuient, disparaissant dans le couloir bondé avant même que &p2 puisse crier de nouveau.
@note: Dix minutes plus tard. &p3 et &p12 reviennent, portant une seule carafe d'eau tiède. Ils trouvent la porte de la cabine brisée et &p2 recroquevillée en boule sur le sol, pleurant en silence. &p12 lâche l'eau sous le choc.
@p12: &p2_firstname !
@note: &p3 inspecte la cabine et les alentours à la recherche d'indices.
@p3: Grand Dieu. Que s'est-il passé ?
@p12: &p2_firstname, parlez-moi ! Vous ont-ils blessée ?
@note: &p2 désigne les caisses du geste, étranglée par ses larmes.
@p2: Ils... ils ont tout pris. Le Bovril. Le lait malté. J'ai essayé de les arrêter, &p12_firstname... mais j'étais trop faible.
@p3: Ces vautours sans scrupules. Ils ont dû le sentir à travers les hublots.
@p12: Ce n'est pas que la nourriture, &p3_firstname. Ils l'ont touchée. Sur un navire britannique, sous les couleurs du Roi... Nos propres compatriotes sont en train de nous mettre en pièces.
@p3: Je ne laisserai pas passer ça. Je vais trouver le Maître d'armes. Nous sommes peut-être DBS, mais nous sommes toujours des êtres humains et je vais faire mettre ces misérables aux fers avant le coucher du soleil.
@p12: Du calme. Vous ne ferez qu'envenimer la situation. Nous devons nous faire discrets et tenir notre langue. Cessez donc de parler de bagarre et soyez simplement le père de famille dont j'ai besoin en ce moment et venez consoler &p2_firstname.
@note: &p3 acquiesce et rentre dans la cabine. Il s'agenouille et rejoint &p12 pour prendre &p2 dans leurs bras et la réconforter.
        `},arabiansea_12:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: La chaleur torride des tropiques s'est enfin dissipée, remplacée par un froid mordant qui descend des sables du désert la nuit.
@note: &p3, &p12 et &p2 sont blottis ensemble à l'abri du vent sur le flanc du pont, enveloppés dans les couvertures de laine de l'armée britannique fournies par &p8.
@p12: Je n'aurais jamais cru regretter l'humidité de Borneo, mais ce vent est proprement glacial.
@p2: Je ne sens plus mon nez. Je n'ai jamais eu aussi froid. C'est comme ça, l'Angleterre ?
@p3: Seulement les beaux jours, petite lune. Quand nous atteindrons la Manche, vous trouverez que c'était une promenade d'été.
@note: &p12 donne une grande claque dans le dos de &p3.
@p12: Ne la taquinez pas comme ça. Elle va vous croire et ne voudra plus jamais y aller.
@p3: J'exagère à peine. Il faudra bien qu'elle s'y habitue.
@p2: Je ne pourrais jamais m'habituer à ça. Je porterai de gros manteaux en laine et des couvertures et des chapeaux en permanence. Et d'épais gants en cuir.
@p12: Buvez du thé. Ça vous réchauffera. Je sais que ce n'est pas du Bovril mais ça tiendra le froid à distance.
@p2: Je donnerais un souverain pour l'un de ces laits maltés en ce moment. Rien que pour rendre le thé meilleur.
@p3: Vous savez, il y a une règle que j'ai toujours suivie : ne jamais mettre tous ses œufs dans le même panier.
@p12: &p3_firstname... à quoi jouez-vous ?
@note: &p3 plonge la main dans la poche intérieure de sa veste et en sort son étui à cigarettes Dunhill en argent. Il le fait claquer et à la place des cigarettes, trois disques blanc-crayeux sont nichés contre la doublure en soie.
@p2: Les Horlicks ! &p3_firstname, espèce de coquin ! Vous en avez caché !
@p3: J'en ai glissé quelques-uns dans mon étui dès que &p8_firstname les a distribués. Une petite assurance pour un jour de pluie... ou dans ce cas, une nuit glaciale en mer d'Arabie.
@note: &p12 glisse un comprimé dans sa bouche et le suce tandis que &p2 le croque avec contentement.
@p2: Ça rend le thé presque supportable. Merci, &p3_firstname.
@note: &p3 passe son bras autour d'eux deux, serrant la famille contre le vent.
@p3: Nous nous en sortirons tous. Nous passerons le &suez dans trois jours et nous serons alors à portée de chez nous.
@note: &p2 se blottit contre lui, les yeux qui se ferment.
@p2: Pouvez-vous me parler des trains pour Londres ? Racontez-moi encore le brouillard, les ponts et la grande horloge.
            `},suez_13:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: &p3, &p12 et &p2 sont accoudés au bastingage du pont des embarcations. La vue n'est plus l'infini bleu de l'Océan Indien mais un étroit ruban d'eau qui découpe le désert du Sinaï.
@p12: Seigneur. J'avais complètement oublié que l'air pouvait se sentir ainsi. C'est comme une gifle après des années à être bouillis vivants.
@p3: C'est le désert, Rose. Nous sommes en Égypte maintenant. L'Orient est officiellement derrière nous.
@p2: Regardez ! Il y a des chameaux ! De vrais chameaux ! Je vois des chameaux, &p12_firstname. Vous y croyez !
@note: &p3 remarque un mât rouillé d'un cargo coulé qui dépasse de l'eau peu profonde près de la rive.
@p3: Nous sommes hors de portée des <c>Nips</c>, mais nous sommes maintenant dans l'arrière-cour de Mussolini.
@note: Un petit bateau à fond plat s'approche du cargo Blue Funnel. Un homme en fez grimpe à une échelle de corde. Une foule de réfugiés se rassemble tandis qu'il atteint le pont.
@p2: Qui est-ce ?
@p3: Je suppose que c'est un homme de Gully-Gully. Un artiste. Ils sont courants dans ces parages, ils montent divertir les gens pour quelques sous.
@p12: Les hommes de Gully-Gully ! J'avais entendu les Vieux de la vieille du Club en parler quand j'étais jeune. Je n'aurais jamais cru voir ça de mes propres yeux.
@note: L'homme de Gully-Gully est un magicien qui s'approche de &p2, ses mains se mouvant comme l'éclair. Il tend la main derrière l'oreille de la jeune fille et en sort un minuscule poussin jaune vivant.
@p2: Oh ! Comment a-t-il fait... ? Regardez ! Il est vraiment réel !
@note: &p3 lance une petite pièce d'argent au magicien.
@p3: Bravo, brave homme.
@note: Ils se tiennent tous les trois ensemble, regardant les tours absurdes du magicien tandis que le soleil du désert commence à décliner.
@note: &p3 tend un imperméable en gabardine à &p2.
@p3: Mets ça, petite lune. Il est un peu lourd mais tu m'en remercieras à la nuit tombée.
@p2: Il est si lourd. Je me sens comme un soldat.
@note: &p12 et &p3 enfilent leurs propres imperméables.
@p12: Voyez, nous sommes tous des soldats maintenant, &p2_firstname.
@p12: Ce style vous va bien, &p3_firstname.
@note: &p3 tend la main et ajuste son col, son geste s'attardant une seconde.
@p3: Nous aurons la &mediterranean à affronter ensuite. Ça risque de se corser quand nous nous rapprocherons des <c>Huns</c> et des Italiens.
        `},mediterranean_14:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: &p3, &p12 et &p2 sont blottis sur le pont, leurs cols Burberry relevés contre les embruns. Le cargo Blue Funnel fait maintenant partie d'un petit convoi, flanqué de deux vieux destroyers de classe V.
@p12: L'atmosphère sur ce navire a changé très rapidement. Même les stewards ont l'air d'attendre une sentence de mort.
@p3: Ils ont de bonnes raisons. J'ai eu un mot avec un officier des transmissions près de la salle sans fil. Marseille est effectivement un port boche maintenant et le gouvernement français réfugié à Vichy joue un double jeu, aidant les nazis à traquer les dernières forces françaises libres. On ne peut pas leur faire confiance. Notre seul sanctuaire est le Rocher, &gibraltar.
@p2: &gibraltar ? C'est loin ?
@p3: Mille miles d'un champ de tir à découvert, &p2_firstname. Nous devons passer entre la Sicile et la Tunisie. Les Italiens ont leurs sous-marins qui rôdent dans les eaux et la Luftwaffe peut nous atteindre depuis les aérodromes du nord en moins de trente minutes.
@p12: Alors, de l'armée japonaise à Borneo aux nazis en mer Méditerranée. Est-ce que affronter des défis mortels est simplement en train de devenir notre quotidien, &p3_firstname ?
@p3: Je sais que j'ai dit ça d'innombrables fois au cours de notre périple, mais c'est vraiment la partie la plus dangereuse. Les <c>Huns</c> sont désespérés de couper l'artère vitale du Suez. Chaque navire qui coule par le fond est une victoire pour Jerry. Nous naviguerons en zigzag permanent de là jusqu'à l'Atlantique.
@note: &p2 regarde le destroyer d'escorte avec inquiétude.
@p2: Ce petit bateau peut-il vraiment arrêter un bombardier ?
@p3: Je n'ai pas grande foi en nos escortes. On n'aurait pas pu nous fournir des reliques plus vieilles si on l'avait voulu.
@p12: Eh bien, j'ai déjà survécu à un débarquement japonais, à un bombardement aérien et à des semaines passées dans une minuscule boîte de sardines avec vous et &p2_firstname. Je n'ai aucune envie d'être interrompue par une torpille italienne.
@p3: Je vous le promets : vous et &p2_firstname serez dans la première chaloupe mise à la mer si nous sommes touchés. Je vous amènerai au Rocher dût-il me falloir nager toute la distance moi-même.
@note: &p12 se penche et lui embrasse la joue.
@p12: Ne jouez pas au martyr. Ce n'est pas le mari que j'ai appris à connaître.
@note: Une sirène retentit du destroyer de tête. C'est le signal de changer de cap. Le cargo entame son premier virage en zigzag vers le cœur de la mer Méditerranée.
        `},mediterranean_15:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: Haut dans le ciel du nord, trois points argentés émergent de l'éblouissement du soleil. Le navire bascule dans le chaos. Le gong d'urgence retentit sans cesse. &p3, &p12 et &p2 sont projetés contre la paroi alors que leur navire effectue un virage serré.
@p3: Des [Stukas](STUKAS) ! Gagnez le centre du pont. Restez loin des vitres !
@note: Une seconde plus tard, une déflagration secoue le navire. Une bombe a touché la grue avant. L'énorme structure s'effondre, détruisant une partie du pont.
@note: Les destroyers d'escorte font feu de toutes leurs pièces. L'un des avions se désintègre en plein vol. Un second Junker, l'aile rognée, part en vrille et percute durement la mer.
@note: L'attaque ne dure que quelques minutes. Le dernier avion nazi fuit vers le nord, poursuivi par les obus des destroyers. Le pont est jonché de réfugiés blessés, fauchés par la grue effondrée.
@note: &p3 et &p12 sortent de derrière leur abri pour évaluer l'étendue des dégâts. Des marins courent dans tous les sens en aboyant des ordres.
@p3: &p12_firstname, aidez à aller chercher les bacs à sable !
@note: &p12 jette son manteau et retrousse ses manches.
@p12: À vos ordres !
@note: &p3 et &p12 plongent tête baissée dans la mêlée. Ils rejoignent une équipe de lutte contre l'incendie composée de marins et de réfugiés. Tandis que &p3 s'affaire à colmater une voie d'eau, &p12 s'active durement, passant de lourds bacs de sable pour étouffer les flammes.
@note: Dans la cambuse transformée en poste de secours improvisé, &p2 est à genoux, sa robe fleurie ruinée, déchirant de longues bandes de lin blanc arrachées à une nappe de récupération pour en faire des pansements.
@note: Elle passe les bandes à un chirurgien du navire qui soigne les marins blessés. Lune détourne le regard du sang, pas encore tout à fait prête pour ça.
@note: &p12 entre dans la cambuse.
@p12: &p2_firstname ? Ah, vous voilà. Dieu merci. Vous n'êtes pas blessée. Nous ne vous trouvions plus.
@p2: <i>(Sans lever les yeux)</i> J'aide, &p12_firstname. Il n'y a pas assez de charpie. J'ai déjà utilisé toutes les nappes que j'ai pu trouver. Je commence à m'attaquer aux serviettes maintenant.
@note: &p12 attrape une paire de ciseaux sur une table voisine et rejoint Lune sur le sol.
@p12: Tenez. Donnez-moi l'autre bout. Nous allons dépouiller la salle entière s'il le faut.
@note: &p3 entre, couvert de suie et de sueur. Il voit les deux femmes, ses yeux reflétant un profond sentiment de fierté et de respect.
@p3: Je vais vous chercher du thé, mesdemoiselles.
        `},gibraltar_16:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: Après la terreur de la Méditerranée, la vue de Gibraltar ressemble au premier vrai sanctuaire en Europe où ils peuvent enfin baisser la garde.
@note: Grâce aux relations de &p8, la famille n'est pas envoyée dans les camps de réfugiés bondés du champ de courses. Au lieu de cela, ils sont logés dans un appartement réquisitionné dans la vieille ville.
@note: La maison est petite et ne compte que deux pièces, mais c'est bien suffisant pour eux trois. Un petit feu de charbon illumine la pièce. &p2 dort déjà dans l'annexe, épuisée par le voyage. &p3 et &p12 sont assis devant le feu.
@note: &p12 tend les mains vers la chaleur.
@p12: Je suis sûre que je n'aurai jamais plus chaud, &p3_firstname. Ce satané rocher est un frigidaire.
@p3: C'est l'air de l'Atlantique, &p12_firstname. Il est purifiant.
@note: Ils restent assis dans un silence embarrassé un moment.
@p12:<i>(Furtivement)</i> Nous avons passé la Méditerranée. Le Secrétariat ne nous surveille pas ici. Nous pourrions... nous pourrions arrêter tout ce manège conjugal, si vous le souhaitez. Vous pouvez enlever l'alliance.
@p3: Est-ce ce que vous voulez, &p12_firstname ?
@note: &p12 fixe simplement le feu, pensive.
@p12: Je crois que j'ai perdu le fil, &p3_firstname. J'ai passé des années à Borneo à jouer la Mem ennuyée, puis des semaines sur cette coque rouillée à jouer votre femme dévouée. Je ne suis vraiment plus sûre de qui je suis ni de ce que je ressens.
@p3: Je vais vous dire qui est là. Une femme qui a plus de cran que quiconque j'aie jamais rencontré. Une femme qui a gardé son élégance pendant que le monde brûlait. Une femme que j'admire profondément et sincèrement... Plus qu'admire.
@p3: Je vous ai dit dans la Baie du Bengale que je ne voulais pas franchir la barre seul. Ce n'était pas du jeu à ce moment-là, &p12_firstname. Je ne joue plus depuis longtemps.
@note: &p12 se retourne dans son fauteuil pour lui faire face, ses yeux scrutant les siens.
@p12: Êtes-vous vraiment épris de moi, ou n'est-ce que la fièvre de l'évasion ?
@note: &p3 lui prend la main, son pouce traçant le contour de l'alliance qu'il lui a offerte à Singapour.
@p3: Ce n'est pas la fièvre. Je vous porte dans mon cœur depuis un bon moment maintenant. Je ne veux plus être votre « promis » sur les manifestes, &p12_firstname. Je veux être votre mari quand nous arriverons à &arrival. Pour de vrai.
@p12: Espèce d'idiot. Vous pourriez avoir n'importe quelle femme bien. Pourquoi une veuve de planteur brisée ?
@note: &p3 se penche pour l'embrasser. &p12 répond de même, ses mains trouvant sa poitrine nue sous son pull.
@note: Il l'emmène vers le petit lit dans le coin. Dehors, un projecteur balaie la fenêtre, les illuminant une seconde avant de replonger la pièce dans l'ambre chaud et intime du feu.
        `},arrival_17:{personIds:["p2","p3","p12"],objects:[{id:"sample",heldBy:"p3"}],clue:`@note: L'arrivée n'est pas le retour triomphal qu'ils avaient imaginé lors de ces nuits étouffantes dans le détroit de Malacca. Londres est un monde de gris cendré et de charbon. Le rivage est jonché d'entrepôts détruits et de cratères de bombes.
@p12: Seigneur. Qu'ont-ils fait à la ville ?
@note: L'un des marins avec qui ils ont sympathisé au cours du voyage fume une cigarette à côté d'eux.
@unknown: Ça fait dix-huit mois de bombardements incessants, Madame &p3_lastname.
@p2: C'est si calme. Si mortellement calme.
@note: Ils descendent la passerelle vers le hangar des douanes de Tilbury. Ils voient des femmes en salopette et grosses bottines, transportant des caisses.
@note: Au bureau de traitement, un fonctionnaire portant un brassard de défense civile lève à peine les yeux en inspectant leurs faux papiers.
@unknown: DBS de l'Est, hein ? Vous êtes les derniers des chanceux. Singapour est pratiquement dans la poche des <c>Nips</c>.
@unknown: Voici vos livrets de rations d'urgence. Vous avez des coupons pour quatorze jours. Utilisez-les prudemment.
@note: Il fait glisser trois petits carnets en papier sur le bureau puis tamponne leurs papiers.
@unknown: Circulez.
@note: &p2 ramasse son livret de rations, regardant les coupons pour divers produits.
@p2: Qu'est-ce que ça veut dire ?
@note: &p3 prend les carnets et les glisse dans son manteau.
@p3: Ça veut dire que nous ne sommes pas encore tirés d'affaire, &p2_firstname.
@note: Ils sortent des docks pour prendre le train vers le centre de Londres.
@note: Alors que le train s'éloigne, ils traversent l'East End. Des rues entières ont été rasées. Des gens font la queue sous la pluie pour un seul pain, leurs boîtes à masque à gaz en bandoulière.
@p12: Nous avons fui un cimetière pour atterrir dans un autre. Ils ont l'air si... brisés.
@p3: Nous remettons la fiole à Whitehall ce soir. Ensuite nous trouverons un hôtel avec une cave et demain... demain nous commencerons notre nouvelle vie ensemble.
@note: Il lui saisit la main fermement. Elle y pose instinctivement son autre main.
@note: &p2 appuie sa tête contre la vitre, caressant ses perles tout en regardant des [Ballons de barrage](BARRAGE_BALLOONS) haut dans le ciel.
@p2: Le Blighty, &p3_firstname. Ce n'est pas comme dans vos histoires.
@note: L'énergie psychique s'intensifie et toute la tapisserie de leur vie commune s'ouvre soudain à moi.
@note: Je vois &p2, non plus la petite demoiselle heureuse que les circonstances avaient brisée, s'épanouir en une femme d'une remarquable ténacité et indépendance.
@note: Je vois &p3 et &p12, pleinement amoureux et dévoués l'un à l'autre.
@note: Je les vois là où ils ont trouvé refuge à &london, dans une modeste maison en terrasse.
@note: Ils sont heureux.
        `},london_18:{personIds:["p2","p3","p12"],objects:[],unlocks:["p15"],clue:`@note: Pour les trois survivants de la plantation de Goodwill, les quatre années écoulées depuis leur arrivée en Angleterre avaient été une lente et pénible ascension. Ils avaient vécu dans une seule pièce à Bayswater durant les pires raids de bombes volantes V, survivant aux œufs en poudre. Mais ils avaient tenu ensemble.
@note: &p12 est assise à la petite table de la salle à manger, une montagne de cahiers d'exercices devant elle. Elle est maintenant institutrice dans une école primaire locale. Elle est là à corriger des devoirs.
@p12: Vraiment, je voudrais bien que ces garçons consacrent autant de temps à leurs divisions qu'ils en passent à rêver de piloter des Spitfires.
@note: &p2 entre de la cuisine, s'essuyant les mains sur un tablier. Elle a vingt et un ans maintenant, son visage n'est plus hâve par le paludisme mais celui d'une femme qui a géré quatre années de coupons de rationnement et d'obscurcissement.
@p2: Laissez-les tranquilles, &p12_firstname. Ils sont juste contents de pouvoir courir dehors sans crainte. J'ai réussi à obtenir de la graisse de rognon chez le boucher. J'ai pensé tenter ma chance avec un spotted dick pour le thé.
@p12: Vous êtes une véritable magicienne, &p2_firstname. Je ne sais pas comment nous aurions survécu toutes ces années sans votre fourneau.
@note: La porte d'entrée s'ouvre et &p3 entre. Il paraît plus vieux et plus mûr. Durant la seconde moitié de la guerre, il avait travaillé secrètement pour le MI6 afin d'intercepter et de neutraliser des saboteurs tentant de frapper les docks londoniens.
@note: Il marque une pause dans l'embrasure, son chapeau à la main. &p12 lève les yeux, son sourire se fige. Elle reconnaît l'expression froide et sévère sur son visage.
@p3: &p2_firstname. Venez dans le salon, voulez-vous ?
@p2: Vous avez des nouvelles. Du Bureau de la Guerre. Je le sens.
@note: &p3 plonge la main dans sa poche intérieure et tend à &p2 une enveloppe d'allure officielle.
@p3: J'ai passé dix-huit mois à suivre sa trace. Je vous avais promis sur ce bateau, il y a quatre ans, que je vous le livrerais.
@p3: Je l'ai trouvé, petite lune. Ou du moins... j'ai découvert ce qui lui est arrivé.
@p2: Dites-moi. Dites-le-moi franchement.
@p3: Il est cité à l'ordre du jour, &p2_firstname. C'était un homme de trempe. Il a combattu sur le continent jusqu'à la toute fin.
@note: Un lourd silence tombe sur la pièce. &p2 ne crie pas et ne pleure pas, elle ferme simplement les yeux, la tête s'inclinant. &p12 passe son bras autour d'elle.
@p12: Oh, ma chérie. Je suis tellement, tellement désolée.
@note: &p12 caresse le rang de perles, celles que &p3 lui a offertes à Singapour, qu'elle porte toujours chaque jour.
@p2: Il est cité à l'ordre du jour, avez-vous dit ?
@p3: En effet. Il est mort face à l'ennemi, &p2_firstname. Il a honoré le nom de Goodwill.
@note: &p2 essuie une seule larme de sa joue avec le coin de son tablier.
@p2: Alors... alors nous aurons quand même ce pouding au suet. Nous le mangerons en son honneur. Parce qu'il aurait donné un souverain pour un bon dessert, n'est-ce pas ?
@p3: Je crois bien que oui, petite lune. Je crois bien que oui.
@p12: Nous sommes toujours une famille, &p2_firstname. La famille &p3_lastname. Nous avons survécu à la jungle, aux mers et au <c>Hun</c>. Nous survivrons à ça aussi. Courage, mon amour.
@p2: Courage.
        `},london_19:{personIds:["p2","p3","p12","p15"],objects:[],clue:`

        `},plantation_0:{personIds:["p8","p16","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"photo2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`
@note: Elle s'approche d'un &p19_title qui monte la garde.
@p8: Le &p16_title est-il au &commandpost ?
@note: Le soldat acquiesce et &p8 entre dans le &commandpost construit à la hâte dans la plantation de Goodwill.
@p16: Bonsoir &p8_firstname. J'évalue la situation actuelle, veuillez vous asseoir.
@p8: Nous avons fait ce que nous pouvions ici, mon commandant. Les incendies sont éteints et les morts ont été mis en terre. Mais nous savons tous les deux que les <c>Nips</c> ne font que se regrouper dans les mangroves. Ils reviendront bientôt et avec du matériel plus lourd.
@p16: Précisément. La marine est très dispersée. Je ramène mes hommes aux navires pour protéger la côte. La brume verte se déplace vers l'ouest, nous devrions pouvoir l'éviter. Nous ne pouvons pas tenir cette position longtemps.
@p8: Je comprends. C'est pourquoi je dois solliciter votre indulgence. Je dois partir pour [Sandakan](SANDAKAN) immédiatement. Mon promis s'y trouve. Je devais le retrouver après cette mission.
@p16: <i>(L'observant longuement, puis hochant lentement la tête)</i> Tout à fait. Votre promis. Vous n'avez pas à me donner vos raisons mais ne me prenez pas pour un imbécile. Je ne peux pas détacher un peloton, mais je peux vous confier un groupe d'éclaireurs.
@p8: Je souhaiterais vivement emmener &p17_lastname et ses hommes. Ils se sont montrés utiles aujourd'hui et semblent avoir les aptitudes requises pour cette traversée de la jungle.
@p16: J'ai effectivement une mission pour laquelle ils seraient bien adaptés et qui répondrait également à vos besoins. Faire d'une pierre deux coups, en quelque sorte. Ils feront office d'escorte et de piquet d'alerte avancée. S'ils repèrent des patrouilles japonaises se déplaçant à travers la forêt primaire, ils doivent faire demi-tour et signaler.
@p8: Et leurs ordres une fois arrivés à la capitale ?
@p16: Ils doivent se regrouper avec le Gouverneur à Government House. Ils peuvent porter mes dépêches, toutes les informations sur les mouvements de la Marine et la nécessité d'une évacuation immédiate.
@p8: Je vous suis très obligée, Commandant.
@p8: Juste... Une dernière chose.
@p16: Dites.
@p8: Qui est arrivé tout à l'heure ? Je les ai vus arriver en locomotive à vapeur quand j'étais près de la &jungle.
@p16: Je ne vois pas de quoi vous parlez.
@p8: J'aurais juré vous avoir vu aller les accueillir quand je redescendais... J'ai dû me tromper.
@p16: Bonne chance, &p8_firstname.
@note: Alors que &p8 sort, &p16 lève les yeux :
@p16: Dites bonjour à &p20_firstname de ma part.
@note: &p8 s'arrête net, se retourne et sort une &photo2 de sa poche. Elle la regarde un instant, puis la tend à &p16.
@p8: C'est &p20_firstname il y a quelques semaines. Gardez-la.
@note: Le groupe se rassemble au bord de la plantation, là où l'ancienne pelouse de croquet soignée rencontre le mur vert de la jungle.
@note: &p8 sort de la buanderie où elle a récupéré la &pearl2 et ses affaires.
@note: &p17 teste le tranchant de son parang tandis que &p18 finit de préparer son sac à dos.
@p17: Bien, Mademoiselle. La marche jusqu'à [Sandakan](SANDAKAN) est une affaire pénible par ce temps. La boue est à mi-jambe et les sangsues abondent. Restez dans mes pas et gardez les yeux sur la canopée.
@p18: Ne vous inquiétez pas, Mademoiselle. Nous vous ferons prendre un [Gin Pahit](GIN_PAHITS) au [Club de Sandakan](SANDAKAN) avant que vous puissiez dire « ouf ».
@p19: Combien de temps cela prendra-t-il ? [Sandakan](SANDAKAN) semble si loin.
@p17: En temps normal, on pourrait y marcher en 2 jours, mais nous devons avancer prudemment et éviter les routes principales, donc ça pourrait prendre jusqu'à 5 jours, mais idéalement 4 jours si Dieu le veut.
@p8: En marche, messieurs. J'ai un rendez-vous en ville et je n'ai pas l'intention de le faire attendre.
@p17: Nous commencerons par descendre directement le sentier et nous établirons le camp à l'extrémité de la piste. Nous serons en sécurité là cette nuit et ça nous donnera un bon départ pour traverser le &ulu demain matin.
@note: Guidé par &p17, le petit groupe plonge dans la forêt. L'humidité les engloutit instantanément, les sons de la plantation s'estompant au loin mais des détonations sourdes et inquiétantes résonnent depuis la direction où ils se dirigent.
@note: Ils atteignent l'extrémité de la piste forestière, &p17 fait signe de s'arrêter dans une clairière au milieu des buissons.
@note: Ils laissent tomber leurs lourds sacs avec un grognement.
@p17: Bien. Nous établissons le camp ici. &p18_lastname, montez les tapis de sol. &p19_firstname, allez chercher du bois sec. Je veux une flamme petite et sans fumée.
@note: &p8 cueille quelques lianes avec un parang.
@p8: Quel est le tableau de garde, &p17_title ?
@p17: Des relèves de deux heures. &p18_lastname, vous avez la première garde. &p19_lastname, vous prenez la garde du mort de deux heures à quatre heures. &p8_firstname, je prendrai l'heure du Tigre avant l'aube.
@p8: <i>(L'interrompant)</i> Je prendrai de minuit à deux heures. Je suis aussi capable de manier un fusil que n'importe quel marin. Ne vous laissez pas tromper par les jupes que je portais tout à l'heure.
@p17: Vous êtes bien plus qu'une avocate, ça c'est sûr.
@p8: MI5. J'essaie de ne pas le crier sur les toits. Secret professionnel et tout ça. Mais vu que nous allons devoir compter les uns sur les autres pour survivre, je vous dois la courtoisie de la vérité.
@p17: Je vous en suis reconnaissant. Je me doutais que c'était quelque chose du genre.
@note: Une heure plus tard, ils se rassemblent autour d'un tout petit feu protégé. Une petite boîte de Horlicks chauffe sur une lampe à alcool.
@p19: Je propose qu'on se raconte des histoires. Pour garder le moral. Je pensais... à vos histoires, &p17_title. À l'affaire de Rundum en '15. Vous étiez vraiment là, Sergent ? À poursuivre des fantômes dans la boue ?
@p17: Oui, j'y étais. Le soulèvement a escaladé si rapidement. C'était le symbole des tensions plus larges et de la résistance au régime colonial.
@p18: J'ai vu Antanum, vous savez. De mes propres yeux.
@p19: C'est quoi, ça ?
@p18: Pas quoi, qui. C'était le plus grand guerrier qui ait jamais vécu. Si légendaire qu'on lui prêtait des pouvoirs surnaturels. Il a mené la rébellion.
@p8: Il devait être quelqu'un d'exceptionnel.
@p18: Je l'ai regardé brûler. Il a brûlé comme n'importe quel autre homme. Il a crié comme n'importe quel autre homme aussi. Les pouvoirs surnaturels, ça n'existe pas.
@note: Les cigales commencent à chanter, signalant à &p17 qu'il est temps d'éteindre le feu.
@p17: L'heure de la veille.
@p19: C'est quoi ça ?
@p17: Le moment juste avant le coucher du soleil et juste avant l'aube sont les plus dangereux pour tout campement dans la jungle. La veille est une règle sacrée. Les ombres changeantes à cette heure rendent difficile d'apercevoir quoi que ce soit. Nous gardons un silence de mort et les armes prêtes à la baïonnette pendant les 30 prochaines minutes, les yeux fixés sur la lisière.
@p18: Écoutez les cigales. Si vous cessez de les entendre, c'est que quelque chose de gros est à l'affût.
@note: Ils restent tous silencieux un moment puis, quand le soleil est complètement couché, &p17 rompt le silence.
@p17: Bien, &p19_firstname, allez au périmètre. Gardez les oreilles ouvertes. Si quelque chose de plus grand qu'une souris bouge, donnez-nous un coup de sifflet.

        `},ulu_1:{personIds:["p8","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: &p8 monte la garde à 3 heures du matin, mâchant une racine de réglisse, le regard fixé sur la lueur orangée de la destruction qui se produit à des kilomètres d'eux.
@note: &p18 et &p19 dorment profondément.
@note: &p17 lui tape sur l'épaule.
@p17: Allez vous reposer, j'assure la relève.
@p8: Je ne suis pas fatiguée. Je vais allumer un petit feu. Vous voulez une tasse ?
@p17: Ce serait parfait.
@note: &p8 met l'eau à bouillir.
@p17: Alors qu'est-ce qu'un agent du MI5 fait dans ce coin de jungle ?
@p8: C'est justement ce que j'aurais voulu savoir. Tout semblait si simple mais tout est parti à vau-l'eau quand les <c>Nips</c> ont débarqué et maintenant que je suis si loin des miens, ça ne semble plus en valoir la peine.
@p17: Je crois que c'est ce que tout le monde ressent à propos de cette foutue guerre.
@p8: La tasse est prête.
@note: Ils restent assis en silence quelques heures puis les autres se réveillent et ils démontent le camp, descendant vers le cœur de la jungle.
        `},ulu_2:{personIds:["p8","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`
@note: La journée est un poids lourd et humide. Le groupe avance en file indienne, seul le cliquetis du [parang](PARANG) de &p17 se fait entendre tandis qu'il taille les lianes et les feuilles pour se frayer un chemin. La forêt sauvage est un labyrinthe de végétation et de fougères préhistoriques, où la lumière est filtrée dans un vert profond et sombre.
@note:&p19 est collé directement derrière &p8. Il n'a pas arrêté de parler depuis qu'ils ont passé la clôture de la plantation.
@p19: "...et mon père disait toujours, &p19_firstname, il disait, si un mouton peut passer la tête dans une brèche, le reste suit qu'on le veuille ou non. C'est un peu pareil avec ces lianes, Mademoiselle &p8_lastname, vous ne trouvez pas ? On en attrape une sous la botte et toute la jungle essaie de vous tirer en arrière. C'est pas comme les Dales, remarquez. Chez nous, on voit un nuage de pluie arriver de cinq kilomètres. Bien qu'ici, un nuage de pluie ne soit jamais à plus d'un mètre dans n'importe quelle direction. Ici, c'est juste... enfin, c'est comme marcher dans une éponge chaude, non ?"
@p18: <i>(Sans se retourner, sa voix portant)</i> Cuicui. Ferme-la. Tu fais assez de bruit pour réveiller tous les serpents d'ici jusqu'à la côte.
@p19: Désolé, &p18_title. J'observe, c'est tout. C'est vraiment extraordinaire. Ma mère ferait une crise si elle voyait la taille des araignées ici. Elle trouve celles de la grange monstrueuses, mais celles-ci. Sergent, vous vous rappelez quand Paulie voulait mettre sa botte et qu'elle était trop serrée, alors il l'a mise devant sa figure pour bien regarder et cette énorme araignée lui a sauté dessus directement. Il a hurlé comme une fille. Absolument hilarant.
@note: Soudain, un fracas violent éclate dans la canopée juste au-dessus d'eux. Des branches cassent comme des coups de pistolet. &p19 pousse un cri aigu, trébuche en arrière et manque de renverser &p8 en essayant d'épauler son fusil.
@p19: Les <c>Nips</c> ! Dans les arbres ! Ils descendent !
@p17: Ne tirez pas, espèce d'idiot !
@note: Un grand singe s'élance dans leur champ de vision, son nez frémissant tandis qu'il pousse un petit cri et disparaît dans les branches plus hautes.
@p18: Vous disiez quoi à propos de Paulie ? À moins que ce singe soit un espion japonais, je crois qu'on est tranquilles pour l'instant. Vous avez failli loger une balle dans les fesses du Sergent.
@p17: Seigneur, donnez-moi la force. Je suis &p17_title dans les Royal Marines, pas une putain de nounou. Je devrais aider &p16_lastname à défendre l'Empire et à la place, je trotte dans l'Ulu avec un blanc-bec qui a peur de son ombre.
`},ulu_3:{personIds:["p8","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`
@note: Au crépuscule, ils trouvent refuge dans une grotte de calcaire peu profonde perchée sur une crête. Elle est humide et sent le guano de chauve-souris, mais elle offre une vue sur les basses terres qui s'étendent vers la côte lointaine.
@note: Alors que la lumière baisse, une série de détonations sourdes se font entendre faiblement depuis le nord. Là où [Sandakan](SANDAKAN) se trouve, le ciel commence à pulser d'orange. De sombres panaches de fumée, à peine visibles dans le crépuscule, s'élèvent à l'horizon. &p19 fixe le spectacle d'un mélange de stupeur et d'effroi.
@p19: Sergent ? Ces... ce ne sont pas des feux d'artifice, n'est-ce pas ?
@p17: <i>(Allumant une seule cigarette protégée, les yeux durs)</i> Non, fiston.
@p8: Ce sont les entrepôts de pétrole du port. Et cette lueur... c'est la ville en flammes.
@p19: Ils ne prendront pas Singapour, n'est-ce pas Sergent ? Mon père disait que Singapour était une forteresse... Il disait qu'on serait rentrés au printemps.
@p18: Rentré au printemps ? Cuicui, ton père a trop lu les journaux.
@p17: &p19_lastname, allumez la lampe à alcool et prenez de la nourriture dans le sac. Nous avons une longue marche demain et je ne veux pas vous voir vous évanouir parce que vous avez raté votre thé.
@note: &p8 s'assoit à l'entrée de la grotte, regardant les feux lointains de sa destination.
@note: &p18 s'approche et pose une couverture sur ses épaules.
@p18: Venez manger. Nous avons une longue journée devant nous. Si vous avez trouvé la forêt difficile. Attendez qu'on atteigne le &nipa demain.
@p17: &p18, je prendrai la garde du mort. Demain c'est ton jour de gloire, on a besoin de toi frais et alerte.
@p19: Qu'est-ce que ça veut dire, Sergent ? &p18_title, qu'est-ce qu'il veut dire ?
@note: &p18 imite la gueule d'un crocodile qui claque avec ses bras.
@p18: C'est ça qu'il veut dire. Faites attention à vos pieds demain.`},ulu_4:{personIds:["p8","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: &p18 est le premier à sortir de son sac de couchage ce matin-là, il n'a pas très bien dormi sachant qu'il devra mener la charge.
@note: &p19 fume une cigarette en scrutant le ciel alors que de la suie noire continue de pleuvoir sur eux. Il tire la langue.
@p19: À votre avis, ça a quel goût ? C'est dangereux si j'en avale trop ? Est-ce que mes entrailles vont se transformer en charbon ?
@p18: Il est trop tôt pour vos bêtises. Vous n'avez pas encore mis une casserole d'eau à chauffer ?
@p19: Je ne pouvais pas assurer la garde et aller chercher du petit bois. C'est l'un ou l'autre.
@p18: On est dans la jungle, espèce d'idiot ! Vous êtes entouré d'arbres ! Si vous ne trouvez pas un bout de bois sec, je vais vous enfoncer le canon de mon fusil dans votre...
@note: &p8 se lève, secouant l'humidité de son imperméable en gabardine. Elle commence à lacer ses bottines.
@p8: Je vais chercher du petit bois. Continuez à vous chamailler, messieurs. C'est une excellente façon de signaler aux <c>Nips</c> exactement où nous trouver.
        `},nipa_5:{personIds:["p8","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: Le groupe a de l'eau jusqu'à la taille. La boue en dessous colle comme de la graisse. &p17 ouvre la voie, ses yeux scrutant constamment les berges boueuses.
@p17: Attention où vous mettez les pieds. Et pour l'amour du ciel, gardez vos canons hors de la vase. Si vous bouchez le canon et tirez, le fusil vous explodera au visage.
@note: &p19 peine à extraire ses jambes du limon.
@p19: C'est comme marcher dans de la mélasse, Sergent ! Sauf que la mélasse ne sent pas comme un égout bouché.
@p18: Attention, Cuicui. Vous éclaboussez comme une baleine échouée.
@note: &p18 lève la main.
@p18: Immobile. Personne ne bouge d'un muscle.
@note: &p8 se fige, sa main trouvant instinctivement la crosse de son revolver. À dix pieds sur leur gauche, une piste de boue aplatie s'incurve vers l'eau indiquant une toute fraîche coulée de crocodile. Les roseaux tremblent encore.
@p18: Un grand. Douze pieds au moins. Il est quelque part dans le chenal. Si vous sentez un tronc heurter votre jambe, ne criez pas. Priez juste que le Tout-Puissant aime les éleveurs de moutons.
@p19: Je prie. Je prie très fort.
@note: &p19 tente un large pas prudent autour d'un bouquet de racines de mangrove. Il se penche trop loin et sa jambe gauche s'enfonce dans un trou profond. Un gluant gargouillis se fait entendre tandis que la boue engloutit son membre.
@p19: Aïe ! Je suis coincé ! &p18_title, aidez-moi !
@note: &p18 commence à tirer le gamin.
@p18: Tirez, Cuicui ! Poussez !
@note: &p19 s'élance vers le haut avec un grognement désespéré. Il se libère, mais son pied gauche ressort recouvert d'une boue noire puante. Sa botte réglementaire reste enterrée à un mètre de profondeur, perdue dans les marais pour toujours.
@p19: Ma botte ! Sergent, la foutue boue a bouffé ma botte !
@p17: Ça ne fait même pas 2 jours et les forces impériales sont déjà à une chaussure. &p18_lastname, donnez-lui un coup de main. On ne peut pas s'arrêter pour la déterrer.
@note: Alors qu'ils négocient un méandre dans l'étroit chenal, un petit [sampan](SAMPAN) émerge de la berge. Il est piloté par un homme du cru.
@note: L'embarcation est dangereusement basse sur l'eau, chargée à ras bord de meubles et d'une chèvre terrifiée. Deux petits enfants sont assis au sommet de la pile, regardant d'un air interrogateur.
@p8: Tabek. Où allez-vous, Pak ? À la ville ?
@note: L'homme du cru interrompt sa pagaie, regardant les soldats britanniques crottés et la dame aux bottines boueuses. Il secoue lentement la tête.
@unknown: Non, Mem. Pas en ville. Nous allons vers les petites rivières, nous cacher un moment.
@p17: Il a bien raison. Il emmène sa famille à l'intérieur des terres avant que les <c>Nips</c> ne puissent les attraper. Notre temps est révolu, &p8_firstname. Même les autochtones le sentent.
@note: L'homme offre un hochement de tête respectueux et pagaie silencieusement devant eux, disparaissant dans le labyrinthe de racines.
@p19: Est-ce que ça veut dire que le [Club de Sandakan](SANDAKAN) ne sera pas ouvert ? J'avais toujours voulu y aller.
@p18: Je suppose que la nouvelle direction servira du Saké quand nous y arriverons, Cuicui. Maintenant essaie de garder ton pied au sec et continue d'avancer.
        `},nipa_6:{personIds:["p8","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: Alors que le soleil commence à décliner à l'horizon, projetant de longues ombres sur l'eau, le groupe se hisse finalement sur la terre ferme.
@note: Chaque centimètre de leur kaki est plâtré d'une épaisse couche de boue. &p19 est dans le pire état, boitillant sur son chemin.
@note: &p17 fait signe de s'arrêter sous les racines d'un arbre géant. Ils entendent le premier bourdonnement des cigales de six heures. &p18 lâche son lourd sac à dos.
@p18: Bien. Enlevez vos chaussettes, fiston. Je vais vous débarrasser de ces sales sangsues.
@p19: Je les sens, &p18_title. C'est comme des douzaines de vers qui se tortillent dans ma jambe. C'est vraiment répugnant.
@note: &p18 commence à arracher soigneusement les vers à crochets qui se tortillent.
@p18: Regardez la taille de celui-là. Ce pourrait être un repas entier. On dirait une grosse saucisse.
@p8: Utilisez le sel. N'arrachez pas ça, c'est trop enfoncé. Vous lui causerez un ulcère tropical d'ici le matin qui lui rongera jusqu'à l'os.
@p19: J'ai perdu ma botte, mes chaussettes sont en lambeaux et je suis dévoré vivant par des limaces vampiriques.
@p8: Courage, Cuicui. Je vais vous fabriquer une sandale en rotin et en toile.
@note: &p8 profite du prétexte de chercher du palmier pour s'accorder un moment de solitude. Elle trouve un mince filet d'eau de pluie qui coule le long d'une fissure calcaire.
@note: Elle sort un chiffon de son sac pour se frotter la boue des marais du visage et du cou. L'eau est glacée contre sa peau.
@note: Elle défait ses cheveux, en secouant le silt et les brindilles, avant de les tresser de son mieux. &p17 s'approche. Il prend un peu d'eau de pluie dans ses mains pour s'asperger le visage.
@p17: Vous prenez tout ça très sportivement. Avez-vous déjà dû traverser la brousse comme ça ?
@p8: Pas vraiment, non. Le travail d'espionnage n'est pas tout à fait aussi aventureux que les livres d'histoire pourraient vous le faire croire.
@p17: Dites-moi. J'ai toujours cru que c'était tout voitures rapides, télégrammes codés et fusillades dans des ruelles sombres.
@p8: Il y a une raison pour laquelle ma couverture est celle d'une avocate. En réalité, c'est surtout du travail de comptabilité et d'analyse. C'est être la femme que personne ne remarque pendant les parties de jardin. C'est passer six mois dans un bureau étouffant à [Sandakan](SANDAKAN), à verifier les manifestes de chaque navire japonais qui accoste dans le port. C'est remarquer qu'un coiffeur japonais dans une petite rue prend des photos de la caserne.
@p8: On ne cherche pas une arme fumante. On cherche l'odeur de la fumée avant même que l'incendie ne commence. On écoute ce que les gens ne disent pas.
@p17: Mais vous portez quand même un pistolet partout où vous allez.
@p8: On nous apprend à penser que si je dois appuyer sur cette gâchette, &p17_title, c'est que j'ai échoué dans ma mission première. La plupart de mes aventures impliquent des yeux douloureux à force de lire des copies carbone floues et la crainte d'avoir raté un tout petit détail dans une facture d'expédition.
@p17: Eh bien vous êtes là maintenant, Mademoiselle. Et vous marchez dans l'Ulu avec nous. C'est une aventure, non ?
@p8: C'est un échec, &p17_firstname. Le fait que nous fuyions à travers les arbres signifie que notre réseau d'espionnage a échoué. Notre travail était de le voir venir.
@note: &p17 fait signe à &p8 de se taire. Il la guide vers les autres.
@p17: Veille, tout le monde. Le soleil touche les arbres. Pas un bruit.
@note: Le groupe se fige. &p19 serre son fusil, son pied nu replié sous lui. Ils restent assis dans le noir, écoutant la jungle.
@note: Quand ils finissent par installer le camp, ils trouvent une petite grotte dans le calcaire. Elle est plus facile à défendre et ils pourront se reposer plus aisément, ne serait-ce que pour une nuit.
        `},nipa_7:{personIds:["p8","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: Tout commence par la formation de grands nuages au-dessus d'eux puis les cieux se déversent.
@note: La première vraie averse de mousson de leur trek ne tombe pas, elle arrive comme un mur d'eau solide.
@note: Le groupe est tiré de son sommeil en sursaut quand la grotte se remplit d'eau en quelques secondes.
@note: Ils attrapent tous leurs sacs et leurs bottes précipitamment et sortent en courant.
@p19: Je n'ai jamais rien vu de pareil ! Ce n'est pas de la pluie, c'est une putain de cascade.
@p18: Arrêtez de faire l'idiot, ramassez tout ce que vous pouvez avant que tout soit emporté !
@p8: <i>(Riant)</i> C'est une bénédiction du ciel, voilà ce que c'est.
@note: Ils utilisent la force de l'eau pour se débarrasser de la croûte de boue des marais de Nipa de leurs bras et de leur torse.
@note: Ils suspendent précipitamment leurs vêtements sur des branches basses pour les laisser tremper et ils utilisent le pommeau de leur parang pour les battre et les nettoyer.
@note: Aussi soudainement qu'elle a commencé, l'averse cesse, aussitôt suivie d'une vapeur montante alors que l'eau de pluie s'évapore dans la chaleur.
@p17: Bien. La récréation est terminée. &p18_lastname, étalez ces tapis de sol. Nous devons faire sécher le matériel avant que l'humidité ne transforme tout en moisissure. Cuicui, faites sécher votre sandale, je ne veux pas vous voir boiter sur un pied mouillé.
@p17: Nous avons une longue marche devant nous. Le terrain va être comme une patinoire après tout ça.
@p8: Le &p17_title a raison. Nous nous dirigeons vers les crêtes calcaires du &gomantong. Elles seront très glissantes. Nous devons les traverser avant la chaleur de l'après-midi.
        `},gomantong_8:{personIds:["p8","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: Après les basses terres boueuses, le terrain monte brusquement vers des crêtes calcaires où l'air se raréfie à mesure qu'ils grimpent. Le vent change, portant l'odeur d'ammoniac des déjections de millions de chauves-souris et de martinets des grottes au-dessus.
@p18: Gardez un œil sur les nids de martinets. Ils sont non seulement comestibles mais constituent un mets délicat et se conservent des semaines.
@p19: Des nids comestibles ? Comment peuvent-ils être comestibles, de quoi sont-ils faits ?
@p18: De salive, fiston. C'est de la salive d'oiseau solidifiée.
@p19: Ça semble répugnant. J'aurais préféré que vous ne me le disiez pas.
@p18: C'est vous qui avez demandé, &p19_lastname !
@p17: Vous deux, taisez-vous et concentrez-vous. Je ne veux pas vous voir perdre prise et glisser. Continuons juste d'avancer.
@note: Le groupe escalade une crête raide et glissante après la pluie. &p19 peine énormément, sa sandale de fortune étant particulièrement glissante.
@note: &p19 aperçoit des ombres au-dessus et lève les yeux.
@note: Très au-dessus d'eux, se balançant dans la brise, se trouvent des centaines d'échelles en bois et de cordes de lianes. Elles pendent depuis les bouches des nombreuses grottes qui forment le sommet du Gomantong.
@p19: Seigneur ! À quoi servent-elles ?
@p18: C'est là que vivent les collecteurs, fiston. Les nids de salangane sont là-haut. Comme je disais, c'est un mets délicat.
@p19: Mais comment font-ils pour monter là-haut ?
@p8: Ils grimpent, &p19_lastname. Ils grimpent.
@p18: Bon sang. On ne me ferait pas monter là-haut pour tout l'or du roi. Ces collecteurs doivent avoir des os creux.
@p8: Il semble qu'ils aient tous décampé depuis un moment à en juger par l'état des lieux, &p18_firstname.
        `},gomantong_9:{personIds:["p8","p13","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: Ils atteignent un petit plateau, une corniche naturelle dans la falaise. Le groupe est essoufflé. &p17 fait signe de faire une courte pause, mais avant même de pouvoir s'asseoir, il remarque quelque chose surgir des ombres.
@note: Une douzaine de silhouettes émergent de derrière un rideau de grandes fougères. Ce sont des pirates Suluk, avec des tatouages tribaux gravés sur la poitrine, brandissant sabres et fusils.
@note: &p18 bondit sur ses pieds, épaulant son fusil.
@p18: Embuscade ! En carré !
@note: &p19 geint en manipulant maladroitement la culasse.
@p19: Sergent ! Ils sont partout !
@note: La situation est sans espoir. Les pirates tiennent la hauteur et sont en supériorité numérique. &p8 et les soldats britanniques sont acculés contre la paroi verticale de calcaire. Un pirate, un homme portant une vilaine cicatrice en travers de la gorge, s'avance, sa lame pointée sur la poitrine de &p17. Juste alors qu'il s'apprête à frapper, un coup de sifflet bref retentit depuis les rochers au-dessus.
@note: &p13 émerge de l'ombre d'une fissure, un lourd pistolet glissé dans une ceinture cramoisie. Son regard tombe sur le groupe, s'arrêtant finalement sur &p8. Un lent sourire se répand sur son visage.
@p13: Tiens, je n'en reviens pas. L'avocate. Je pensais que les <c>Nips</c> vous auraient éventrée depuis le temps.
@note: &p8 s'avance, sa main restant sur son revolver, sa voix aussi assurée que de la glace.
@p8: Vous êtes loin de la plantation, &p13_lastname.
@p13: Le monde se retourne comme une crêpe, ma chère. Un homme doit trouver un point haut quand l'ennemi débarque par les côtes. Et vous ? À trottiner dans l'Ulu avec un gamin à une jambe et deux vieux routiers ?
@p13: Et dites-moi, qu'est-il advenu de Bone et du reste des pauvres diables ? Ont-ils sauvé quelque chose du chaos ?
@p8: Bone est mort. La plantation est une ruine calcinée et tout le monde évacue.
@note: &p13 a l'air sincèrement attristé. Il regarde vers l'horizon où la fumée s'attarde encore, puis revient vers Cynthia. Il offre un lent hochement de tête respectueux.
@p13: Mort, vous dites ? Dommage. J'aimais bien le vieux diable. Il avait du cran.
@note: &p13 fait signe à ses hommes de reculer. Ils disparaissent dans la verdure aussi vite qu'ils étaient apparus.
@p13: Allez. Filez vers la ville. Mais les <c>Nips</c> tiennent les routes secondaires menant à Sandakan. Vous devrez prendre les pistes du &sepilok si vous voulez passer.
@p8: Pourquoi nous aider, &p13_firstname ?
@p13: Considérez ça comme une courtoisie professionnelle. Je préfère vous voir vous noyer dans l'Atlantique plutôt que d'être exécutée par ces petits hommes du Nord. Maintenant, filez avant que je change d'avis.
@p19: Sergent ? Est-ce qu'il vient de... Est-ce qu'un pirate vient de nous laisser partir ?
@p17: Fermez-la, &p19_title &p19_lastname. Continuez juste d'avancer avant que le Tout-Puissant ne réalise qu'il a fait une erreur.
@note: Le groupe déguerpit, leurs bottes glissant sur le calcaire humide. &p19 jette un dernier coup d'œil en arrière, s'attendant à moitié à recevoir une volée de balles.
@note: Cette nuit-là, le groupe est doublement vigilant. Chaque craquement de brindille, chaque bruissement de feuille envoie une décharge d'adrénaline. Ils se serrent les uns contre les autres autour du feu, les flammes ne faisant guère obstacle à l'obscurité oppressante de la jungle.
`},gomantong_10:{personIds:["p8","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: Le lendemain matin, le groupe reprend sa marche dans la jungle. Le terrain est encore traître, mais les pires crêtes calcaires sont derrière eux. Ils avancent bien, mais la chaleur humide se fait sentir.
@p19: Combien encore jusqu'à &sepilok, &p17_title &p17_lastname ?
@p17: Pas loin maintenant, &p19_title. Juste au-delà de cette prochaine crête et nous devrions apercevoir la côte.
@note: Alors qu'ils franchissent la crête, ils sont accueillis par un spectacle époustouflant. En contrebas, la jungle s'étend à perte de vue, une mer de vert interrompue seulement par le ruban sinueux de la rivière.
@note: Ils descendent la crête. En atteignant le bas, ils tombent sur une petite clairière où un groupe d'autochtones est rassemblé autour d'un feu.
@p18: Regardez-moi ça ! Un vrai repas !
@p17: Ne sautons pas aux conclusions. C'est leur festin. On peut être polis et s'arrêter pour un déjeuner s'ils nous y invitent.
@note: Les autochtones sont un groupe de [chasseurs Dusun](DUSUN). Ils lèvent les yeux à l'approche du groupe. Ils sont d'abord méfiants, mais en voyant que le groupe ne sont pas des soldats japonais, ils se détendent légèrement.
@p8: Bonjour. Nous sommes des soldats britanniques. Nous allons à Sandakan.
@note: Les autochtones hochent la tête, comprenant le mot « Sandakan ». Ils font signe au groupe de les rejoindre autour du feu.
@p8: Ils semblent assez amicaux.
@p17: Oui, mais restez sur vos gardes.
@note: Le groupe rejoint les autochtones autour du feu et on leur offre de la nourriture et de l'eau. &p19 s'en empare avec appétit.
@p19: C'est la meilleure nourriture que j'aie mangée depuis des semaines !
@p19: Je vous dis, Mademoiselle &p8_firstname, si jamais je rentre dans le Yorkshire, je dirai à mon père d'arrêter d'élever des moutons et de commencer à élever ce que ces gars-là chassent. C'est vraiment excellent.
@note: &p17 s'assoit un peu à l'écart, observant les chasseurs Dusun et le reste de son groupe savourer le repas. Il accepte un tube de bambou rempli d'eau, acquiesçant pour remercier l'ancien.
@p17: Vous savez... J'ai passé les quarante-huit dernières heures à vous traiter de désastre ambulant. Je vous ai traités de blanc-becs, de gamins et de boulets.
@p18: Eh bien, vous n'aviez pas tort pour ce qui est du boulet où Cuicui est concerné, Sergent.
@p17: J'ai vu beaucoup d'hommes affronter l'Ulu pour la première fois. Des hommes avec des années d'entraînement derrière eux. Et je les ai vus pleurer et craquer sous la dureté de l'épreuve. Mais je dirai ceci pour vous...
@p17: Vous avez du cran. Plus que la plupart dans ces circonstances.
@p8: Je bois à ça.
@note: Ils prennent tous une longue gorgée dans leur tube de bambou, le liquide débordant sur les bords et leur coulant sur le menton.
`},sepilok_11:{personIds:["p8","p17","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: Après s'être remis de ce déjeuner, ils pénètrent dans la réserve de Sepilok, où les gigantesques Diptérocarpes s'élèvent à soixante mètres dans les airs, leurs cimes entrelacées tissant un toit si dense que le soleil arrive à peine à filtrer. Le sol de la forêt est un monde en crépuscule permanent, étonnamment libre de lianes mais couvert de mousse, de champignons et de l'occasionnel mille-pattes géant.
@note: Le groupe avance entre les troncs géants, se sentant comme des fourmis. Même &p19 a été réduit au silence par la majesté des lieux tandis qu'ils marchent sur l'épais tapis de feuilles en décomposition.
@p19: Je n'aurais pas cru que des arbres pouvaient atteindre cette taille.
@p8: On les appelle les Diptérocarpes. Ce sont les géants de la jungle.
@p18: La façon dont la lumière filtre à travers les branches ressemble à une cathédrale.
@note: En marchant, ils tombent sur une clairière où un grand orang-outan est perché sur une branche. Il les observe de ses yeux mélancoliques, épluchant lentement un fruit sauvage.
@p19: Regardez ! Sergent ! Mademoiselle &p8_firstname ! C'est un homme ! Il y a un homme en manteau de fourrure là-haut !
@p17: Ce n'est pas un homme, Cuicui. C'est le vrai maître de Borneo. Il se demande probablement ce qu'une aussi pitoyable troupe fait à trotter dans son domaine.
@p19: Il a une tête exactement comme mon Grand-Oncle Georges ! Il a une grande barbe rousse broussailleuse. Regardez-le ! Il me fait un clin d'œil !
@note: Le groupe s'arrête pour observer l'orang-outan.
@note: &p19 fait un claquement de langue. L'orang-outan incline la tête, laisse tomber la peau du fruit et pousse un appel retentissant qui résonne à travers les arbres. Le groupe éclate de rire.
@note: Après quelques minutes, l'orang-outan s'élance et disparaît, laissant le groupe dans le silence.
@p17: Nous devrions continuer. Nous perdons la lumi...
@note: Un craquement semblable à la cassure d'une branche morte brise le moment.
@note: &p17 ne crie pas. Il est simplement projeté en arrière. Du sang commence à imbiber sa tunique kaki. Il regarde &p8 avec une expression de profond effarement avant de s'effondrer dans la mousse.
@note: &p19 regarde avec horreur. &p8 plonge dans la terre.
@p19: Sergent ? Sergent !
@p8: &p19_firstname ! À terre ! À terre, espèce d'idiot !
@note: &p18 se précipite derrière un tronc d'arbre, le visage blême.
@p18: C'était quoi ? Un tireur embusqué ?
@note: De l'ombre des troncs massifs, des coups de feu claquent dans l'air, touchant les arbres tout autour d'eux.
@p8: Des snipers ! Ce sont les <c>Nips</c> !
@p19: <i>(Jetant un coup d'œil par-dessus un tronc)</i> Ils sont partout !
@note: &p8 dégaine son pistolet.
@p8: Mettez-vous derrière moi !
@note: Le crépitement d'une mitrailleuse japonaise éclate depuis derrière les feuilles, déchiquetant les arbres tout autour d'eux. &p18 est appuyé contre une racine massive. Il tire en direction des lueurs des bouches à feu.
@p18: Les <c>Nips</c> dans la canopée ! Dix heures ! Ils sont dans les putains d'arbres !
@note: &p19 est allongé là, figé de terreur. Il fixe les yeux sans vie de &p17.
@p8: Regardez-moi, &p19_title ! Le Sergent est parti ! Si vous voulez revoir le Yorkshire, vous prenez ce fusil et vous tirez ! Vous m'entendez ? Tirez !
@note: &p8 plonge de nouveau dans la zone de tir alors que &p18 et &p19 assurent la couverture, les balles japonaises soulevant la terre autour de ses talons. Elle saisit le sac de &p17, contenant les dépêches pour le Gouverneur, et le traîne en lieu sûr. Dans la ceinture du Sergent, elle arrache une grenade. Elle en arrache la goupille avec les dents.
@p8: &p18_firstname ! Couvrez le flanc gauche !
@note: &p8 se lève, cambrant le dos et lance la grenade dans un épais bouquet de fougères où les lueurs des bouches à feu sont les plus vives.
@note: Une forte explosion secoue le sol de la forêt et les mitrailleuses se taisent une minute.
@p8: Maintenant ! Courez ! Direction la crête arrière ! Ne regardez pas en arrière !
@note: Les trois survivants fuient dans l'ombre du Sepilok, laissant le corps de &p17 derrière eux.

    `},sepilok_12:{personIds:["p8","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: Ils ont couru jusqu'à ce que la lumière soit complètement disparue, laissant la patrouille japonaise loin derrière eux.
@note: Ils s'effondrent sous l'un des arbres, les poumons en feu, les uniformes trempés de sueur.
@note: &p8 s'affaisse contre le bois humide, sa respiration venant par halètements douloureux et saccadés. Elle serre le sac de Miller contre sa poitrine.
@note: &p18 jette son fusil à terre de colère. &p19 pleure, les épaules secouées de sanglots incontrôlables.
@p19: Il est parti. Il est putain de parti. On l'a abandonné.
@p8: Nous l'avons laissé pour que vous puissiez vivre, &p19_firstname. Reprenez-vous. Il n'aurait pas voulu vous voir comme ça. Il connaissait les risques.
@note: &p19 tressaille mais ne lève pas les yeux. &p18 s'agenouille, la tête dans les mains.
@p18: C'est ma faute. J'aurais dû... j'aurais dû faire quelque chose.
@p8: Il n'y avait rien à faire, &p18_firstname. Les <c>Nips</c> nous avaient cloués sur place. On ne les a même pas vus venir, c'étaient des fantômes. Nous sommes vivants. C'est tout ce qui compte.
@p18: Quand j'avais la malaria en '39, il est resté trois nuits à me verser de la quinine dans la gorge. C'était un homme bien.
@p18: C'était un homme bien et on l'a laissé là ! On l'a tout simplement laissé là à pourrir ! Il méritait des funérailles décentes !
@note: &p8 ouvre le sac de Miller. À l'intérieur, nichées parmi des cartes humides et une demi-boîte de biscuits entamée, se trouvent les dépêches pour le Gouverneur.
@p8: Il n'aurait pas voulu des funérailles, &p18_firstname. Il aurait voulu que nous livrions ces dépêches au Gouverneur.
@note: &p18 lève les yeux, ses yeux rougis. &p19 cesse de pleurer, son attention captée.
@note: &p19 s'essuie les yeux du revers de la main.
@p19: Alors... on devrait continuer la mission ? Pour le Sarge ?
@p8: Nous le devrions. Écoutez-moi tous les deux. Le Service ne nous accorde pas le luxe de pleurer aujourd'hui. Mais je vous jure que nous ferons en sorte que la mort du Sergent ait un sens. Nous porterons ce sac jusqu'à sa destination.
@note: &p18 se relève, sa résolution retrouvée.
@p18: Alors allons-y. Plus vite on y sera, plus vite on pourra retrouver la civilisation.
@p19: Ouais. La civilisation. Et une pinte.
@note: &p8 esquisse un faible sourire. Elle range les dépêches dans le sac.
@p8: Allez, vous deux. Nous avons encore un long chemin à faire. Prochain arrêt &batusapi.
        `},batusapi_13:{personIds:["p8","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: Ils ont marché toute la nuit en silence. Ils ne pouvaient pas se résoudre à établir un camp et voulaient juste avancer et rejoindre la civilisation le plus vite possible.
@note: L'obscurité de la forêt primaire est remplacée par l'éclat brutal du soleil équatorial se réfléchissant sur la mer de Sulu.
@note: Ils se tiennent sur un bas promontoire de grès. En contrebas se trouve [Batu Sapi](BATU). En temps de paix, c'est un site touristique populaire mais en temps de guerre, c'est un endroit désolé.
@p19: On s'en est sortis. On est vraiment sortis des arbres.
@p18: Oui. C'est la Vache. Ça veut dire qu'on est proches. À huit kilomètres de la Tour du Jubilé.
@note: &p8 s'avance jusqu'au bord du promontoire, les yeux plissés pour voir au travers du brouillard de chaleur de la baie. Au loin, les bâtiments blanchis à la chaux de [Sandakan](SANDAKAN) sont visibles.
@note: Une fumée noire et huileuse monte en spirale dans le ciel depuis le front de mer. Les scieries et les entrepôts de pétrole sont tous en flammes.
@p18: Mon Dieu. Ils ont mis le feu à toute la foutue ville.
@p8: C'est l'œuvre des Britanniques, pas des <c>Nips</c>. Ils détruisent tout en partant. Nous devons nous dépêcher ou il ne restera plus personne, ils auront tous évacué.
@p8:  Regardez là, &p18_lastname. Près du port, derrière le promontoire.
@note: Ils peuvent voir un destroyer impérial japonais, immobile à l'entrée de la baie, attendant que tout navire britannique tente une percée vers la haute mer.
@p8: Une classe Fubuki, à en juger par la silhouette. Elle bouche le goulot. Personne ne sort de Sandakan par la mer.
@p19: Alors qu'est-ce qu'on fait maintenant ?
@p8: On continue d'avancer. On trouve un moyen de rejoindre &sandakan. On livre ces dépêches. Nous entrerons dans la ville par les falaises.
        `},sandakan_14:{personIds:["p8","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`@note: Ils contournent le bas-fond du [quartier chinois](CHINESETOWN), d'où montent les crépitements de fusillades et les cris d'une population en panique depuis le front de mer. Ils se frayent un chemin jusqu'à la Station sans fil.
@note: Les hauts mâts d'acier des télégraphes de la station sans fil ont été abattus comme des arbres, leurs câbles gisant dans la poussière. La communication radio avec l'extérieur est désormais impossible.
@note: Ils peuvent voir les bâtiments du Secrétariat en contrebas ainsi que les docks, un enchevêtrement de navires sabordés et d'embarcations en feu.
@p19: Tout le monde fuit, &p18_title. Sommes-nous trop tard ? Le Gouverneur a-t-il décampé ?
@p8: Il n'aura pas décampé, &p19_lastname. Un Gouverneur britannique ne quitte pas son poste, on l'en arrache de force. Direction Government House, au pas de course !
@note: Ils atteignent les grilles de Government House. À l'intérieur, tout le monde court dans tous les sens. Des clercs font face à des masses d'autochtones et de réfugiés qui cherchent une issue. Le groupe est ignoré à son entrée et laissé à lui-même.
@note: Ils trouvent le Gouverneur dans son bureau, un verre bien tassé à la main. &p8 le salue en entrant.
@p8: Gouverneur, je porte des dépêches du &p16_title &p16_lastname.
@unknown: &p16_lastname... est-il encore en vie ? Nous avions entendu dire que les <c>Nips</c> avaient atteint la côte du Sulu hier.
@p8: La Marine les a tenus en respect un temps, mon général. Ces dépêches contiennent les dernières coordonnées de la Marine pour l'évacuation. Y a-t-il un navire disponible pour ces hommes ?
@unknown: Un navire ? Regardez par la fenêtre, ma chère. Les <c>Nips</c> tiennent le port à la gorge.
@unknown: Aucun cargo ne quittera ce port aujourd'hui ni de sitôt. Nous attendons simplement qu'on frappe à la porte maintenant.
@p8: Alors il est temps de terminer ceci. &p18_lastname, &p19_lastname, suivez-moi. J'ai une dernière mission à mener et vous pouvez tout aussi bien m'accompagner.
`},sandakan_15:{personIds:["p8","p18","p19","p20"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`
@note: &p8 emmène les deux soldats interloqués loin du quartier gouvernemental et monte les collines résidentielles jusqu'à un bungalow sans prétention. À peine la porte d'entrée verrouillée, son fiancé, &p20_firstname, émerge des ombres.
@note: &p20 aperçoit les deux soldats et marque une pause une seconde avant d'ouvrir les bras pour accueillir &p8.
@p20: Ah ma bien-aimée, enfin.
@p8: Laissez tomber la comédie, &p20_firstname. Nous sommes en guerre et les subterfuges sont dépassés. Voici &p18_firstname et &p19_firstname. Ils sont avec moi.
@p8: Les gars, voici &p20, mon officier traitant. Le frère du Commandant &p16_lastname.
@p20: Bien. Rapport, agent. Et vite. Les <c>Nips</c> sont à la [Tour du Jubilé](JUBILEE).
@p8: J'ai peut-être échoué dans ma mission première mais vu ce qui se passe à notre porte, je doute que ça change quoi que ce soit.
@p8: En revanche, j'ai quelque chose de bien meilleur dans ces circonstances.
@note: &p8 ouvre son sac et fait glisser le &report.
@p8: La formule de la Brume Verte. Tout ce dont le Service a besoin pour la fabriquer. Un agent du SIS, &p3, est en route vers les Alliés avec les contre-mesures, mais ça... c'est l'épée pour répondre à son bouclier.
@p20: Excellent travail, agent &p8_lastname. Voilà qui va faire asseoir le Conseil d'administration et prendre note.
@note: Alors que &p20 parcourt les documents, &p18 regarde autour de lui et découvre une pièce cachée avec du matériel de radio.
@p18: Dites donc... Qui êtes-vous vraiment ?
@p8: Nous sommes les fantômes dans la machine, &p18_firstname. Et nous sommes votre seul billet de sortie de ce cimetière.
@p20: Le port est bloqué mais la base d'hydravions à l'inlet ouest tient encore. Nous avons un Catalina, un hydravion militaire, qui se prépare pour un départ à l'aube vers Colombo.
@p19: Un hydravion ? Nous allons voler jusqu'à Londres ?
@p20: Pas tout à fait Londres, fiston, mais ça vous amènera à Ceylan en quarante-huit heures. C'est à l'étroit et aussi bruyant que possible mais c'est toujours mieux que de rester ici à attendre de mourir.
 `},sandakan_16:{personIds:["p8","p18","p19"],objects:[{id:"pearl2",heldBy:"p8"},{id:"report",heldBy:"p8"},{id:"knife",heldBy:"p18"}],clue:`
@note: Le Catalina est bas sur l'eau d'une crique cachée. &p8, &p18 et &p19, en uniformes propres et neufs, se glissent par l'écoutille à mi-hauteur.
@note: L'avion commence sa course au décollage.
@p8:  Gardez la tête haute, les gars ! Prochain arrêt, le [Galle Face Hotel](GALLEFACE) !
@note: &p19 regarde en bas la ville en flammes alors que l'avion s'arrache de l'eau.
@p19: Regardez ça, &p18_firstname ! On vole ! On s'envole vraiment loin de tout ça !
@p18: Bon débarras l'Ulu, elle ne me manquera pas, &p19_firstname.
@note: L'hydravion vire à l'ouest, prenant de l'altitude dans les nuages. Le long vol vers l'Océan Indien a commencé.
@note: J'ai trouvé tout ce que je pouvais concernant Cynthia maintenant. Je vais tout consigner dans un [rapport annexe](doc_cynthia_ending). Ça pourrait encore intéresser quelqu'un.
        `}},r={the_seas:{title:"La terre sous le vent",text:`Les marins en 1941 faisaient référence aux mers autour de Bornéo du Nord comme étant la Terre sous le vent. 
Ce n'était pas seulement un nom poétique, c'était un fait géographique. Bornéo du Nord se trouve juste au sud de la ceinture de typhons qui ravage les Philippines et le nord de la mer de Chine méridionale.
Pour les pirates et les propriétaires de plantations de l'époque, cela signifiait que les mers étaient relativement calmes et navigables toute l'année, ce qui explique exactement pourquoi l'industrie perlière et la contrebande maritime ont pu y prospérer. La météo interrompait rarement leurs affaires.

Bornéo du Nord (l'actuel Sabah) était défini par sa relation avec trois mers distinctes, chacune jouant un rôle spécifique dans l'économie, la contrebande et la piraterie endémique.

La mer de Chine méridionale à l'ouest était l'artère principale pour le commerce et la contrebande. C'était l'autoroute qui reliait Bornéo du Nord au reste du monde.

La mer de Sulu à l'est était le cœur des fermes ostréicoles et de l'industrie de la nacre. C'était aussi le domaine des nomades de la mer Bajau et des pirates qui s'en prenaient aux colonies côtières. Le port principal ici était Sandakan, alors la plus grande ville de Bornéo du Nord.
Elle était connue comme l'eau la plus dangereuse sur terre à l'époque. Les pirates de Sulu (Moros) utilisaient les milliers de minuscules îles de cette mer pour se cacher des canonnières britanniques.

La mer de Célèbes au sud était la frontière entre les eaux britanniques et néerlandaises, bordant les Indes orientales néerlandaises et le port de Tawau. C'était la route principale pour les travailleurs javanais et japonais venant travailler dans les plantations.
`,image:"photos/sulu_archipelago.png"},culture:{title:"Culture de la Boisson",text:`En 1941, un colon britannique à Bornéo avait un vocabulaire très spécifique pour les rituels de beuverie du soir, profondément ancré dans la culture de l'époque.

Les termes les plus courants étaient :

Le Sundowner
C'est le terme le plus emblématique. Il désignait le premier verre de la soirée, pris exactement au moment où le soleil commençait à se coucher. Sous les tropiques, le soleil se couche rapidement et à peu près à la même heure toute l'année, faisant des "sundowners" un rendez-vous social rigide. Cela marquait la transition de la chaleur du jour à la fraîcheur du soir.

Ils ne prenaient pas seulement un verre ; ils prenaient un Gin Pahit qui était essentiellement un Pink Gin mélangé avec plusieurs grosses gouttes de bitter Angostura. 
Les planteurs et les officiers coloniaux croyaient que les amers étaient médicinaux et aidaient à calmer l'estomac après une journée dans la jungle humide.

Un Stengah
Si un homme voulait une boisson plus légère avant le dîner, il demandait un Stengah.
C'était une demi-mesure de whisky complétée par de l'eau gazeuse. C'était la boisson de session des clubs coloniaux permettant aux hommes de boire pendant plusieurs heures sans s'enivrer immédiatement.

L'Heure du Tigre (The Tiger Hour)
Bien que moins courant comme nom direct pour la boisson, le début de soirée était souvent appelé L'Heure du Tigre. C'était le moment où le Gin Tonic régnait en maître. La quinine dans l'eau tonique était une prophylaxie contre le paludisme, donnant aux colons une excuse médicale pour commencer à boire tôt.

Prendre un sundowner correctement dans les années 1930 impliquait une routine très spécifique qu'un colon britannique suivait :

1. Le travail se terminait généralement vers 16h00 ou 16h30 à cause de la chaleur. Ils prenaient ensuite un mandi, un bain traditionnel de style malais consistant à s'éclabousser d'eau fraîche avec une louche.
Après le bain, ils enlevaient leurs vêtements de travail kaki tachés de sueur et enfilaient des vêtements en lin blanc propres. Ils s'asseyaient sur la véranda ombragée de leur bungalow ou au Club local et savouraient leurs boissons.

Voici ce qui était typiquement préparé comme amuse-gueules pour accompagner les boissons au coucher du soleil :

Le Kachang
L'amuse-gueule le plus omniprésent était les cacahuètes frites mais préparées avec une touche locale. Contrairement aux simples noix salées en Angleterre, celles-ci étaient frites avec de l'ail et du piment. Le cuisinier faisait frire des cacahuètes crues avec des gousses d'ail entières, des piments rouges séchés et des feuilles de combava.
Elles étaient servies chaudes et étaient incroyablement addictives. C'est étroitement lié à l'ancêtre du Bombay Mix mais dans le Bornéo des années 1930, on l'appelait simplement Kachang.

Ikan Bilis et Cacahuètes
Souvent servis avec ou mélangés aux noix se trouvaient les Ikan Bilis : de minuscules anchois séchés au soleil. Ils étaient frits jusqu'à devenir croustillants et salés. 
C'était l'amuse-gueule colonial ultime avec la bière. La salinité aidait à remplacer ce qui avait été perdu par la sueur pendant la journée, rendant le Stengah frais encore meilleur.

Beignets de Crevettes (Keropok)
Les Keropok étaient un amuse-gueule salé haut de gamme pour les Britanniques. Fabriqués à partir de crevettes broyées et d'amidon, ils étaient séchés au soleil en disques durs puis frits rapidement dans l'huile de noix de coco jusqu'à ce qu'ils gonflent.
Ils étaient légers, aérés et portaient une forte saveur de mer qui se mariait parfaitement avec un Gin Pahit.

Curry Puffs
Le Curry Puff était l'hybride parfait des années 1930. Il utilisait une pâte brisée de style britannique mais était rempli d'un curry sec et épicé de pommes de terre et de viande.  Ceux-ci étaient souvent faits en forme de demi-lune.
Parce qu'ils étaient petits et secs, ils pouvaient être mangés d'une seule main tout en tenant un verre de l'autre.
`,image:"photos/drinks.png"},opium:{title:"Opium",text:`Dans les années 1920 et jusqu'à la Seconde Guerre mondiale, le commerce de l'opium dans la mer de Chine méridionale était une collision bizarre et à enjeux élevés entre les monopoles légaux des gouvernements coloniaux et les syndicats criminels impitoyables.
L'opium n'était pas illégal à l'époque, c'était une source de revenus contrôlée par l'État.

À cette époque, il y avait deux types d'opium qui circulaient sur les mers :
* L'Opium Gouvernemental : Les Britanniques (à Bornéo du Nord et à Sarawak) et les Néerlandais (à Kalimantan) exploitaient des monopoles sur l'opium. Ils importaient de l'opium brut, le transformaient en Chandu et le vendaient via des boutiques agréées. Cela fournissait jusqu'à 20 % du budget colonial total.
* L'Opium de Contrebande : Parce que le gouvernement taxait lourdement l'opium pour maximiser ses revenus, un marché noir massif a émergé. Les contrebandiers vendaient de l'opium à la moitié du prix gouvernemental.

Dans les années 1920, la Chine était dans l'ère des seigneurs de la guerre. L'autorité centrale s'était effondrée et les seigneurs de la guerre provinciaux avaient besoin d'argent pour acheter des armes modernes. 
Les seigneurs de la guerre du Yunnan et du Sichuan ont forcé les agriculteurs à cultiver des pavots plutôt que de la nourriture. Cet opium était expédié le long de la rivière des Perles jusqu'à Guangzhou (Canton) et Hong Kong et par Macao. 
Les Triades, telles que le Gang Vert basé à Shanghai, géraient la logistique. Elles utilisaient les réseaux de pirates pour escorter les cargaisons à travers la mer de Chine méridionale.

Bornéo était une destination de choix pour l'opium de contrebande en raison de sa main-d'œuvre massive de coolies chinois travaillant dans les plantations.

De grands bateaux à vapeur (tramp steamers) transportaient des caisses d'opium de Chine ou du Vietnam vers la côte de Bornéo. Ils arrivaient par différents ports. 
Sandakan et Kudat dans le Bornéo du Nord étaient les principales portes d'entrée. Le littoral était un labyrinthe de mangroves où un petit bateau pouvait disparaître en quelques minutes.
Les îles Natuna, situées entre Singapour et Bornéo, étaient un célèbre point de chute (dead drop) où les contrebandiers cachaient de l'opium dans des grottes pour une récupération ultérieure, puis les contrebandiers utilisaient les réseaux fluviaux pour contourner les postes de douane à Kuching, livrant l'opium directement aux travailleurs dans les camps forestiers de l'intérieur des terres.

Les douaniers coloniaux étaient constamment déjoués par la créativité des contrebandiers.
Bornéo était un important exportateur de bois. Les contrebandiers creusaient des bûches massives, les remplissaient de boîtes d'opium et les faisaient flotter dans le port pour les récupérer la nuit.
Une autre astuce consistait à construire de faux planchers dans les jonques chinoises. Pour un douanier regardant dans une cale pleine de poissons salés puants ou de porcs, le bateau avait l'air légitime, mais sous les planches se cachaient des milliers de dollars d'opium.
Si un navire de contrebandiers était sur le point d'être abordé par une canonnière britannique, l'équipage jetait l'opium par-dessus bord. Cependant, les paquets étaient lestés de sacs de sel qui se dissolvaient après quelques heures, permettant à l'opium de remonter à la surface pour être récupéré une fois la marine partie.

Dans les années 1930, la pression internationale de la Société des Nations a commencé à forcer les Britanniques et les Néerlandais à éliminer progressivement leurs monopoles sur l'opium. Ils ont introduit des cartes de Fumeur Enregistré, ce qui signifie que seules les personnes déjà toxicomanes pouvaient acheter de l'opium.
Cette politique bien intentionnée s'est retournée contre eux. Comme l'opium légal devenait plus difficile à obtenir et plus cher, le commerce de contrebande illégale a explosé. Les années 1930 sont devenues un âge d'or pour les contrebandiers qui ont comblé le vide laissé par les gouvernements coloniaux en recul.

Lorsque les Japonais ont envahi Bornéo en 1941, les réseaux des sociétés secrètes utilisés pour la contrebande d'opium étaient si bien établis qu'ils sont devenus l'infrastructure principale de la résistance clandestine pendant la guerre.`,image:"photos/opium_trade.png"},colonies:{unlockedByDefault:!0,title:"Les Colonies",text:`Bornéo en 1941 était dans une période d'industrialisation des ressources de l'île, dominée par une poignée de puissances et de sociétés européennes profitant de la population locale. L'économie est passée du commerce traditionnel aux industries à grande échelle comme les plantations de caoutchouc et de tabac, ainsi qu'à une petite mais lucrative industrie perlière.

En 1941, Bornéo était effectivement divisé entre deux puissances européennes. 
Les Britanniques au Nord étaient divisés en trois territoires : Sarawak dirigé par [Charles Brooke de la famille Brooke, les Rajahs Blancs](WHITERAJAH:CHARLESBROOKE) ; le Bornéo du Nord britannique dirigé par la British North Borneo Chartered Company, dont faisait partie la plantation Goodwill ; et Brunei, un protectorat britannique.
Les Néerlandais occupaient le Sud en tant que partie des Indes orientales néerlandaises et administré depuis Jakarta.
Historiquement, les Allemands avaient été les premiers pionniers de l'industrie du tabac de Bornéo avant la Première Guerre mondiale, mais leur influence a décliné après cette guerre.

Il y a eu un boom massif de l'agriculture de plantation qui a redéfini le paysage de l'île.
Après la Première Guerre mondiale, la demande de caoutchouc, due à l'industrie automobile, est montée en flèche. Les entreprises européennes ont défriché de vastes étendues de jungle pour planter des hévéas. Dans les années 1930, le caoutchouc était l'exportation la plus importante pour le Bornéo britannique et néerlandais.
Avant cela, Bornéo du Nord était mondialement connu pour ses feuilles de cape de cigare de haute qualité. Cependant, dans les années 1930, de nombreuses compagnies de tabac ont commencé à se tourner vers le caoutchouc, car les cigarettes américaines prenaient le dessus et la demande de feuilles de cigare diminuait.

Quand on parlait de fermes ostréicoles à Bornéo à cette époque, on parlait d'huîtres perlières pour cultiver des perles et des coquilles de nacre, plutôt que d'huîtres comestibles.
La mer de Sulu et la mer de Célèbes étaient les principales zones de pêche. Les perles naturelles étaient récoltées par des plongeurs indigènes. Dans les années 1920, l'industrie a traversé une crise due à l'invention des perles de culture au Japon. Alors que les perles de culture japonaises inondaient le marché à un coût inférieur, la valeur des perles naturelles de Bornéo a chuté.
Les gouvernements britannique et néerlandais ont accordé des concessions à des entreprises européennes pour draguer les fonds marins afin de pouvoir le faire à grande échelle et de lutter contre les perles japonaises. Ils s'intéressaient principalement à la nacre, qui était utilisée pour les boutons et les bijoux en Europe et en Amérique.

Il est important de noter que si les Européens possédaient la terre et le capital, ils ne fournissaient pas la main-d'œuvre. La période précédant la Seconde Guerre mondiale a vu un afflux massif d'ouvriers chinois amenés pour le tabac et le caoutchouc, qui sont finalement devenus les marchands dominants dans les villes côtières comme Sandakan. 
Et les Japonais étaient très influents dans les années 1930 dans le bois et la pêche, agissant souvent comme espions pour l'armée japonaise, recueillant des renseignements avant leur invasion en 1941.`,image:"photos/colonies.png"},piracy:{title:"Piraterie",text:`Les années 1920 jusqu'en 1941 furent une période majeure de piraterie dans la mer de Chine méridionale. La piraterie a évolué du maraudage traditionnel vers une entreprise criminelle hautement organisée qui déconcertait les marines les plus puissantes du monde.

C'était la tempête parfaite : l'explosion de la piraterie a été stimulée par l'effondrement politique de la Chine à la suite de la chute de la dynastie Qing.
L'autorité centrale en Chine a disparu, remplacée par des seigneurs de la guerre locaux qui passaient souvent des accords avec des gangs de pirates, prenant une part de leur butin en échange de leur protection.
Les guerres civiles, les famines et la Grande Dépression ont poussé les villageois des côtes vers la piraterie comme moyen de survie, y compris de nombreuses femmes et enfants. La figure la plus légendaire de cette époque fut Lai Choi San, la Reine des Pirates. Elle commandait, dit-on, une flotte de 12 navires pirates armés et des milliers de partisans. 
La côte de Canton et de Fujian était un labyrinthe de milliers de petites îles avec des criques cachées et des deltas de rivières. Le plus tristement célèbre d'entre eux était Bias Bay, qui servait de république pirate.

Contrairement aux pirates des Caraïbes qui pourchassaient les navires, les pirates de la mer de Chine méridionale de cette époque utilisaient une méthode plus subtile. 
Les pirates achetaient des billets légitimes et montaient à bord des bateaux à vapeur en tant que passagers de troisième classe. Ils faisaient passer en contrebande des pistolets et des grenades dans leurs bagages ou les faisaient cacher à bord par des membres d'équipage soudoyés.
Une fois le navire en mer, les pirates se précipitaient sur la passerelle et la salle des machines, tuant ou capturant les officiers.
Ils forçaient le navire à naviguer jusqu'à Bias Bay, déchargeaient la cargaison et kidnappaient de riches passagers en échange d'une rançon.
Cette menace était si courante que les navires à vapeur des années 1920 étaient équipés de grilles anti-piraterie, de lourdes barres de fer et de portes qui séparaient la passerelle et les quartiers de première classe du reste du navire.

Hong Kong était une cible privilégiée pour les activités pirates, forgeant la Royal Navy britannique à maintenir une présence massive connue sous le nom de China Station.
Après un détournement particulièrement audacieux, les Britanniques envoyèrent des canonnières et même des porte-avions comme le HMS Hermes à Bias Bay pour saccager les villages pirates et brûler leurs navires.
Le Raid de Bias Bay (1927) : L'une des plus grandes opérations impliqua le débarquement de troupes britanniques à Bias Bay pour détruire les places fortes des pirates après le détournement du navire SS Sunning. Bien qu'ils aient détruit des dizaines de navires pirates, ces derniers se sont simplement cachés dans les collines et sont revenus des semaines plus tard.
Les Britanniques ont fini par placer des Gardes de Peloton sur les navires marchands pour empêcher les détournements.

L'ère des Républiques Pirates a pris fin brusquement à la fin des années 1930, non pas à cause du maintien de l'ordre, mais à cause de la Seconde Guerre mondiale.
En 1937, le Japon a lancé une invasion à grande échelle de la Chine. En 1938, la Marine Impériale Japonaise occupait les régions côtières, y compris Bias Bay.
Les Japonais n'avaient aucune patience pour les pirates interférant avec leurs lignes d'approvisionnement militaire. Ils ont utilisé la tactique de la terre brûlée, détruisant tout navire ou village soupçonné de piraterie.
De nombreux pirates ont fui, ont été exécutés ou ont rejoint la résistance chinoise en tant que guérilleros, utilisant leur connaissance de la côte pour harceler les navires japonais.`,image:"photos/pirates.png"},british_standards:{title:"Les Standards Britanniques",text:`Mettre les pieds dans une plantation britannique de Bornéo du Nord semblait fondamentalement différent d'entrer dans un domaine géré par des Hollandais dans le Sud. Les Britanniques ont apporté une marque de colonialisme très spécifique qui a laissé une empreinte visuelle et culturelle distincte sur le paysage.

Voici comment on pouvait facilement reconnaître une plantation britannique et ce qui la distinguait.

L'indice le plus immédiat était le Bungalow du Directeur. Alors que les maisons hollandaises du Sud avaient tendance à être construites plus près du sol, les bungalows britanniques étaient sur pilotis.
Ils étaient presque toujours surélevés de 6 à 10 pieds au-dessus du sol sur des pieux de bois massifs. Cela gardait la maison au-dessus de la boue, loin des serpents, et permettait à l'air de circuler en dessous.
Un bungalow britannique était reconnaissable à sa massive véranda ombragée qui en faisait le tour. Elle servait de salon et de bar.

Si vous voyiez une petite machine à vapeur, vous étiez sans aucun doute dans une plantation britannique. Le chemin de fer de Bornéo du Nord (North Borneo Railway) était un projet typiquement britannique. C'était le seul réseau ferroviaire de toute l'île. 
Les plantations étaient conçues pour se raccorder à cette ligne de chemin de fer.

Le Tuan avait généralement une grande nostalgie de la campagne anglaise. On pouvait reconnaître un domaine britannique au jardin anglais que l'on tentait d'aménager devant le bungalow.
Les Britanniques déployaient des efforts absurdes pour essayer de maintenir une pelouse plate et verte au milieu de la jungle. Elle était souvent utilisée pour le croquet ou le badminton.

La plupart des plantations britanniques étaient gérées par une agence plutôt que par le gouvernement lui-même. 
Contrairement aux planteurs hollandais plus indépendants, les domaines britanniques suivaient un manuel normalisé sur l'apparence que devait avoir une plantation, de l'espacement des arbres à la couleur de la peinture sur les dépendances.

Dans le Bornéo britannique, la vie sociale était rattachée au club.
Si vous voyiez un bâtiment qui ressemblait à une version rustique d'un club de gentlemen londonien, complet avec une table de billard, de vieilles copies de magazines britanniques et un bar, vous étiez en territoire britannique.

Les Britanniques tenaient à porter des tenues très emblématiques pour montrer leur supériorité sur les locaux.
Le casque colonial (Solar Topee) était le casque blanc emblématique obligatoire porté avec des vêtements blancs empesés. Même avec 90 % d'humidité, ils se changeaient souvent pour mettre un short blanc empesé, des chaussettes blanches montantes et une chemise blanche.

`,image:"photos/british_standards.png"},pearls:{title:"Les Perles",text:`Dans les années 1920 et 1930, évaluer une perle à Bornéo (particulièrement dans les mers de Sulu et de Célèbes) était un exercice de jugement aux enjeux élevés, combinant l'ancienne intuition maritime avec la précision impitoyable des intermédiaires chinois qui contrôlaient le marché.

À cette époque, l'industrie était en fait une double économie. L'argent constant se trouvait dans la coquille de nacre (utilisée pour les boutons en Europe).

Lorsqu'un plongeur Bajau ou japonais remontait une énorme huître à lèvre argentée ou à lèvre dorée, l'évaluation commençait immédiatement.
Contrairement à la perliculture moderne où les perles sont retirées chirurgicalement, les perles naturelles étaient trouvées en palpant la chair de l'huître ou en secouant la coquille une fois ouverte. 
Les perles brutes sont souvent recouvertes d'une membrane fine et visqueuse. Les évaluateurs frottaient la perle entre leurs pouces avec un peu de sel ou un morceau de soie fine pour révéler la peau.

Un marchand des années 1930 à Sandakan évaluait une perle selon cinq critères principaux, utilisant souvent un morceau de velours noir ou de soie bleu foncé pour faire ressortir les couleurs :

1 - L'Orient (Le lustre) : C'était le facteur le plus important. Ce n'était pas seulement la brillance ; c'était la façon dont la lumière semblait luire depuis l'intérieur des couches de nacre. Une perle avec une surface vitreuse mais sans profondeur valait peu.
2 - La Forme : La forme ronde était la plus rare et la plus chère. Même une forme presque ronde faisait chuter le prix de manière significative.
3 - La Couleur : L'argent était la plus recherchée par les acheteurs européens et la dorée était très prisée sur les marchés locaux et chinois.
4 - La Surface : Les évaluateurs cherchaient des creux ou des fissures. Une seule petite piqûre d'épingle sur une sphère par ailleurs parfaite pouvait réduire la valeur de moitié.
5 - La Taille : Mesurée en grains. Une perle de 10 grains était une trouvaille solide et tout ce qui dépassait 20 grains était un événement majeur qui pouvait financer la famille d'un plongeur pendant des années.

L'évaluation se déroulait généralement dans l'arrière-boutique d'une maison de commerce chinoise à Sandakan.
Pour calibrer les plus petites perles de semence, le marchand utilisait un ensemble de passoires en laiton ou en cuivre imbriquées avec des trous de différents diamètres. Ils secouaient les perles à travers les tamis pour les trier par grades.
La perle était pesée sur une minuscule balance à main avec de petits poids en cuivre.
Dans les années 30, les acheteurs les plus sophistiqués utilisaient une loupe grossissante pour vérifier la peau et y chercher les fins motifs en forme de brique de la vraie nacre.

La partie la plus dramatique de l'évaluation dans les années 1930 était la peur du faux.
Les perles de culture japonaises ont commencé à inonder le marché à la fin des années 1920. 
À l'œil nu, une perle de culture de haute qualité semblait identique à une perle naturelle. Cela a provoqué une panique à Bornéo. 
Les acheteurs expérimentés cherchaient le trou de perçage. Les perles de culture étaient cultivées autour d'une bille, donc si vous regardiez dans le trou avec une forte lumière, vous pouviez parfois voir la ligne où la nacre naturelle rencontrait le noyau artificiel. Sans trou de perçage, les marchands devaient se fier au toucher et au poids de la perle. Les perles naturelles étaient souvent légèrement plus irrégulières dans leur densité.

À Bornéo, ces évaluations étaient souvent gardées secrètes. Si un plongeur trouvait une perle vraiment magnifique, il ne la montrait pas sur le pont (où le Tuan ou le propriétaire du bateau pourrait en réclamer une plus grande part). Il la cachait dans sa joue ou dans une petite pochette et l'apportait à un intermédiaire de confiance la nuit. 

L'évaluation se faisait en silence, le marchand et le plongeur négociant sous un tissu. Ils se tenaient la main sous un sarong ou un tissu et signalaient les prix en serrant les doigts. Cela gardait le prix secret des spectateurs ou des rivaux.

Dans les années 1930, la terminologie utilisée pour le revêtement irisé de la coquille d'huître dépendait entièrement de qui parlait et où. 
Dans les affaires quotidiennes de la pêche perlière, les hommes sur les bateaux, les commerçants chinois et les fonctionnaires coloniaux n'utilisaient presque jamais l'expression Mère-de-Perle (Nacre). Ils l'appelaient simplement coquille ou coquille de perle.
Parce que les coquilles étaient le produit principal (pour les boutons) et que les perles étaient le bonus, l'ensemble de l'industrie était appelé "ramassage de coquille de perle" (pearlshelling) plutôt que "culture de la nacre".

Dans le monde bilingue de Bornéo, les plongeurs et ouvriers locaux parlant malais avaient leurs propres termes que les Britanniques ont souvent adoptés :
* Kulit Mutiara : Littéralement Peau de Perle ou Coquille de Perle. 
* Kulit : Simplement Peau ou Coquille. Un plongeur montait sur le pont et disait : "Banyak kulit, Tuan" (Beaucoup de coquilles, Monsieur).

Les coquilles de qualité inférieure et la poussière laissée par les usines de taille de boutons étaient réduites en une fine poudre blanche. La poudre de perle était un incontournable du marché cosmétique asiatique. Elle était utilisée dans les poudres et les crèmes pour le visage, censées éclaircir la peau et lui donner de l'éclat.
Dans la médecine traditionnelle chinoise, la poudre de coquille broyée était consommée comme source de calcium pour traiter de nombreuses affections différentes.

Dans les régions côtières de Bornéo, où la roche mère calcaire était souvent rare, les parties extérieures jetées des coquilles d'huîtres étaient recyclées pour la construction.
Les coquilles étaient brûlées dans des fours massifs pour créer de la chaux de coquillage. Cette chaux était mélangée à du sable et de l'eau pour créer le mortier et le badigeon pour les bâtiments en pierre.
`,image:"photos/pearls.png"},maritime_rules:{title:"Les Règles Maritimes",text:`Si vous vous teniez sur une jetée à Sandakan en 1941, voici à quoi auraient ressemblé ces bateaux et comment ils s'appelaient :

Le Navire Typique : La Chaloupe Thornycroft
La British North Borneo Chartered Company achetait presque exclusivement ses chaloupes à John I. Thornycroft & Co.
La plupart mesuraient entre 35 et 50 pieds de long. Contrairement aux navires en acier, ceux-ci étaient souvent construits avec des coques en bois de Bornéo. C'était crucial car les tarets tropicaux dévoraient le bois standard en quelques mois, mais le bois de Bornéo était très robuste et dur comme de la roche.
Ils avaient une étrave haute et droite, un rouf en bois pour les officiers et une grande zone ouverte recouverte d'un auvent en toile pour protéger l'équipage du soleil brûlant de Bornéo.
Ils n'étaient pas rapides, plafonnant généralement à 8 ou 12 nœuds. Ils étaient conçus pour l'endurance et la navigation dans les embouchures de rivières peu profondes.

Le gouvernement donnait à ses chaloupes des noms qui sonnaient à la fois officiels et un peu aventureux. Les navires notables de l'époque comprennent :
- Le Petrel : Le yacht du gouverneur. C'était le navire amiral de la petite flotte et il était utilisé pour les patrouilles de haut niveau et pour transporter le gouverneur depuis et vers Sandakan.
- Le Klias : Une chaloupe côtière robuste nommée d'après la péninsule de Klias.
- Le Membakut : Une autre chaloupe de patrouille courante utilisée pour la lutte anti-piraterie.
- Le Kedah : Un navire à vapeur côtier / grande chaloupe qui s'occupait des trajets plus longs à travers la mer de Chine méridionale.

Une chaloupe de la branche marine (Marine Wing) était essentiellement un poste de police flottant. 
Pour faire face aux pirates, ils étaient généralement armés de mitrailleuses montées.

Une chaloupe de patrouille transportait généralement un équipage mixte qui reflétait la hiérarchie coloniale.
- Le Commandant : Généralement un officier britannique de la gendarmerie (Constabulary) ou engagé par la Compagnie.
- L'Ingénieur : Souvent un Singapourien ou un spécialiste local capable de faire fonctionner les moteurs dans l'humidité.
- Les Agents de Police (Constables) : 4 à 8 policiers sikhs ou dayaks. Les Britanniques préféraient les Sikhs pour leur taille imposante et leur discipline, tandis que les Dayaks avaient une grande connaissance de la côte et des rivières.

Si un Tuan voyait une chaloupe peinte en blanc battant le drapeau de la Chartered Company, il savait que c'étaient les autorités. 
Cependant, comme ces chaloupes étaient lentes, elles arrivaient souvent après la fin d'un raid de pirates. Leur principale tâche n'était pas d'intercepter, mais de naviguer dans les villages reculés pour rappeler aux habitants que le gouvernement avait toujours des armes et surveillait le commerce de l'opium.

En 1941, un jeune homme qui voulait rejoindre la Royal Navy s'y retrouverait dans l'un des deux rôles très distincts, dépendant entièrement de sa classe sociale.

Voici la répartition de ces deux postes :

Mousse (Boy Seaman)
Si le jeune homme était issu de la classe ouvrière, son grade officiel serait Mousse de 2e Classe (Boy 2nd Class) en formation ou Mousse de 1re Classe (Boy 1st Class) en mer. 
La Royal Navy recrutait des mousses dès l'âge de 15 ans. C'étaient les apprentis et leur vie était incroyablement disciplinée et physiquement exigeante.

Leurs tâches comprenaient le rôle de messager pour les officiers, courant entre la passerelle, la salle des machines et la salle radio. Passer des heures chaque jour à polir les cuivres et à frotter les ponts. 
S'il était vif d'esprit, il pouvait être formé comme mousse signaleur (Signal Boy), chargé de hisser les pavillons de signalisation ou d'utiliser les lampes de code Morse.
Faire le quart dans le nid-de-pie ou sur les ailerons de passerelle, scrutant l'horizon à la recherche de pirates ou d'autres navires.

C'était un travail très dur. Les garçons de 15 ans étaient toujours soumis aux châtiments corporels. Un mousse pouvait être canné pour des délits mineurs.
Ils ne dormaient pas avec les marins adultes. Ils avaient leur propre poste d'équipage séparé et accrochaient leurs hamacs dans une zone désignée. Il leur était strictement interdit de trop se mêler aux hommes plus âgés, en partie pour qu'ils restent concentrés sur leur formation.

Aspirant de marine (Midshipman)
Si le jeune de 15 ans était issu d'une bonne famille et avait fréquenté une école navale comme Dartmouth, il serait un aspirant. Bien qu'encore adolescent, il était techniquement un sous-officier et s'imposait à tous les marins adultes engagés.

Dans l'argot naval, les aspirants étaient appelés Snotties (Morveux) parce qu'ils étaient connus pour s'essuyer le nez sur leurs manches.

Leurs tâches comprenaient le commandement d'embarcations, faire le quart sur la passerelle et superviser les marins adultes. 

Les aspirants vivaient dans le Carré des aspirants (Gunroom), où ils mangeaient, dormaient et étudiaient sous la supervision d'un sous-lieutenant. C'était un monde d'apprentissage sous haute pression et de bizutage intense de la part des aspirants plus âgés.
`,image:"photos/maritine_rules.png"},japanese_invasion:{title:"L'Invasion Japonaise",text:`L'invasion japonaise de Bornéo a commencé le 16 décembre 1941, neuf jours seulement après l'attaque de Pearl Harbor. Ce fut une frappe rapide et calculée visant les atouts les plus précieux de l'île, comme le pétrole et le caoutchouc.

La Chronologie de l'Invasion
Les Japonais ont utilisé une stratégie de saut de puce, atterrissant sur la côte ouest et se dirigeant vers les centres administratifs :

16 décembre 1941 : Les premiers débarquements à Miri et Seria, les centres pétroliers. Les Britanniques et les Néerlandais avaient déjà commencé leur plan de déni, incendiant les puits de pétrole pour que les Japonais ne puissent pas les utiliser immédiatement.

25 décembre 1941 : Kuching, la capitale du Sarawak, est tombée le jour de Noël.

1er janvier 1942 : Les Japonais ont débarqué sur l'île de Labuan.

19 janvier 1942 : Sandakan a été officiellement rendue par le gouverneur Robert Smith.

L'ont-ils vu venir ?
La réponse est un mélange de terreur au plus haut niveau et de déni chez les civils, mais le gouvernement, lui, savait. Les gouvernements britannique et néerlandais savaient qu'une invasion était probable dès la fin de 1940. Cependant, ils savaient aussi qu'ils ne pouvaient pas l'arrêter. Les Britanniques ont décidé que le Bornéo du Nord était indéfendable. Ils ont envoyé un seul régiment inexpérimenté et ont essentiellement dit au gouverneur du Bornéo du Nord que sa police n'était que pour la sécurité intérieure et non pour combattre une armée japonaise.

Dans les années qui ont précédé 1941, les Japonais avaient mené une forme de pénétration pacifique de Bornéo par l'intermédiaire de divers espions appelés la Cinquième Colonne. Bien que cela soit vrai, le mythe qui a surgi après la guerre selon lequel beaucoup de travailleurs japonais locaux étaient en réalité des agents de renseignement n'est pas fondé.
Ce qui était bien documenté et exact, cependant, c'est que les flottes de pêche japonaises dans la mer de Sulu étaient fréquemment tenues par des officiers de la marine japonaise qui cartographiaient les criques pour les navires d'invasion.
L'activité de renseignement japonaise avant 1941 était réelle mais limitée. La conquête rapide de Bornéo devait plus à la négligence stratégique des Alliés, au manque de défenses aériennes et navales et à l'élan du Japon qu'à une Cinquième Colonne qui verrait tout.

Sur les plantations, de nombreux propriétaires britanniques vivaient dans un état d'ignorance volontaire. Ils voyaient les nouvelles de la guerre en Europe, mais l'idée qu'une puissance non européenne envahisse avec succès leur forteresse tropicale semblait impossible pour beaucoup. Lorsque la nouvelle de Pearl Harbor est tombée, l'humeur est passée de l'insouciance à la terreur presque du jour au lendemain.
Le signe le plus frappant que l'invasion était arrivée, même pour les gens qui n'avaient pas encore vu un seul soldat japonais, était la fumée.
Dans le cadre de leur retraite, les Britanniques et les Néerlandais ont fait sauter les raffineries de pétrole et ont mis le feu aux puits de Miri et Balikpapan. Pendant des semaines, le ciel au-dessus de Bornéo a été taché de noir. Pour les habitants et les propriétaires de plantations, cette pluie noire de suie était littéralement la fin de l'ancien monde.

Pour le résident moyen, l'arrivée réelle des Japonais a semblé étonnamment rapide. À Sandakan, les Japonais ne sont pas arrivés dans des navires de guerre massifs, ils se sont glissés dans le port en utilisant de petits bateaux de pêche et des embarcations locales qu'ils avaient saisis le long de la côte.
Un jour, une femme pouvait être en train de prendre son sundowner du soir sur la véranda et le lendemain, se voir dire par un officier japonais que sa maison appartenait désormais à l'armée impériale japonaise. La transition du paradis des années 1930 à l'occupation militaire s'est produite en l'espace de quelques heures pour la plupart des villes.
        `,image:"photos/japanese_invasion2.png"},tropical_killers:{title:"Les Tueurs Tropicaux",text:`En 1941, Bornéo était souvent surnommé le cimetière de l'homme blanc, bien qu'à cette époque, la mortalité se soit améliorée grâce à la quinine et à une meilleure hygiène. Cela dit, Bornéo restait dangereux, en particulier à l'intérieur des terres et pour les hommes plus jeunes.

La cause de décès de loin la plus redoutée chez les jeunes Européens était la Fièvre Bilieuse Hémoglobinurique (Blackwater Fever). C'était une complication terrifiante d'infections paludéennes répétées. Elle provoquait une dégradation massive des globules rouges, qui submergeait les reins.
Elle a été nommée ainsi pour l'urine du patient qui devenait rouge foncé ou noire alors que le corps essayait d'évacuer les cellules sanguines détruites.
Ironiquement, elle visait soudainement des hommes expérimentés. Un jeune homme qui avait survécu à un an ou deux de légères crises de paludisme était le plus à risque. Elle était souvent déclenchée par des doses irrégulières de quinine.
C'était souvent mortel en quelques jours. Il n'y avait pas de remède à part un alitement absolu et des prières.

Alors que la fièvre bilieuse hémoglobinurique (Blackwater fever) était le tueur aigu, le paludisme (Malaria) standard était le bruit de fond mortel. Il ne tuait pas toujours directement mais affaiblissait le cœur et le système immunitaire. Beaucoup de jeunes hommes mouraient d'infections secondaires comme la pneumonie parce que leur corps était épuisé par les tremblements.
Si un jeune homme était envoyé dans un poste à l'intérieur des terres, ses chances de contracter une souche mortelle étaient nettement plus élevées que dans les villes côtières.

À une époque antérieure aux antibiotiques ou à la réfrigération généralisée, l'intestin était un point de défaillance constant. La dysenterie, souvent causée par de l'eau de puits contaminée ou des produits non lavés, pouvait tuer un homme de déshydratation en 48 heures. Les Européens avaient une certaine protection grâce à l'eau en bouteille et la nourriture bouillie. Les ouvriers supportaient la grande majorité des décès à ce niveau.
Le choléra balayait les files de laboureurs. Parce que les jeunes hommes vivaient souvent dans des quartiers communs, ils étaient très exposés.

Dans les 90 % d'humidité de Bornéo, même une petite égratignure due à une épine ou une piqûre d'insecte pouvait devenir mortelle. Une petite coupure devenait un ulcère tropical. Sans antibiotiques, si l'infection atteignait l'os ou la circulation sanguine, les seules options étaient l'amputation ou la mort. 
C'était une raison courante pour laquelle les jeunes assistants étaient renvoyés chez eux en tant qu'invalides, mais pour ceux des stations isolées, cela conduisait souvent à une mort lente et douloureuse.

Le Béribéri était principalement un tueur de la main-d'œuvre, mais il frappait parfois de jeunes Européens qui avaient vécu trop longtemps avec un régime alimentaire local. C'était causé par une carence en Vitamine B1, due généralement au fait de ne manger que du riz blanc. Il faisait enfler les jambes et menait finalement à une insuffisance cardiaque.

L'obsession britannique de porter des vêtements blancs empesés ou simplement de se surmener sous le soleil de midi a conduit à de nombreuses morts subites. C'était souvent enregistré dans les journaux officiels comme une défaillance du cœur due au climat. Cela arrivait surtout aux nouveaux arrivants qui sous-estimaient la chaleur et l'humidité.

Pour obtenir un emploi à Bornéo en 1941, un jeune homme devait passer devant un rigoureux conseil médical à Londres ou Amsterdam. Si vous aviez le sang clair ou la poitrine fragile, vous étiez rejeté. Ceux qui partaient étaient les plus aptes, mais pourtant les registres des cimetières locaux de villes comme Sandakan sont remplis de pierres tombales pour des hommes au début de la vingtaine, souvent avec l'épitaphe simple : Mort de la Fièvre.
        `,image:"photos/tropical_killers.png"},jargon:{title:"Jargon",text:`En 1941, dire "okay" aurait semblé un peu trop moderne ou même américain pour un colon britannique. Bien que le mot OK ait existé, un Tuan ou une dame britannique de l'époque aurait utilisé des expressions plus formelles ou idiomatiques pour rassurer ou montrer sa résilience.

Selon la situation, voici comment ils l'auraient exprimé :

- "I shall be quite all right." (Je serai tout à fait bien.)
- "I'll be fine." (Ça ira très bien.)
- "I shall manage." (Je me débrouillerai.)

Si la personne était blessée, malade de la fièvre ou face à des pirates, elle ne voudrait pas montrer de faiblesse. Ils utilisaient des phrases suggérant qu'ils surmontaient la tempête :
- "I shall pull through." (Je m'en remettrai.)
- "I've a sturdy constitution" (J'ai une constitution robuste.)
- "I'll be fit by morning." (Je serai sur pied demain matin.)
- "It's nothing to speak of." (Ce n'est rien d'important.)
- "I shall weather it." (Je ferai avec.)

S'ils parlaient à un ami au club :
- "I'll be right as rain." (Je serai frais comme un gardon.)
- "I shall be fit as a fiddle." (Je serai en pleine forme.)
- "I'll make out." (Je vais m'en sortir.)
- "I'm still in the pink!" (J'ai encore la pêche !)

Ils pouvaient utiliser un mélange d'anglais et de sentiment local :
- "I've survived the '26 floods, I shall survive this." (J'ai survécu aux inondations de '26, je survivrai à ceci.)
- "Don't worry about me, I'm an old hand." (Ne t'inquiète pas pour moi, j'ai de l'expérience.)


En 1941, les phrases qu'ils utilisaient pour exprimer l'incrédulité ou le scepticisme variaient selon qu'ils étaient impatients, sceptiques ou encourageants.

Pour exprimer l'incrédulité ou le scepticisme
- "Oh, I say!" (Ah, dites donc !)
- "Come, come now." (Allons, allons.)
- "Surely not!" (Sûrement pas !)
- "Nonsense!" (Absurde !)
- "Bosh!" (Balivernes !)
- "Don't be absurd, old man." (Ne sois pas absurde, mon vieux.)

Pour exprimer l'impatience ou la frustration
- "Steady on!" (Doucement !)
- "Do get a move on." (Grouille-toi.)
- "Dash it all!" (Zut à la fin !)
- "Confound it!" (Que le diable l'emporte !)
- "Really now!" (Vraiment, maintenant !)
- "Hang it!" (Au diable !)

Pour encourager quelqu'un
- "Do be a sport." (Sois un chic type.)
- "Don't be a killjoy." (Ne sois pas un rabat-joie.)
- "Be a brick!" (Sois un gars sympa !)
- "Don't be so stodgy." (Ne sois pas si coincé.)

Pour rejeter une excuse
- "That's a bit thin, isn't it?" (C'est un peu léger, n'est-ce pas ?)
- "Tell that to the Marines!" (Raconte ça à d'autres !)
- "Stuff and nonsense!" (Foutaises !)

Si le Tuan était avec d'autres hommes au club, le langage devenait un peu plus coloré.
- "Bloody nuisance!" (Fichue peste / Bon sang de nuisance !)
- "Blast it!" (Bon sang !)
- "Bugger it!" (Et merde !)

Si quelqu'un essayait d'éviter les "vrais" jurons, il utilisait des versions adoucies des jurons religieux :
- "Drat!" (Saperlipopette !)
- "Botheration!" (Zut !)
- "Good Grief!" ou "Good Heavens!" (Bon Dieu ! ou Ciel !)


Dans le Bornéo de 1941, les Britanniques parsemaient souvent leur discours de mots malais comme exclamations de frustration :
- "Tidak apa!" = Ça ne fait rien.
- "Ayo!" ou "Alamak!" = Oh mon Dieu !
        
        `},occult:{title:"L'Occulte",text:`En 1941, Bornéo abritait un paysage spirituel riche dans lequel la maladie, le malheur et la jungle elle-même étaient souvent interprétés à travers des forces invisibles. Les croyances indigènes et malaises coexistaient avec la médecine moderne, tandis que les Européens, peu familiers avec les cosmologies locales, interprétaient ces traditions à travers un prisme de peur et d'incompréhension.
Les Européens ne croyaient généralement pas à ces choses de la même manière que les locaux. Ils craignaient que les locaux y croient.

Voici les croyances occultes, les sectes redoutées et les méthodes de guérison des malédictions dans le Bornéo de l'entre-deux-guerres.

Les sectes mortelles que les gens craignaient étaient un mélange d'anciennes traditions indigènes et d'organisations criminelles secrètes.

Il y avait les Chasseurs de Têtes, également connus sous le nom de culte du trophée. Les Britanniques sous les Rajahs Brooke à Sarawak et la Chartered Company au Nord avaient en grande partie réprimé la chasse aux têtes. Cependant, on croyait largement que l'esprit de la tête était toujours affamé. En période de sécheresse ou d'épidémie, les rumeurs circulaient selon lesquelles les Dayaks se préparaient à prendre une tête pour apaiser les esprits.
Pour les Européens, les sociétés secrètes chinoises étaient les sectes les plus dangereuses. Elles étaient avant tout des organisations criminelles, non pas des sectes mystiques, mais elles participaient à des rituels de sang. Des sociétés comme les Ghee Hin ou les Hai San utilisaient des rituels d'initiations occultes comme le fait de boire du vin mélangé au sang d'un animal sacrifié appelé vin de sang, de ramper sous l'épée du ciel et de prêter des serments de mort. Elles n'étaient pas seulement criminelles, elles croyaient avoir une protection spirituelle qui les rendait invulnérables aux balles.
Et puis il y avait les Orang Bunian : il s'agissait d'une race légendaire de Personnes Cachées ou, selon certains, d'elfes. Ce n'était pas un culte humain, mais une croyance que si vous tombiez sur leur village dans la jungle, vous seriez enlevé et ne reviendriez jamais. Les gens craignaient d'être kidnappés par eux, mais ils étaient vus comme des êtres raffinés et moralement stricts.

Si quelqu'un mourait mystérieusement dans une plantation, les locaux blâmaient rarement les germes, ils blâmaient des entités spécifiques :

- Le Pontianak : L'esprit le plus redouté de Bornéo. Le fantôme d'une femme morte en couches qui, disait-on, se manifestait sous l'apparence d'une belle femme en blanc qui éviscérait les hommes avec de longues griffes. Le parfum des fleurs de frangipanier dans la jungle la nuit était un signe qu'elle était proche.
- Le Penanggalan : Une créature terrifiante composée d'une tête de femme flottante avec l'estomac et les entrailles pendant en dessous. Elle volait dans la nuit à la recherche de sang de nourrisson. Les gens accrochaient des branches épineuses d'hibiscus autour de leurs fenêtres car les organes traînants de la créature s'accrochaient aux épines.

Les malédictions étaient une arme utilisée par les locaux contre les puissants. Un propriétaire de plantation trop cruel avec ses ouvriers pouvait se retrouver victime d'un maléfice.

- Le Tuju : Un chaman pouvait envoyer un objet comme une aiguille ou même une mèche de cheveux dans le corps d'une victime à travers les airs. La victime tombait soudainement malade, prise de tremblements, et les médecins occidentaux ne trouvaient rien d'anormal.
- Le Sortilège d'Amour : Utilisé pour rendre un homme amoureux d'une femme locale. Il s'agissait généralement de glisser une potion comprenant une goutte de sang dans sa boisson du soir.
- Le Pelesit : Un esprit lié à une sauterelle. Une sorcière envoyait la sauterelle entrer dans une maison, puis une fois à l'intérieur, elle faisait dépérir ou devenir fous les habitants.

Si un jeune homme se croyait maudit, il recherchait un chaman malais. Le chaman utilisait un bouquet de feuilles spécifiques pour balayer les ténèbres invisibles de la peau de la victime. La victime était lavée dans une eau remplie de citrons verts et de pétales de fleurs. On croyait que l'acidité du citron vert brûlait l'impureté spirituelle de la malédiction. Une fois guérie, la victime recevait une amulette à porter. Pour un Britannique, cela pouvait être un minuscule morceau de parchemin avec une prière cousue dans une pochette en cuir et portée autour du cou. 
Il y avait aussi une technique courante où un œuf cru était frotté sur le corps de la victime. Lorsque l'œuf était fendu, si le jaune était noir ou contenait une aiguille, cela signifiait que la malédiction avait été attirée avec succès dans l'œuf.
        `}};export{a as DOCUMENTS,t as EVENTS,r as GLOSSARY,o as HELP,n as ITEMS,e as PEOPLE,s as ROOMS,l as getNextHint};
